PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE laws (
	law_id VARCHAR(50) NOT NULL, 
	law_num VARCHAR(100) NOT NULL, 
	title VARCHAR(255) NOT NULL, 
	promulgation_date DATE, 
	xml_file_path VARCHAR(255), 
	last_synced_at DATETIME, law_revision_id VARCHAR(100), full_text TEXT, 
	PRIMARY KEY (law_id)
);
CREATE TABLE agent_law_mappings (
	id INTEGER NOT NULL, 
	agent_id VARCHAR(50) NOT NULL, 
	law_id VARCHAR(50) NOT NULL, 
	status VARCHAR(20), 
	last_embedded_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(law_id) REFERENCES laws (law_id)
);
INSERT INTO laws VALUES('105DF0000000337','明治五年太政官布告第三百三十七号','明治五年太政官布告第三百三十七号（改暦ノ布告）','1872-11-09',NULL,'2026-02-25 02:13:29.246737','105DF0000000337_18721109_000000000000000','<LawFullText>
      <Law Era="Meiji" Year="05" Num="337" LawType="CabinetOrder" Lang="ja" PromulgateMonth="11" PromulgateDay="09">
        <LawNum>明治五年太政官布告第三百三十七号</LawNum>
        <LawBody>
          <LawTitle Kana="かいれきのふこく" Abbrev="改暦の布告" AbbrevKana="か">明治五年太政官布告第三百三十七号（改暦ノ布告）</LawTitle>
          <MainProvision>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>今般改暦ノ儀別紙　詔書ノ通被　仰出候条此旨相達候事</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </MainProvision>
          <AppdxNote>
            <AppdxNoteTitle>（別紙）</AppdxNoteTitle>
            <NoteStruct>
              <NoteStructTitle>詔書写</NoteStructTitle>
              <Note>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence>朕惟フニ我邦通行ノ暦タル太陰ノ朔望ヲ以テ月ヲ立テ太陽ノ躔度ニ合ス故ニ二三年間必ス閏月ヲ置カサルヲ得ス置閏ノ前後時ニ季候ノ早晩アリ終ニ推歩ノ差ヲ生スルニ至ル殊ニ中下段ニ掲ル所ノ如キハ率子妄誕無稽ニ属シ人知ノ開達ヲ妨ルモノ少シトセス盖シ太陽暦ハ太陽ノ躔度ニ従テ月ヲ立ツ日子多少ノ異アリト雖モ季候早晩ノ変ナク四歳毎ニ一日ノ閏ヲ置キ七千年ノ後僅ニ一日ノ差ヲ生スルニ過キス之ヲ太陰暦ニ比スレハ最モ精密ニシテ其便不便モ固リ論ヲ俟タサルナリ依テ自今旧暦ヲ廃シ太陽暦ヲ用ヒ天下永世之ヲ遵行セシメン百官有司其レ斯旨ヲ体セヨ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence>　　　明治五年壬申十一月九日</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="3">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence>　　　　　　○</Sentence>
                  </ParagraphSentence>
                  <Item Num="1">
                    <ItemTitle>一</ItemTitle>
                    <ItemSentence>
                      <Column Num="1" LineBreak="true">
                        <Sentence>今般太陰暦ヲ廃シ太陽暦御頒行相成候ニ付来ル十二月三日ヲ以テ明治六年一月一日ト被定候事</Sentence>
                      </Column>
                      <Column Num="2">
                        <Sentence>但新暦鏤板出来次第頒布候事</Sentence>
                      </Column>
                    </ItemSentence>
                  </Item>
                  <Item Num="2">
                    <ItemTitle>一</ItemTitle>
                    <ItemSentence>
                      <Sentence>一ケ年三百六十五日十二ケ月ニ分チ四年毎ニ一日ノ閏ヲ置候事</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="3">
                    <ItemTitle>一</ItemTitle>
                    <ItemSentence>
                      <Sentence>時刻ノ儀是迄昼夜長短ニ随ヒ十二時ニ相分チ候処今後改テ時辰儀時刻昼夜平分二十四時ニ定メ子刻ヨリ午刻迄ヲ十二時ニ分チ午前幾時ト称シ午刻ヨリ子刻迄ヲ十二時ニ分チ午後幾時ト称候事</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="4">
                    <ItemTitle>一</ItemTitle>
                    <ItemSentence>
                      <Column Num="1" LineBreak="true">
                        <Sentence>時鐘ノ儀来ル一月一日ヨリ右時刻ニ可改事</Sentence>
                      </Column>
                      <Column Num="2">
                        <Sentence>但是迄時辰儀時刻ヲ何字ト唱来候処以後何時ト可称事</Sentence>
                      </Column>
                    </ItemSentence>
                  </Item>
                  <Item Num="5">
                    <ItemTitle>一</ItemTitle>
                    <ItemSentence>
                      <Sentence>諸祭典等旧暦月日ヲ新暦月日ニ相当シ施行可致事</Sentence>
                    </ItemSentence>
                  </Item>
                </Paragraph>
              </Note>
            </NoteStruct>
          </AppdxNote>
          <AppdxTable>
            <AppdxTableTitle>太陽暦　一年三百六十五日　閏年三百六十六日四年毎ニ置之</AppdxTableTitle>
            <TableStruct>
              <Table>
                <TableRow>
                  <TableColumn BorderTop="none" BorderBottom="none" BorderLeft="none" BorderRight="none">
