INSERT INTO laws VALUES('106DF0000000065','明治六年太政官布告第六十五号','明治六年太政官布告第六十五号（絞罪器械図式）','1873-02-20',NULL,'2026-02-25 02:13:32.241751','106DF0000000065_18730220_000000000000000','<LawFullText>
      <Law Lang="ja" Era="Meiji" Year="06" Num="065" PromulgateMonth="2" PromulgateDay="20" LawType="Act">
        <LawNum>明治六年太政官布告第六十五号</LawNum>
        <LawBody>
          <LawTitle Kana="こうざいきかいずしき" Abbrev="" AbbrevKana="">明治六年太政官布告第六十五号（絞罪器械図式）</LawTitle>
          <Preamble>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>府県ヘ</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </Preamble>
          <MainProvision>
            <Paragraph Num="1" OldStyle="true">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>絞罪器械別紙図式ノ通改正相成候間各地方ニ於テ右図式ニ従ヒ製造可致事</Sentence>
              </ParagraphSentence>
              <FigStruct>
                <FigStructTitle>絞架全図　実物　六十分ノ一</FigStructTitle>
                <Remarks>
                  <RemarksLabel LineBreak="true" />
                  <Item Num="1">
                    <ItemTitle />
                    <ItemSentence>
                      <Sentence>本図死囚二人ヲ絞ス可キ装構ナリト雖モ其三人以上ノ処刑ニ用ルモ亦之ニ模倣シテ作リ渋墨ヲ以テ全ク塗ル可シ</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="2">
                    <ItemTitle />
                    <ItemSentence>
                      <Sentence>凡絞刑ヲ行フニハ先ツ両手ヲ背ニ縛シ紙ニテ面ヲ掩ヒ引テ絞架ニ登セ踏板上ニ立シメ次ニ両足ヲ縛シ次ニ絞繩ヲ首領ニ施シ其咽喉ニ当ラシメ繩ヲ穿ツトコロノ鉄鐶ヲ頂後ニ及ホシ之ヲ緊縮ス次ニ機車ノ柄ヲ挽ケハ踏板忽チ開落シテ囚身<QuoteStruct><Table><TableRow><TableColumn BorderTop="none" BorderBottom="none" BorderRight="none" BorderLeft="none"><Sentence>地ヲ離ル</Sentence><Sentence>凡一尺</Sentence></TableColumn></TableRow></Table></QuoteStruct>空ニ懸ル凡二分時死相ヲ験シテ解下ス（凡絞刑云々以下ハ原文絞架図面ノ後ニアリ）</Sentence>
                    </ItemSentence>
                  </Item>
                </Remarks>
                <Fig src="./pict/M06SE065-001.jpg" />
              </FigStruct>
              <FigStruct>
                <FigStructTitle>踏板表面図　実物三十分ノ一</FigStructTitle>
                <Fig src="./pict/M06SE065-002.jpg" />
              </FigStruct>
              <FigStruct>
                <FigStructTitle>機車　実物三十分ノ一</FigStructTitle>
                <Fig src="./pict/M06SE065-003.jpg" />
              </FigStruct>
              <FigStruct>
                <FigStructTitle>機車属鉄板図　実物三十分ノ一</FigStructTitle>
                <Fig src="./pict/M06SE065-004.jpg" />
              </FigStruct>
              <FigStruct>
                <FigStructTitle>踏板裏面図　実物三十分ノ一</FigStructTitle>
                <Fig src="./pict/M06SE065-005.jpg" />
              </FigStruct>
              <FigStruct>
                <FigStructTitle>機車装置図　実物三十分ノ一</FigStructTitle>
                <Fig src="./pict/M06SE065-006.jpg" />
              </FigStruct>
              <FigStruct>
                <FigStructTitle>絞繩鐶図　実物十分ノ一</FigStructTitle>
                <Fig src="./pict/M06SE065-007.jpg" />
              </FigStruct>
              <FigStruct>
                <FigStructTitle>鉄板架図　実物十分ノ一</FigStructTitle>
                <Fig src="./pict/M06SE065-008.jpg" />
              </FigStruct>
              <FigStruct>
                <FigStructTitle>螺旋図　実物十分ノ一</FigStructTitle>
                <Fig src="./pict/M06SE065-009.jpg" />
              </FigStruct>
              <FigStruct>
                <FigStructTitle>絞繩略図　繩長二丈五尺</FigStructTitle>
                <Fig src="./pict/M06SE065-010.jpg" />
              </FigStruct>
            </Paragraph>
          </MainProvision>
        </LawBody>
      </Law>
    </LawFullText>
    ');
INSERT INTO laws VALUES('108DF0000000054','明治八年太政官布告第五十四号','明治八年太政官布告第五十四号（勲章制定ノ件）','1875-04-10',NULL,'2026-02-25 02:13:34.298056','108DF0000000054_20030501_414CO0000000277','<LawFullText>
      <Law Era="Meiji" Lang="ja" LawType="CabinetOrder" Num="054" Year="08" PromulgateMonth="04" PromulgateDay="10">
        <LawNum>明治八年太政官布告第五十四号</LawNum>
        <LawBody>
          <LawTitle Kana="くんしょうせいていのけん" Abbrev="勲章制定の件" AbbrevKana="く">明治八年太政官布告第五十四号（勲章制定ノ件）</LawTitle>
          <Preamble>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>今般賞牌別冊ノ通被定候条此旨布告候事</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="2">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>（別冊）</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="3">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>朕惟フニ凡ソ国家ニ功ヲ立テ績ヲ顕ス者宜ク之ヲ褒賞シ以テ之ニ酬ユヘシ仍テ勲等賞牌ノ典ヲ定メ人々ヲシテ寵異表彰スル所アルヲ知ラシメントス汝有司其斯旨ヲ体セヨ</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="4">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>明治八年二月</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </Preamble>
          <MainProvision>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>勲等ハ勲績及功労アル者ヲ賞スル為メニ設クル所ノ階級ニシテ位階ト異ナル故ニ各種ノ勲章ヲ佩用セシム</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>勲等ヲ分ツテ次ノ六級ト為ス</Sentence>
                </ParagraphSentence>
                <Item Num="1">
                  <ItemTitle>一</ItemTitle>
                  <ItemSentence>
                    <Sentence>旭日大綬章、瑞宝大綬章又ハ桐花大綬章ヲ賜フベキモノ</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="2">
                  <ItemTitle>二</ItemTitle>
                  <ItemSentence>
                    <Sentence>旭日重光章又ハ瑞宝重光章ヲ賜フベキモノ</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="3">
                  <ItemTitle>三</ItemTitle>
                  <ItemSentence>
                    <Sentence>旭日中綬章又ハ瑞宝中綬章ヲ賜フベキモノ</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="4">
                  <ItemTitle>四</ItemTitle>
                  <ItemSentence>
                    <Sentence>旭日小綬章又ハ瑞宝小綬章ヲ賜フベキモノ</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="5">
                  <ItemTitle>五</ItemTitle>
                  <ItemSentence>
                    <Sentence>旭日双光章又ハ瑞宝双光章ヲ賜フベキモノ</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="6">
                  <ItemTitle>六</ItemTitle>
                  <ItemSentence>
                    <Sentence>旭日単光章又ハ瑞宝単光章ヲ賜フベキモノ</Sentence>
                  </ItemSentence>
                </Item>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>旭日大綬章、旭日重光章、旭日中綬章、旭日小綬章、旭日双光章及旭日単光章ハ国家又ハ公共ニ対シ勲績アル者ニ之ヲ賜フ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>右各勲章ニ在テハ章ハ旭日ノ形ヲ以テ飾リ綬ハ地白色双線紅色トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>瑞宝大綬章、瑞宝重光章、瑞宝中綬章、瑞宝小綬章、瑞宝双光章及瑞宝単光章ハ国家又ハ公共ニ対シ積年ノ功労アル者ニ之ヲ賜フ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>右各勲章ニ在テハ章ハ鏡珠ノ形ヲ以テ飾リ綬ハ地藍色双線橙黄色トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>桐花大綬章ハ旭日大綬章又ハ瑞宝大綬章ヲ賜フベキ者ノ中其勲績又ハ功労特ニ優レタルモノニ之ヲ賜フ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>桐花大綬章ノ章ハ旭日ト桐花ノ形ヲ以テ飾リ綬ハ地紅色双線白色トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>勲章ハ佩用本人ニ止リ子孫之ヲ用ユルコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>勲章ノ製式其他ノ細目ハ内閣府令ヲ以テ之ヲ定ム</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </MainProvision>
          <SupplProvision AmendLawNum="平成一四年八月一二日政令第二七七号" Extract="false" Type="Amend">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphCaption>（施行期日）</ParagraphCaption>
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence>この政令は、平成十五年五月一日から施行し、改正後の規定は、平成十五年十一月三日以後の日付をもって授与される勲章から適用する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="2">
              <ParagraphCaption>（経過措置）</ParagraphCaption>
              <ParagraphNum>２</ParagraphNum>
              <ParagraphSentence>
                <Sentence>この政令による改正前の規定により授与された勲章及び平成十五年十一月二日以前の日付をもって授与される勲章については、改正前の規定は、なおその効力を有する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="3">
              <ParagraphCaption>（婦人の勲労ある者に瑞宝章を賜うの件の廃止）</ParagraphCaption>
              <ParagraphNum>３</ParagraphNum>
              <ParagraphSentence>
                <Sentence>婦人の勲労ある者に瑞宝章を賜うの件（大正八年勅令第二百三十二号）は、廃止する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('108DF0000000103','明治八年太政官布告第百三号','明治八年太政官布告第百三号（裁判事務心得）','1875-06-08',NULL,'2026-02-25 02:13:37.089896','108DF0000000103_18750608_000000000000000','<LawFullText>
      <Law Era="Meiji" Year="08" Num="103" LawType="CabinetOrder" Lang="ja" PromulgateMonth="06" PromulgateDay="08">
        <LawNum>明治八年太政官布告第百三号</LawNum>
        <LawBody>
          <LawTitle Kana="さいばんじむこころえ" Abbrev="" AbbrevKana="">明治八年太政官布告第百三号（裁判事務心得）</LawTitle>
          <Preamble>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>今般裁判事務心得左ノ通相定候条此旨布告候事</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </Preamble>
          <MainProvision Extract="true">
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>一民事ノ裁判ニ成文ノ法律ナキモノハ習慣ニ依リ習慣ナキモノハ条理ヲ推考シテ裁判スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>一裁判官ノ裁判シタル言渡ヲ以テ将来ニ例行スル一般ノ定規トスルコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>一頒布セル布告布達ヲ除クノ外諸官省随時事ニ就テノ指令ハ将来裁判所ノ準拠スヘキ一般ノ定規トスルコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </MainProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('108DT0000000152','明治八年太政官達第百五十二号','明治八年太政官達第百五十二号（不用物品等払下ノトキ其管庁所属ノ官吏入札禁止ノ件）','1875-08-27',NULL,'2026-02-25 02:13:39.063731','108DT0000000152_18750827_000000000000000','<LawFullText>
      <Law Era="Meiji" Year="08" Num="152" LawType="CabinetOrder" Lang="ja" PromulgateMonth="08" PromulgateDay="27">
        <LawNum>明治八年太政官達第百五十二号</LawNum>
        <LawBody>
          <LawTitle Kana="ふようぶっぴんとうはらいさげのときそのかんちょうしょぞくのかんりにゅうさつきんしのけん" Abbrev="不用物品等払下のとき其管庁所属の官吏入札禁止の件" AbbrevKana="ふ">明治八年太政官達第百五十二号（不用物品等払下ノトキ其管庁所属ノ官吏入札禁止ノ件）</LawTitle>
          <MainProvision>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>官地官林及ヒ不用ノ物品等公ケノ入札法ヲ以テ払下候節其管庁ニ属スル官員ニ限リ本人ハ勿論其代理人ト雖モ投票為致候儀不相成候条此旨相達候事</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </MainProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('110DT0000000097','明治十年太政官達第九十七号','明治十年太政官達第九十七号（大勲位菊花大綬章及副章製式ノ件）','1877-12-25',NULL,'2026-02-25 02:13:41.171209','110DT0000000097_20030501_414CO0000000277','<LawFullText>
