INSERT INTO laws VALUES('128AC0000000028','明治二十八年法律第二十八号','通貨及証券模造取締法','1895-04-05',NULL,'2026-02-25 02:14:45.837912','128AC0000000028_20250601_504AC0000000068','<LawFullText>
      <Law Era="Meiji" Lang="ja" LawType="Act" Num="028" Year="28" PromulgateMonth="04" PromulgateDay="05">
        <LawNum>明治二十八年法律第二十八号</LawNum>
        <LawBody>
          <LawTitle Kana="つうかおよびしょうけんもぞうとりしまりほう" Abbrev="" AbbrevKana="">通貨及証券模造取締法</LawTitle>
          <MainProvision>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">貨幣、政府発行紙幣、銀行紙幣、兌換銀行券、国債証券及地方債証券ニ紛ハシキ外観ヲ有スルモノヲ製造シ又ハ販売スルコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前条ニ違反シタル者ハ三年以下ノ拘禁刑ニ処ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第一条ニ掲ケタル物件ハ刑法ニ依リ没収スル場合ノ外何人ノ所有ヲ問ハス警察官ニ於テ之ヲ破毀スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第一条ニ掲ケタル物件ニハ明治九年布告第五十七号ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </MainProvision>
          <SupplProvision AmendLawNum="令和四年六月一七日法律第六八号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphCaption>（施行期日）</ParagraphCaption>
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、刑法等一部改正法施行日から施行する。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、次の各号に掲げる規定は、当該各号に定める日から施行する。</Sentence>
              </ParagraphSentence>
              <Item Num="1">
                <ItemTitle>一</ItemTitle>
                <ItemSentence>
                  <Column Num="1">
                    <Sentence Num="1" WritingMode="vertical">第五百九条の規定</Sentence>
                  </Column>
                  <Column Num="2">
                    <Sentence Num="1" WritingMode="vertical">公布の日</Sentence>
                  </Column>
                </ItemSentence>
              </Item>
            </Paragraph>
          </SupplProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('128IO0000000167','明治二十八年勅令第百六十七号','明治二十八年勅令第百六十七号（標準時ニ関スル件）','1895-12-28',NULL,'2026-02-25 02:14:47.832052','128IO0000000167_19370924_312IO0000000529','<LawFullText>
      <Law Era="Meiji" Lang="ja" LawType="ImperialOrder" Num="167" Year="28" PromulgateMonth="12" PromulgateDay="28">
        <LawNum>明治二十八年勅令第百六十七号</LawNum>
        <LawBody>
          <LawTitle Kana="ひょうじゅんじにかんするけん" Abbrev="" AbbrevKana="">明治二十八年勅令第百六十七号（標準時ニ関スル件）</LawTitle>
          <MainProvision>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>帝国従来ノ標準時ハ自今之ヲ中央標準時ト称ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>削除</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>本令ハ明治二十九年一月一日ヨリ施行ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </MainProvision>
          <SupplProvision AmendLawNum="昭和一二年九月二四日勅令第五二九号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>本令ハ昭和十二年十月一日ヨリ之ヲ施行ス</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('129AC0000000005','明治二十九年法律第五号','国債証券買入銷却法','1896-02-21',NULL,'2026-02-25 02:14:49.771646','129AC0000000005_20051021_417AC0000000102','<LawFullText>
      <Law Lang="ja" Era="Meiji" Year="29" Num="005" PromulgateMonth="02" PromulgateDay="21" LawType="Act">
        <LawNum>明治二十九年法律第五号</LawNum>
        <LawBody>
          <LawTitle Kana="こくさいしょうけんかいいれしょうきゃくほう" Abbrev="" AbbrevKana="">国債証券買入銷却法</LawTitle>
          <MainProvision>
            <Article Delete="false" Hide="false" Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">政府ハ毎年度国債費予算定額以内ニ於テ国債証券ヲ買入レ之カ銷却ヲ為スコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">前項買入ハ計算上利益アリト認ムルトキ其ノ他国債ノ整理ノ円滑ナル実施ノタメ必要アリト認ムルトキニ限リ之ヲ為スコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="2">
