              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">国債証券ノ買入銷却ヲ為シタルトキハ財務大臣ハ其ノ証券ノ種類、番号、総額及其ノ買入価格ヲ告示スヘシ</Sentence>
                </ParagraphSentence>
