INSERT INTO laws VALUES('131AC0000000011','明治三十一年法律第十一号','民法施行法','1898-06-21',NULL,'2026-02-25 02:15:01.504228','131AC0000000011_20251001_505AC0000000053','<LawFullText>
      <Law Lang="ja" Era="Meiji" Year="31" Num="011" PromulgateMonth="06" PromulgateDay="21" LawType="Act">
        <LawNum>明治三十一年法律第十一号</LawNum>
        <LawBody>
          <LawTitle Kana="みんぽうしこうほう" Abbrev="" AbbrevKana="">民法施行法</LawTitle>
          <EnactStatement>民法施行法</EnactStatement>
          <TOC>
            <TOCChapter Num="1">
              <ChapterTitle>第一章　通則</ChapterTitle>
            </TOCChapter>
            <TOCChapter Num="2">
              <ChapterTitle>第二章　総則編ニ関スル規定</ChapterTitle>
            </TOCChapter>
            <TOCChapter Num="3">
              <ChapterTitle>第三章　物権編ニ関スル規定</ChapterTitle>
            </TOCChapter>
            <TOCChapter Num="4">
              <ChapterTitle>第四章　債権編ニ関スル規定</ChapterTitle>
            </TOCChapter>
            <TOCChapter Num="5">
              <ChapterTitle>第五章　親族編ニ関スル規定</ChapterTitle>
            </TOCChapter>
            <TOCChapter Num="6">
              <ChapterTitle>第六章　相続編ニ関スル規定</ChapterTitle>
            </TOCChapter>
          </TOC>
          <MainProvision Extract="true">
            <Chapter Num="1">
              <ChapterTitle>第一章　通則</ChapterTitle>
              <Article Num="1">
                <ArticleTitle>第一条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">民法施行前ニ生シタル事項ニ付テハ本法ニ別段ノ定アル場合ヲ除ク外民法ノ規定ヲ適用セス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="2">
                <ArticleTitle>第二条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="3">
                <ArticleTitle>第三条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="4">
                <ArticleTitle>第四条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="5">
                <ArticleTitle>第五条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">証書ハ左ノ場合ニ限リ確定日付アルモノトス</Sentence>
                  </ParagraphSentence>
                  <Item Num="1">
                    <ItemTitle>一</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">公正証書ナルトキハ其日付ヲ以テ確定日付トス</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="2">
                    <ItemTitle>二</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">登記所又ハ公証人役場ニ於テ私署証書ニ日付アル印章ヲ押捺シタルトキハ其印章ノ日付ヲ以テ確定日付トス</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="3">
                    <ItemTitle>三</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">私署証書ノ署名者中ニ死亡シタル者アルトキハ其死亡ノ日ヨリ確定日付アルモノトス</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="4">
                    <ItemTitle>四</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">確定日付アル証書中ニ私署証書ヲ引用シタルトキハ其証書ノ日付ヲ以テ引用シタル私署証書ノ確定日付トス</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="5">
                    <ItemTitle>五</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">官庁又ハ公署ニ於テ私署証書ニ或事項ヲ記入シ之ニ日付ヲ記載シタルトキハ其日付ヲ以テ其証書ノ確定日付トス</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="6">
                    <ItemTitle>六</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">郵便認証司（郵便法（昭和二十二年法律第百六十五号）第五十九条第一項ニ規定スル郵便認証司ヲ謂フ）ガ同法第五十八条第一号ニ規定スル内容証明ノ取扱ニ係ル認証ヲ為シタルトキハ同号ノ規定ニ従ヒテ記載シタル日付ヲ以テ確定日付トス</Sentence>
                    </ItemSentence>
                  </Item>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">指定公証人（公証人法（明治四十一年法律第五十三号）第七条ノ二第一項ニ規定スル指定公証人ヲ謂フ以下之ニ同ジ）ガ其設ケタル公証人役場ニ於テ請求ニ基キ法務省令ノ定ムル方法ニ依リ電磁的記録（電子的方式、磁気的方式其他人ノ知覚ヲ以テ認識スルコト能ハザル方式（以下電磁的方式ト称ス）ニ依リ作ラルル記録ニシテ電子計算機ニ依ル情報処理ノ用ニ供セラルルモノヲ謂フ以下之ニ同ジ）ニ記録セラレタル情報ニ日付ヲ内容トスル情報（以下日付情報ト称ス）ヲ電磁的方式ニ依リ付シタルトキハ当該電磁的記録ニ記録セラレタル情報ハ確定日付アル証書ト看做ス</Sentence>
                    <Sentence Num="2" WritingMode="vertical">但公務員ガ職務上作成シタル電磁的記録以外ノモノニ付シタルトキニ限ル</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="3" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ場合ニ於テハ日付情報ノ日付ヲ以テ確定日付トス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="6">
                <ArticleTitle>第六条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">私署証書ニ確定日附ヲ附スルコトヲ登記所又ハ公証人役場ニ請求スル者アルトキハ登記官又ハ公証人ハ確定日附簿ニ署名者ノ氏名又ハ其一人ノ氏名ニ外何名ト附記シタルモノ及ヒ件名ヲ記載シ其証書ニ登簿番号ヲ記入シ帳簿及ヒ証書ニ日附アル印章ヲ押捺シ且其印章ヲ以テ帳簿ト証書トニ割印ヲ為スコトヲ要ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">証書カ数紙ヨリ成レル場合ニ於テハ前項ニ掲ケタル印章ヲ以テ毎紙ノ綴目又ハ継目ニ契印ヲ為スコトヲ要ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="7">
                <ArticleTitle>第七条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">公証人法第六十条及ビ第六十一条ノ規定ハ指定公証人ガ第五条第二項ニ規定スル請求ニ因リ日付情報ヲ付スル場合ニ之ヲ準用ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">本法ニ規定スルモノノ外第五条第二項ニ規定スル日付情報ヲ付スルコトニ関スル事項ハ法務省令ヲ以テ之ヲ定ム</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="8">
                <ArticleTitle>第八条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">私署証書ニ確定日附ヲ附スルコトヲ登記所又ハ公証人役場ニ請求スル者ハ命令ノ定ムル所ニ依リ手数料ヲ納ムルコトヲ要ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ規定ニ依リ登記所ニ為ス請求ニ係ル手数料ノ納付ハ収入印紙ヲ以テ之ヲ為スコトヲ要ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="3" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">第一項ノ規定ハ第五条第二項ニ規定スル請求ヲ行フ者並ニ前条第一項ニ於テ準用スル公証人法第六十条第二項及ビ第三項ノ規定ニ依ル請求ヲ行フ者ニ之ヲ準用ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="9">
                <ArticleTitle>第九条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">左ノ法令ハ民法施行ノ日ヨリ之ヲ廃止ス</Sentence>
                  </ParagraphSentence>
                  <Item Num="1">
