                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">明治六年第十八号布告地所質入書入規則ハ第十一条ヲ除ク外民法施行ノ日ヨリ之ヲ廃止ス</Sentence>
