            <Article Num="39">
              <ArticleCaption>（その他の経過措置の政令への委任）</ArticleCaption>
              <ArticleTitle>第三十九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律に規定するもののほか、公社法及びこの法律の施行に関し必要な経過措置（罰則に関する経過措置を含む。）は、政令で定める。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成一六年一二月一日法律第一四七号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から起算して六月を超えない範囲内において政令で定める日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成一六年一二月三日法律第一五二号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から起算して一年を超えない範囲内において政令で定める日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="39">
              <ArticleCaption>（罰則の適用に関する経過措置）</ArticleCaption>
              <ArticleTitle>第三十九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
