          <SupplProvision AmendLawNum="平成九年六月六日法律第七二号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphCaption>（施行期日）</ParagraphCaption>
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、商法等の一部を改正する法律（平成九年法律第七十一号）の施行の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
