              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、公布の日から起算して二年を超えない範囲内において政令で定める日から施行する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、次の各号に掲げる規定は、当該各号に定める日から施行する。</Sentence>
                </ParagraphSentence>
                <Item Num="1">
                  <ItemTitle>一</ItemTitle>
                  <ItemSentence>
                    <Column Num="1">
                      <Sentence Num="1" WritingMode="vertical">第二条中不動産登記法第百三十一条第五項の改正規定及び附則第三十四条の規定</Sentence>
                    </Column>
                    <Column Num="2">
                      <Sentence Num="1" WritingMode="vertical">公布の日</Sentence>
                    </Column>
                  </ItemSentence>
                </Item>
              </Paragraph>
            </Article>
            <Article Num="9">
              <ArticleCaption>（外国法人の登記及び夫婦財産契約の登記に関する法律の一部改正に伴う経過措置）</ArticleCaption>
              <ArticleTitle>第九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前条の規定による改正後の外国法人の登記及び夫婦財産契約の登記に関する法律第八条において準用する新不動産登記法第百二十一条第三項から第五項までの規定は、施行日以後にされる登記簿の附属書類の閲覧請求について適用し、施行日前にされた登記簿の附属書類の閲覧請求については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">施行日から第二号施行日の前日までの間における前条の規定による改正後の外国法人の登記及び夫婦財産契約の登記に関する法律第八条の規定の適用については、同条中「第百十九条（第六項を除く。）」とあるのは、「第百十九条」とする。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="34">
              <ArticleCaption>（その他の経過措置の政令等への委任）</ArticleCaption>
              <ArticleTitle>第三十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この附則に定めるもののほか、この法律の施行に関し必要な経過措置は、政令で定める。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="令和三年六月一一日法律第六一号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、令和五年四月一日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('131IO0000000090','明治三十一年勅令第九十号','明治三十一年勅令第九十号（閏年ニ関スル件）','1898-05-11',NULL,'2026-02-25 02:15:05.725746','131IO0000000090_18980511_000000000000000','<LawFullText>
      <Law Era="Meiji" Year="31" Num="090" LawType="ImperialOrder" Lang="ja" PromulgateMonth="05" PromulgateDay="11">
        <LawNum>明治三十一年勅令第九十号</LawNum>
        <LawBody>
          <LawTitle Kana="うるうどしにかんするけん" Abbrev="" AbbrevKana="">明治三十一年勅令第九十号（閏年ニ関スル件）</LawTitle>
          <MainProvision>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>神武天皇即位紀元年数ノ四ヲ以テ整除シ得ヘキ年ヲ閏年トス但シ紀元年数ヨリ六百六十ヲ減シテ百ヲ以テ整除シ得ヘキモノノ中更ニ四ヲ以テ商ヲ整除シ得サル年ハ平年トス</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </MainProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('132AC0000000015','明治三十二年法律第十五号','供託法','1899-02-08',NULL,'2026-02-25 02:15:08.986578','132AC0000000015_20160401_426AC0000000069','<LawFullText>
      <Law Era="Meiji" Lang="ja" LawType="Act" Num="015" Year="32" PromulgateMonth="02" PromulgateDay="08">
        <LawNum>明治三十二年法律第十五号</LawNum>
        <LawBody>
          <LawTitle Kana="きょうたくほう" Abbrev="" AbbrevKana="">供託法</LawTitle>
          <MainProvision>
            <Article Delete="false" Hide="false" Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">法令ノ規定ニ依リテ供託スル金銭及ヒ有価証券ハ法務局若ハ地方法務局若ハ此等ノ支局又ハ法務大臣ノ指定スル此等ノ出張所カ供託所トシテ之ヲ保管ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="1_2">
              <ArticleTitle>第一条ノ二</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託所ニ於ケル事務ハ法務局若ハ地方法務局若ハ此等ノ支局又ハ此等ノ出張所ニ勤務スル法務事務官ニシテ法務局又ハ地方法務局ノ長ノ指定シタル者カ供託官トシテ之ヲ取扱フ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="1_3">
              <ArticleTitle>第一条ノ三</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託官ノ処分ニ付テハ行政手続法（平成五年法律第八十八号）第二章ノ規定ハ之ヲ適用セズ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="1_4">
              <ArticleTitle>第一条ノ四</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託官ノ処分ニ不服アル者又ハ供託官ノ不作為ニ係ル処分ノ申請ヲ為シタル者ハ監督法務局又ハ地方法務局ノ長ニ審査請求ヲ為スコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="1_5">
              <ArticleTitle>第一条ノ五</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">審査請求ハ供託官ヲ経由シテ之ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="1_6">
              <ArticleTitle>第一条ノ六</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託官ハ処分ニ付テノ審査請求ヲ理由アリト認ムルトキ又ハ審査請求ニ係ル不作為ニ係ル処分ヲ為スベキモノト認ムルトキハ相当ノ処分ヲ為シテ其旨ヲ審査請求人ニ通知スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Hide="false" Num="2" OldStyle="false" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託官ハ前項ニ規定スル場合ヲ除クノ外意見ヲ付シ審査請求アリタル日ヨリ五日内ニ之ヲ監督法務局又ハ地方法務局ノ長ニ送付スルコトヲ要ス此ノ場合ニ於テ監督法務局又ハ地方法務局ノ長ハ当該意見ヲ行政不服審査法（平成二十六年法律第六十八号）第十一条第二項ニ規定スル審理員ニ送付スルモノトス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="1_7">
              <ArticleTitle>第一条ノ七</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">法務局又ハ地方法務局ノ長ハ処分ニ付テノ審査請求ヲ理由アリト認ムルトキ又ハ審査請求ニ係ル不作為ニ係ル処分ヲ為スベキモノト認ムルトキハ供託官ニ相当ノ処分ヲ命スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Hide="false" Num="2" OldStyle="false" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">法務局又ハ地方法務局ノ長ハ審査請求ニ係ル不作為ニ係ル処分ノ申請ヲ却下スベキモノト認ムルトキハ供託官ニ当該申請ヲ却下スル処分ヲ命ズルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="1_8">
              <ArticleTitle>第一条ノ八</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">第一条ノ四ノ審査請求ニ関スル行政不服審査法ノ規定ノ適用ニ付テハ同法第二十九条第五項中「処分庁等」トアルハ「審査庁」ト、「弁明書の提出」トアルハ「供託法（明治三十二年法律第十五号）第一条ノ六第二項に規定する意見の送付」ト、同法第三十条第一項中「弁明書」トアルハ「供託法第一条ノ六第二項の意見」トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="1_9">
              <ArticleTitle>第一条ノ九</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">行政不服審査法第十三条、第十八条、第二十一条、第二十五条第二項乃至第七項、第二十九条第一項乃至第四項、第三十一条、第三十七条、第四十五条第三項、第四十六条、第四十七条、第四十九条第三項（審査請求ニ係ル不作為ガ違法又ハ不当ナル旨ノ宣言ニ係ル部分ヲ除ク）乃至第五項及ビ第五十二条ノ規定ハ第一条ノ四ノ審査請求ニ付テハ之ヲ適用セズ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託所ニ供託ヲ為サント欲スル者ハ法務大臣カ定メタル書式ニ依リテ供託書ヲ作リ供託物ニ添ヘテ之ヲ差出タスコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託金ニハ法務省令ノ定ムル所ニ依リ利息ヲ付スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="4">
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託所ハ供託物ヲ受取ルヘキ者ノ請求ニ因リ供託ノ目的タル有価証券ノ償還金、利息又ハ配当金ヲ受取リ供託物ニ代ヘ又ハ其従トシテ之ヲ保管ス但保証金ニ代ヘテ有価証券ヲ供託シタル場合ニ於テハ供託者ハ其利息又ハ配当金ノ払渡ヲ請求スルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="5">
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">法務大臣ハ法令ノ規定ニ依リテ供託スル金銭又ハ有価証券ニ非サル物品ヲ保管スヘキ倉庫営業者又ハ銀行ヲ指定スルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Hide="false" Num="2" OldStyle="false" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">倉庫営業者又ハ銀行ハ其営業ノ部類ニ属スル物ニシテ其保管シ得ヘキ数量ニ限リ之ヲ保管スル義務ヲ負フ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="6">
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">倉庫営業者又ハ銀行ニ供託ヲ為サント欲スル者ハ法務大臣カ定メタル書式ニ依リテ供託書ヲ作リ供託物ニ添ヘテ之ヲ交付スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="7">
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">倉庫営業者又ハ銀行ハ第五条第一項ノ規定ニ依ル供託物ヲ受取ルヘキ者ニ対シ一般ニ同種ノ物ニ付テ請求スル保管料ヲ請求スルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="8">
              <ArticleTitle>第八条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託物ノ還付ヲ請求スル者ハ法務大臣ノ定ムル所ニ依リ其権利ヲ証明スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Hide="false" Num="2" OldStyle="false" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託者ハ民法第四百九十六条ノ規定ニ依レルコト、供託カ錯誤ニ出テシコト又ハ其原因カ消滅シタルコトヲ証明スルニ非サレハ供託物ヲ取戻スコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="9">
              <ArticleTitle>第九条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託者カ供託物ヲ受取ル権利ヲ有セサル者ヲ指定シタルトキハ其供託ハ無効トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="10">
              <ArticleTitle>第十条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">供託物ヲ受取ルヘキ者カ反対給付ヲ為スヘキ場合ニ於テハ供託者ノ書面又ハ裁判、公正証書其他ノ公正ノ書面ニ依リ其給付アリタルコトヲ証明スルニ非サレハ供託物ヲ受取ルコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </MainProvision>
          <SupplProvision>
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Delete="false" Hide="false" Num="11">
              <ArticleTitle>第十一条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">本法ハ明治三十二年四月一日ヨリ之ヲ施行ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="12">
              <ArticleTitle>第十二条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">本法施行前ニ供託シタル金銭ニハ其施行ノ月ヨリ払渡請求ノ前月マテ第三条ノ利息ヲ附スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="13">
              <ArticleTitle>第十三条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">第四条、第八条及ヒ第十条ノ規定ハ本法施行前ニ供託シタル物ニモ亦之ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="14">
              <ArticleTitle>第十四条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">明治二十三年勅令第百四十五号供託規則ハ本法施行ノ日ヨリ之ヲ廃止ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="15">
              <ArticleTitle>第十五条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">昭和五十七年四月一日ヨリ昭和六十六年三月三十一日マデノ間ノ利息ハ第三条ノ規定ニ拘ラズ之ヲ付セズ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="大正一〇年四月一二日法律第六九号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Hide="false" Num="1" OldStyle="false" OldNum="true">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence WritingMode="vertical">本法施行ノ期日ハ勅令ヲ以テ之ヲ定ム</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Hide="false" Num="2" OldStyle="false" OldNum="true">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence WritingMode="vertical">本法施行前為シタル供託ニ関シ必要ナル規定ハ勅令ヲ以テ之ヲ定ム</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Hide="false" Num="3" OldStyle="false" OldNum="true">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence WritingMode="vertical">供託所所在地外ニ於テハ法務総裁ハ当分ノ内其ノ適当ト認ムル銀行ヲシテ第一条ノ規定ニ依ル供託事務ヲ取扱ハシムルコトヲ得</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二二年一二月一七日法律第一九五号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Delete="false" Hide="false" Num="17">
              <ArticleTitle>第十七条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">この法律は、公布の後六十日を経過した日から、これを施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二四年五月三一日法律第一三七号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Hide="false" Num="1" OldStyle="false">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence WritingMode="vertical">この法律は、昭和二十四年六月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Hide="false" Num="5" OldStyle="false">
              <ParagraphNum>５</ParagraphNum>
              <ParagraphSentence>
                <Sentence WritingMode="vertical">従前の供託法第一条ノ三又は第一条ノ七第一項の規定によつてした抗告に関しては、この法律施行後でも、なお従前の例による。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二七年七月三一日法律第二六八号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Hide="false" Num="1" OldStyle="false">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence WritingMode="vertical">この法律は、昭和二十七年八月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和三七年九月一五日法律第一六一号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Hide="false" Num="1" OldStyle="false">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence WritingMode="vertical">この法律は、昭和三十七年十月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Hide="false" Num="2" OldStyle="false">
              <ParagraphNum>２</ParagraphNum>
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">この法律による改正後の規定は、この附則に特別の定めがある場合を除き、この法律の施行前にされた行政庁の処分、この法律の施行前にされた申請に係る行政庁の不作為その他この法律の施行前に生じた事項についても適用する。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、この法律による改正前の規定によつて生じた効力を妨げない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Hide="false" Num="3" OldStyle="false">
              <ParagraphNum>３</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律の施行前に提起された訴願、審査の請求、異議の申立てその他の不服申立て（以下「訴願等」という。）については、この法律の施行後も、なお従前の例による。</Sentence>
                <Sentence Num="2" WritingMode="vertical">この法律の施行前にされた訴願等の裁決、決定その他の処分（以下「裁決等」という。）又はこの法律の施行前に提起された訴願等につきこの法律の施行後にされる裁決等にさらに不服がある場合の訴願等についても、同様とする。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Hide="false" Num="4" OldStyle="false">
              <ParagraphNum>４</ParagraphNum>
              <ParagraphSentence>
                <Sentence WritingMode="vertical">前項に規定する訴願等で、この法律の施行後は行政不服審査法による不服申立てをすることができることとなる処分に係るものは、同法以外の法律の適用については、行政不服審査法による不服申立てとみなす。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Hide="false" Num="5" OldStyle="false">
              <ParagraphNum>５</ParagraphNum>
              <ParagraphSentence>
                <Sentence WritingMode="vertical">第三項の規定によりこの法律の施行後にされる審査の請求、異議の申立てその他の不服申立ての裁決等については、行政不服審査法による不服申立てをすることができない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Hide="false" Num="6" OldStyle="false">
              <ParagraphNum>６</ParagraphNum>
              <ParagraphSentence>
                <Sentence WritingMode="vertical">この法律の施行前にされた行政庁の処分で、この法律による改正前の規定により訴願等をすることができるものとされ、かつ、その提起期間が定められていなかつたものについて、行政不服審査法による不服申立てをすることができる期間は、この法律の施行の日から起算する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Hide="false" Num="8" OldStyle="false">
              <ParagraphNum>８</ParagraphNum>
              <ParagraphSentence>
                <Sentence WritingMode="vertical">この法律の施行前にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Hide="false" Num="9" OldStyle="false">
              <ParagraphNum>９</ParagraphNum>
              <ParagraphSentence>
                <Sentence WritingMode="vertical">前八項に定めるもののほか、この法律の施行に関して必要な経過措置は、政令で定める。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和三八年七月九日法律第一二六号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Hide="false" Num="1" OldStyle="false">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence WritingMode="vertical">この法律は、商業登記法の施行の日（昭和三十九年四月一日）から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和五六年一二月四日法律第九四号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Hide="false" Num="1" OldStyle="false">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence WritingMode="vertical">この法律は、公布の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和六〇年三月三〇日法律第五号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Hide="false" Num="1" OldStyle="false">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence WritingMode="vertical">この法律は、公布の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成五年一一月一二日法律第八九号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Delete="false" Hide="false" Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">この法律は、行政手続法（平成五年法律第八十八号）の施行の日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成一一年一二月二二日法律第一六〇号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Delete="false" Hide="false" Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律（第二条及び第三条を除く。）は、平成十三年一月六日から施行する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、次の各号に掲げる規定は、当該各号に定める日から施行する。</Sentence>
                </ParagraphSentence>
                <Item Delete="false" Hide="false" Num="1">
                  <ItemTitle>一</ItemTitle>
                  <ItemSentence>
                    <Column LineBreak="false" Num="1">
                      <Sentence WritingMode="vertical">第九百九十五条（核原料物質、核燃料物質及び原子炉の規制に関する法律の一部を改正する法律附則の改正規定に係る部分に限る。）、第千三百五条、第千三百六条、第千三百二十四条第二項、第千三百二十六条第二項及び第千三百四十四条の規定</Sentence>
                    </Column>
                    <Column LineBreak="false" Num="2">
                      <Sentence WritingMode="vertical">公布の日</Sentence>
                    </Column>
                  </ItemSentence>
                </Item>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成一六年六月九日法律第八四号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Delete="false" Hide="false" Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">この法律は、公布の日から起算して一年を超えない範囲内において政令で定める日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成二六年六月一三日法律第六九号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Delete="false" Hide="false" Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">この法律は、行政不服審査法（平成二十六年法律第六十八号）の施行の日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="5">
              <ArticleCaption>（経過措置の原則）</ArticleCaption>
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">行政庁の処分その他の行為又は不作為についての不服申立てであってこの法律の施行前にされた行政庁の処分その他の行為又はこの法律の施行前にされた申請に係る行政庁の不作為に係るものについては、この附則に特別の定めがある場合を除き、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="6">
              <ArticleCaption>（訴訟に関する経過措置）</ArticleCaption>
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">この法律による改正前の法律の規定により不服申立てに対する行政庁の裁決、決定その他の行為を経た後でなければ訴えを提起できないこととされる事項であって、当該不服申立てを提起しないでこの法律の施行前にこれを提起すべき期間を経過したもの（当該不服申立てが他の不服申立てに対する行政庁の裁決、決定その他の行為を経た後でなければ提起できないとされる場合にあっては、当該他の不服申立てを提起しないでこの法律の施行前にこれを提起すべき期間を経過したものを含む。）の訴えの提起については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Hide="false" Num="2" OldStyle="false">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">この法律の規定による改正前の法律の規定（前条の規定によりなお従前の例によることとされる場合を含む。）により異議申立てが提起された処分その他の行為であって、この法律の規定による改正後の法律の規定により審査請求に対する裁決を経た後でなければ取消しの訴えを提起することができないこととされるものの取消しの訴えの提起については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Hide="false" Num="3" OldStyle="false">
                <ParagraphNum>３</ParagraphNum>
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">不服申立てに対する行政庁の裁決、決定その他の行為の取消しの訴えであって、この法律の施行前に提起されたものについては、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Delete="false" Hide="false" Num="10">
              <ArticleCaption>（その他の経過措置の政令への委任）</ArticleCaption>
              <ArticleTitle>第十条</ArticleTitle>
              <Paragraph Hide="false" Num="1" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence WritingMode="vertical">附則第五条から前条までに定めるもののほか、この法律の施行に関し必要な経過措置（罰則に関する経過措置を含む。）は、政令で定める。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('132AC0000000046','明治三十二年法律第四十六号','船舶法','1899-03-08',NULL,'2026-02-25 02:15:11.429746','132AC0000000046_20250601_504AC0000000068','<LawFullText>
      <Law Lang="ja" Era="Meiji" Year="32" Num="046" PromulgateMonth="03" PromulgateDay="08" LawType="Act">
        <LawNum>明治三十二年法律第四十六号</LawNum>
        <LawBody>
          <LawTitle Kana="せんぱくほう" Abbrev="" AbbrevKana="">船舶法</LawTitle>
          <MainProvision>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">左ノ船舶ヲ以テ日本船舶トス</Sentence>
                </ParagraphSentence>
                <Item Num="1">
                  <ItemTitle>一</ItemTitle>
                  <ItemSentence>
                    <Sentence Num="1" WritingMode="vertical">日本ノ官庁又ハ公署ノ所有ニ属スル船舶</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="2">
                  <ItemTitle>二</ItemTitle>
                  <ItemSentence>
                    <Sentence Num="1" WritingMode="vertical">日本国民ノ所有ニ属スル船舶</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="3">
                  <ItemTitle>三</ItemTitle>
                  <ItemSentence>
                    <Sentence Num="1" WritingMode="vertical">日本ノ法令ニ依リ設立シタル会社ニシテ其代表者ノ全員及ビ業務ヲ執行スル役員ノ三分ノ二以上ガ日本国民ナルモノノ所有ニ属スル船舶</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="4">
                  <ItemTitle>四</ItemTitle>
                  <ItemSentence>
                    <Sentence Num="1" WritingMode="vertical">前号ニ掲ゲタル法人以外ノ法人ニシテ日本ノ法令ニ依リ設立シ其代表者ノ全員ガ日本国民ナルモノノ所有ニ属スル船舶</Sentence>
                  </ItemSentence>
                </Item>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶ニ非サレハ日本ノ国旗ヲ掲クルコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶ニ非サレハ不開港場ニ寄港シ又ハ日本各港ノ間ニ於テ物品又ハ旅客ノ運送ヲ為スコトヲ得ス</Sentence>
                  <Sentence Num="2" WritingMode="vertical">但法律若クハ条約ニ別段ノ定アルトキ、海難若クハ捕獲ヲ避ケントスルトキ又ハ国土交通大臣ノ特許ヲ得タルトキハ此限ニ在ラス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶ノ所有者ハ日本ニ船籍港ヲ定メ其船籍港ヲ管轄スル管海官庁ニ船舶ノ総トン数ノ測度ヲ申請スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">船籍港ヲ管轄スル管海官庁ハ他ノ管海官庁ニ船舶ノ総トン数ノ測度ヲ嘱託スルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">外国ニ於テ取得シタル船舶ヲ外国各港ノ間ニ於テ航行セシムルトキハ船舶所有者ハ日本ノ領事ニ其船舶ノ総トン数ノ測度ヲ申請スルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶ノ所有者ハ登記ヲ為シタル後船籍港ヲ管轄スル管海官庁ニ備ヘタル船舶原簿ニ登録ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項ニ定メタル登録ヲ為シタルトキハ管海官庁ハ船舶国籍証書ヲ交付スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5_2">
              <ArticleTitle>第五条ノ二</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶ノ所有者ハ国土交通大臣ノ定ムル期日マデニ船舶国籍証書ヲ其船舶ノ船籍港ヲ管轄スル管海官庁（其船舶ノ運航上ノ都合ニ因リ已ムコトヲ得ザル事由アルトキハ最寄ノ管海官庁）ニ提出シ其検認ヲ受クルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項ノ期日ハ船舶国籍証書ノ交付ヲ受ケタル日又ハ船舶国籍証書ニ付前回ノ検認ヲ受ケタル日ヨリ総トン数百トン以上ノ鋼製船舶ニ在リテハ四年ヲ総トン数百トン未満ノ鋼製船舶ニ在リテハ二年ヲ木製船舶ニ在リテハ一年ヲ経過シタル後タルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">船舶ガ外国ニ在ル場合其他已ムコトヲ得ザル事由ニ因リ第一項ノ規定ニ依リ国土交通大臣ノ定ムル期日マデニ船舶国籍証書ヲ提出スルコトヲ得ザル場合ニ於テ其期日マデニ其船舶ノ所有者ヨリ理由ヲ具シテ申請アリタルトキハ船籍港ヲ管轄スル管海官庁ハ提出期日ノ延期ヲ認ムルコトヲ得延期セラレタル期日マデニ提出スルコトヲ得ザル場合亦同ジ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="4" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶ノ所有者ガ第一項ノ規定ニ依リ国土交通大臣ノ定ムル期日又ハ前項ノ規定ニ依リ延期セラレタル期日マデニ船舶国籍証書ヲ提出セザルトキハ船舶国籍証書ハ其効力ヲ失フ此場合ニ於テ船籍港ヲ管轄スル管海官庁ハ船舶原簿ニ付職権ヲ以テ抹消ノ登録ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶ハ法令ニ別段ノ定アル場合ヲ除ク外船舶国籍証書又ハ仮船舶国籍証書ヲ請受ケタル後ニ非サレハ日本ノ国旗ヲ掲ケ又ハ之ヲ航行セシムルコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6_2">
              <ArticleTitle>第六条ノ二</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第五条第一項ノ規定ニ依リ登録ヲ為シタル船舶ニ付所有者ノ変更アリタルトキハ新所有者ハ船舶国籍証書ノ書換ノ申請ヲ為シタル後ニ非ザレバ其船舶ヲ航行セシムルコトヲ得ズ</Sentence>
                  <Sentence Num="2" WritingMode="vertical">但其事実ヲ知ルニ至ルマデノ間及其事実ヲ知リタル日ヨリ二週間内ハ此限ニ在ラズ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="7">
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶ハ法令ノ定ムル所ニ従ヒ日本ノ国旗ヲ掲ケ且其名称、船籍港、番号、総トン数、喫水ノ尺度其他ノ事項ヲ標示スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="8">
              <ArticleTitle>第八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="9">
              <ArticleTitle>第九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">船舶所有者カ其船舶ヲ修繕シタル場合ニ於テ其総トン数ニ変更ヲ生シタルモノト認ムルトキハ遅滞ナク船籍港ヲ管轄スル管海官庁ニ其船舶ノ総トン数ノ改測ヲ申請スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第四条第二項及ヒ第三項ノ規定ハ前項ノ場合ニ之ヲ準用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="10">
              <ArticleTitle>第十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">登録シタル事項ニ変更ヲ生シタルトキハ船舶所有者ハ其事実ヲ知リタル日ヨリ二週間内ニ変更ノ登録ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="11">
              <ArticleTitle>第十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">船舶国籍証書ニ記載シタル事項ニ変更ヲ生シタルトキハ船舶所有者ハ其事実ヲ知リタル日ヨリ二週間内ニ其書換ヲ申請スルコトヲ要ス船舶国籍証書カ毀損シタルトキ亦同シ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="12">
              <ArticleTitle>第十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">船舶国籍証書カ滅失シタルトキハ船舶所有者ハ其事実ヲ知リタル日ヨリ二週間内ニ更ニ之ヲ請受クルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="13">
              <ArticleTitle>第十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶カ外国ノ港ニ碇泊スル間ニ於テ船舶国籍証書カ滅失若クハ毀損シ又ハ之ニ記載シタル事項ニ変更ヲ生シタルトキハ船長ハ其地ニ於テ仮船舶国籍証書ヲ請受クルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶カ外国ニ航行スル途中ニ於テ前項ノ事由カ生シタルトキハ船長ハ最初ニ到著シタル地ニ於テ仮船舶国籍証書ヲ請受クルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前二項ノ規定ニ従ヒテ仮船舶国籍証書ヲ請受クルコト能ハサルトキハ其後最初ニ到著シタル地ニ於テ之ヲ請受クルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="14">
              <ArticleTitle>第十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶カ滅失若クハ沈没シタルトキ、解撤セラレタルトキ又ハ日本ノ国籍ヲ喪失シ若クハ第二十条ニ掲クル船舶トナリタルトキハ船舶所有者ハ其事実ヲ知リタル日ヨリ二週間内ニ抹消ノ登録ヲ為シ且遅滞ナク船舶国籍証書ヲ返還スルコトヲ要ス船舶ノ存否カ三个月間分明ナラサルトキ亦同シ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項ノ場合ニ於テ船舶所有者カ抹消ノ登録ヲ為ササルトキハ管海官庁ハ一个月内ニ之ヲ為スヘキコトヲ催告シ正当ノ理由ナクシテ尚其手続ヲ為ササルトキハ職権ヲ以テ抹消ノ登録ヲ為スコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="15">
              <ArticleTitle>第十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本ニ於テ船舶ヲ取得シタル者カ其取得地ヲ管轄スル管海官庁ノ管轄区域内ニ船籍港ヲ定メサルトキハ其管海官庁ノ所在地ニ於テ仮船舶国籍証書ヲ請受クルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="16">
              <ArticleTitle>第十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">外国ニ於テ船舶ヲ取得シタル者ハ其取得地ニ於テ仮船舶国籍証書ヲ請受クルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第十三条第三項ノ規定ハ前項ノ場合ニ之ヲ準用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="17">
              <ArticleTitle>第十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">外国ニ於テ交付スル仮船舶国籍証書ノ有効期間ハ一年ヲ超ユルコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本ニ於テ交付スル仮船舶国籍証書ノ有効期間ハ六个月ヲ超ユルコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前二項ノ期間ヲ超ユルトキト雖モ已ムコトヲ得サル事由アルトキハ船長ハ更ニ仮船舶国籍証書ヲ請受クルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="18">
              <ArticleTitle>第十八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">船舶カ船籍港ニ到著シタルトキハ仮船舶国籍証書ハ有効期間満了前ト雖モ其効力ヲ失フ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="19">
              <ArticleTitle>第十九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第十一条乃至第十四条ノ規定ハ仮船舶国籍証書ニ之ヲ準用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="20">
              <ArticleTitle>第二十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第四条乃至前条ノ規定ハ総トン数二十トン未満ノ船舶及ヒ端舟其他櫓櫂ノミヲ以テ運転シ又ハ主トシテ櫓櫂ヲ以テ運転スル舟ニハ之ヲ適用セス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="21">
              <ArticleTitle>第二十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前条ニ掲ケタル船舶ノ船籍及ヒ其総トン数ノ測度ニ関スル規程ハ小型船舶の登録等に関する法律（平成十三年法律第百二号）及ビ之ニ基キテ発スル命令ニ別段ノ定アルモノヲ除クノ外命令ヲ以テ之ヲ定ム</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項ノ命令ニハ必要ナル罰則ヲ設クルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項ノ罰則ニ規定スルコトヲ得ル罰ハ二十万円以下ノ罰金トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="21_2">
              <ArticleTitle>第二十一条ノ二</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">管海官庁ハ船舶ノ総トン数、登録又ハ標示ニ関シ必要アリト認ムルトキハ何時ニテモ当該官吏ヲシテ船舶ニ臨検セシムルコトヲ得此ノ場合ニ於テハ当該官吏ハ其ノ身分ヲ証明スヘキ証票ヲ携帯スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="21_3">
              <ArticleTitle>第二十一条ノ三</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行政手続法（平成五年法律第八十八号）第二章及ビ第三章ノ規定ハ船舶ノ登録並ニ船舶国籍証書及ビ仮船舶国籍証書ニ関スル処分ニハ之ヲ適用セズ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="22">
              <ArticleTitle>第二十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶ニ非ズシテ国籍ヲ詐ル目的ヲ以テ日本ノ国旗ヲ掲ゲ又ハ日本船舶ノ船舶国籍証書若クハ仮船舶国籍証書ヲ以テ航行シタルトキハ船長ヲ二年以下ノ拘禁刑又ハ百万円以下ノ罰金ニ処ス此場合ニ於テ船長ノ所有又ハ占有ニ係ル其船舶ヲ没収スルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項ノ規定ハ船舶ガ捕獲ヲ避ケントスル目的ヲ以テ日本ノ国旗ヲ掲ゲタルトキハ之ヲ適用セズ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">日本船舶ガ国籍ヲ詐ル目的ヲ以テ日本ノ国旗以外ノ旗章ヲ掲ゲタルトキ亦前二項ニ同ジ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="22_2">
              <ArticleTitle>第二十二条ノ二</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">船長ガ当該官吏吏員ノ臨検ニ際シ之ニ呈示スル目的ヲ以テ他ノ船舶ノ船舶国籍証書又ハ仮船舶国籍証書ヲ船内ニ備置キ其船舶ヲ航行セシメタルトキハ船長ヲ二年以下ノ拘禁刑又ハ百万円以下ノ罰金ニ処ス此場合ニ於テ船長ノ所有又ハ占有ニ係ル其船舶ヲ没収スルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="23">
              <ArticleTitle>第二十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第三条、第六条又ハ第六条ノ二ノ規定ニ違反シタルトキハ船長ヲ二年以下ノ拘禁刑又ハ百万円以下ノ罰金ニ処ス此場合ニ於テ船長ノ所有又ハ占有ニ係ル其船舶ヲ没収スルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="24">
              <ArticleTitle>第二十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">官吏ヲ欺キ船舶原簿ニ不実ノ登録ヲ為サシメタル者ハ二月以上三年以下ノ拘禁刑ニ処ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項ノ未遂罪ハ之ヲ罰ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="25">
              <ArticleTitle>第二十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="26">
              <ArticleTitle>第二十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第七条ノ規定ニ従ヒテ日本ノ国旗ヲ掲ケサルトキハ船長ヲ五十万円以下ノ罰金ニ処ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="27">
              <ArticleTitle>第二十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第七条ニ定メタル事項ヲ船舶ニ標示セサルトキ又ハ第九条乃至第十二条若クハ第十四条ノ規定ニ違反シタルトキハ船舶所有者ヲ五十万円以下ノ罰金ニ処ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="27_2">
              <ArticleTitle>第二十七条ノ二</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第二十一条ノ二ノ規定ニ依ル臨検ヲ拒ミ、妨ケ又ハ忌避シタル者ハ三十万円以下ノ罰金ニ処ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="28">
              <ArticleTitle>第二十八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第二十二条、第二十二条ノ二、第二十三条及ヒ第二十六条ノ規定ハ船長ニ代ハリテ其職務ヲ行フ者ニモ亦之ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="29">
              <ArticleTitle>第二十九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">船舶所有者ノ代表者、代理人、使用人其他ノ従業者船舶所有者ノ業務ニ関シ第二十七条ノ違反行為ヲ為シタルトキハ行為者ヲ罰スルノ外其船舶所有者ニ対シ同条ノ刑ヲ科ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">法人ノ代表者又ハ法人若クハ人ノ代理人、使用人其他ノ従業者其法人又ハ人ノ業務ニ関シ第二十七条ノ二ノ違反行為ヲ為シタルトキハ行為者ヲ罰スルノ外其法人又ハ人ニ対シ同条ノ刑ヲ科ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="30:31">
              <ArticleTitle>第三十条及ビ第三十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="32">
              <ArticleTitle>第三十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">管海官庁ノ事務ハ外国ニ在リテハ日本ノ領事之ヲ行フ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行政不服審査法（平成二十六年法律第六十八号）ニ定ムルモノノ外領事ノ行フ前項ノ事務ニ係ル処分又ハ其不作為ニ付テノ審査請求ニ関シ必要ナル事項ハ政令ヲ以テ之ヲ定ム</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </MainProvision>
          <SupplProvision Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="33">
              <ArticleTitle>第三十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">本法ハ商法施行ノ日ヨリ之ヲ施行ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="34">
              <ArticleTitle>第三十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">船舶ノ登記ニ関スル規程ハ勅令ヲ以テ之ヲ定ム</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">明治十九年法律第一号登記法中船舶ノ登記ニ関スル規定ハ本法施行ノ日ヨリ之ヲ廃止ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="35">
              <ArticleTitle>第三十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第三編ノ規定ハ商行為ヲ為ス目的ヲ以テセサルモ航海ノ用ニ供スル船舶ニ之ヲ準用ス</Sentence>
                  <Sentence Num="2" WritingMode="vertical">但官庁又ハ公署ノ所有ニ属スル船舶ニ付テハ此限ニ在ラス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第七百九十一条及ビ第八百七条ノ規定ハ商行為ヲ為ス目的ヲ以テセザルモ専ラ湖川、港湾其他ノ海以外ノ水域ニ於テ航行ノ用ニ供スル船舶（前項但書ニ規定スル船舶ヲ除ク）ニ之ヲ準用ス此場合ニ於テハ同法第七百九十一条中「船舶」トアルハ「船舶又は船舶法第三十五条第一項に規定する船舶」ト読替フルモノトス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="36">
              <ArticleTitle>第三十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">明治三年正月二十七日布告商船規則、同十二年第五号布告、同年第十九号布告、同十四年第十二号布告其他ノ法令ニシテ本法ノ規定ニ牴触スルモノハ本法施行ノ日ヨリ之ヲ廃止ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="41">
              <ArticleTitle>第四十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">本法ノ施行ニ関スル細則ハ国土交通大臣之ヲ定ム</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和一四年四月五日法律第六八号" Extract="true">
