          <MainProvision>
            <Part Num="1">
              <PartTitle>第一編　総則</PartTitle>
              <Chapter Num="1">
                <ChapterTitle>第一章　通則</ChapterTitle>
                <Article Num="1">
                  <ArticleCaption>（趣旨等）</ArticleCaption>
                  <ArticleTitle>第一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人の営業、商行為その他商事については、他の法律に特別の定めがあるものを除くほか、この法律の定めるところによる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商事に関し、この法律に定めがない事項については商慣習に従い、商慣習がないときは、民法（明治二十九年法律第八十九号）の定めるところによる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="2">
                  <ArticleCaption>（公法人の商行為）</ArticleCaption>
                  <ArticleTitle>第二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">公法人が行う商行為については、法令に別段の定めがある場合を除き、この法律の定めるところによる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="3">
                  <ArticleCaption>（一方的商行為）</ArticleCaption>
                  <ArticleTitle>第三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">当事者の一方のために商行為となる行為については、この法律をその双方に適用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">当事者の一方が二人以上ある場合において、その一人のために商行為となる行為については、この法律をその全員に適用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="2">
                <ChapterTitle>第二章　商人</ChapterTitle>
                <Article Num="4">
                  <ArticleCaption>（定義）</ArticleCaption>
                  <ArticleTitle>第四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">この法律において「商人」とは、自己の名をもって商行為をすることを業とする者をいう。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">店舗その他これに類似する設備によって物品を販売することを業とする者又は鉱業を営む者は、商行為を行うことを業としない者であっても、これを商人とみなす。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="5">
                  <ArticleCaption>（未成年者登記）</ArticleCaption>
                  <ArticleTitle>第五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">未成年者が前条の営業を行うときは、その登記をしなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="6">
                  <ArticleCaption>（後見人登記）</ArticleCaption>
                  <ArticleTitle>第六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">後見人が被後見人のために第四条の営業を行うときは、その登記をしなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">後見人の代理権に加えた制限は、善意の第三者に対抗することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="7">
                  <ArticleCaption>（小商人）</ArticleCaption>
                  <ArticleTitle>第七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">第五条、前条、次章、第十一条第二項、第十五条第二項、第十七条第二項前段、第五章及び第二十二条の規定は、小商人（商人のうち、法務省令で定めるその営業のために使用する財産の価額が法務省令で定める金額を超えないものをいう。）については、適用しない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="3">
                <ChapterTitle>第三章　商業登記</ChapterTitle>
                <Article Num="8">
                  <ArticleCaption>（通則）</ArticleCaption>
                  <ArticleTitle>第八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">この編の規定により登記すべき事項は、当事者の申請により、商業登記法（昭和三十八年法律第百二十五号）の定めるところに従い、商業登記簿にこれを登記する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="9">
                  <ArticleCaption>（登記の効力）</ArticleCaption>
                  <ArticleTitle>第九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">この編の規定により登記すべき事項は、登記の後でなければ、これをもって善意の第三者に対抗することができない。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">登記の後であっても、第三者が正当な事由によってその登記があることを知らなかったときは、同様とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">故意又は過失によって不実の事項を登記した者は、その事項が不実であることをもって善意の第三者に対抗することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="10">
                  <ArticleCaption>（変更の登記及び消滅の登記）</ArticleCaption>
                  <ArticleTitle>第十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">この編の規定により登記した事項に変更が生じ、又はその事項が消滅したときは、当事者は、遅滞なく、変更の登記又は消滅の登記をしなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="4">
                <ChapterTitle>第四章　商号</ChapterTitle>
                <Article Num="11">
                  <ArticleCaption>（商号の選定）</ArticleCaption>
                  <ArticleTitle>第十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人（会社及び外国会社を除く。以下この編において同じ。）は、その氏、氏名その他の名称をもってその商号とすることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人は、その商号の登記をすることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="12">
                  <ArticleCaption>（他の商人と誤認させる名称等の使用の禁止）</ArticleCaption>
                  <ArticleTitle>第十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">何人も、不正の目的をもって、他の商人であると誤認されるおそれのある名称又は商号を使用してはならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の規定に違反する名称又は商号の使用によって営業上の利益を侵害され、又は侵害されるおそれがある商人は、その営業上の利益を侵害する者又は侵害するおそれがある者に対し、その侵害の停止又は予防を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="13">
                  <ArticleCaption>（過料）</ArticleCaption>
                  <ArticleTitle>第十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前条第一項の規定に違反した者は、百万円以下の過料に処する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="14">
                  <ArticleCaption>（自己の商号の使用を他人に許諾した商人の責任）</ArticleCaption>
                  <ArticleTitle>第十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">自己の商号を使用して営業又は事業を行うことを他人に許諾した商人は、当該商人が当該営業を行うものと誤認して当該他人と取引をした者に対し、当該他人と連帯して、当該取引によって生じた債務を弁済する責任を負う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="15">
                  <ArticleCaption>（商号の譲渡）</ArticleCaption>
                  <ArticleTitle>第十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人の商号は、営業とともにする場合又は営業を廃止する場合に限り、譲渡することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の規定による商号の譲渡は、登記をしなければ、第三者に対抗することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="16">
                  <ArticleCaption>（営業譲渡人の競業の禁止）</ArticleCaption>
                  <ArticleTitle>第十六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">営業を譲渡した商人（以下この章において「譲渡人」という。）は、当事者の別段の意思表示がない限り、同一の市町村（特別区を含むものとし、地方自治法（昭和二十二年法律第六十七号）第二百五十二条の十九第一項の指定都市にあっては、区又は総合区。以下同じ。）の区域内及びこれに隣接する市町村の区域内においては、その営業を譲渡した日から二十年間は、同一の営業を行ってはならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">譲渡人が同一の営業を行わない旨の特約をした場合には、その特約は、その営業を譲渡した日から三十年の期間内に限り、その効力を有する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前二項の規定にかかわらず、譲渡人は、不正の競争の目的をもって同一の営業を行ってはならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="17">
                  <ArticleCaption>（譲渡人の商号を使用した譲受人の責任等）</ArticleCaption>
                  <ArticleTitle>第十七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">営業を譲り受けた商人（以下この章において「譲受人」という。）が譲渡人の商号を引き続き使用する場合には、その譲受人も、譲渡人の営業によって生じた債務を弁済する責任を負う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の規定は、営業を譲渡した後、遅滞なく、譲受人が譲渡人の債務を弁済する責任を負わない旨を登記した場合には、適用しない。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">営業を譲渡した後、遅滞なく、譲受人及び譲渡人から第三者に対しその旨の通知をした場合において、その通知を受けた第三者についても、同様とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">譲受人が第一項の規定により譲渡人の債務を弁済する責任を負う場合には、譲渡人の責任は、営業を譲渡した日後二年以内に請求又は請求の予告をしない債権者に対しては、その期間を経過した時に消滅する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="4">
                    <ParagraphNum>４</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">第一項に規定する場合において、譲渡人の営業によって生じた債権について、その譲受人にした弁済は、弁済者が善意でかつ重大な過失がないときは、その効力を有する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="18">
                  <ArticleCaption>（譲受人による債務の引受け）</ArticleCaption>
                  <ArticleTitle>第十八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">譲受人が譲渡人の商号を引き続き使用しない場合においても、譲渡人の営業によって生じた債務を引き受ける旨の広告をしたときは、譲渡人の債権者は、その譲受人に対して弁済の請求をすることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">譲受人が前項の規定により譲渡人の債務を弁済する責任を負う場合には、譲渡人の責任は、同項の広告があった日後二年以内に請求又は請求の予告をしない債権者に対しては、その期間を経過した時に消滅する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="18_2">
                  <ArticleCaption>（詐害営業譲渡に係る譲受人に対する債務の履行の請求）</ArticleCaption>
                  <ArticleTitle>第十八条の二</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">譲渡人が譲受人に承継されない債務の債権者（以下この条において「残存債権者」という。）を害することを知って営業を譲渡した場合には、残存債権者は、その譲受人に対して、承継した財産の価額を限度として、当該債務の履行を請求することができる。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その譲受人が営業の譲渡の効力が生じた時において残存債権者を害することを知らなかったときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">譲受人が前項の規定により同項の債務を履行する責任を負う場合には、当該責任は、譲渡人が残存債権者を害することを知って営業を譲渡したことを知った時から二年以内に請求又は請求の予告をしない残存債権者に対しては、その期間を経過した時に消滅する。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">営業の譲渡の効力が生じた日から十年を経過したときも、同様とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">譲渡人について破産手続開始の決定又は再生手続開始の決定があったときは、残存債権者は、譲受人に対して第一項の規定による請求をする権利を行使することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="5">
                <ChapterTitle>第五章　商業帳簿</ChapterTitle>
                <Article Num="19">
                  <ArticleTitle>第十九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人の会計は、一般に公正妥当と認められる会計の慣行に従うものとする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人は、その営業のために使用する財産について、法務省令で定めるところにより、適時に、正確な商業帳簿（会計帳簿及び貸借対照表をいう。以下この条において同じ。）を作成しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人は、帳簿閉鎖の時から十年間、その商業帳簿及びその営業に関する重要な資料を保存しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="4">
                    <ParagraphNum>４</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">裁判所は、申立てにより又は職権で、訴訟の当事者に対し、商業帳簿の全部又は一部の提出を命ずることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="6">
                <ChapterTitle>第六章　商業使用人</ChapterTitle>
                <Article Num="20">
                  <ArticleCaption>（支配人）</ArticleCaption>
                  <ArticleTitle>第二十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人は、支配人を選任し、その営業所において、その営業を行わせることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="21">
                  <ArticleCaption>（支配人の代理権）</ArticleCaption>
                  <ArticleTitle>第二十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">支配人は、商人に代わってその営業に関する一切の裁判上又は裁判外の行為をする権限を有する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">支配人は、他の使用人を選任し、又は解任することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">支配人の代理権に加えた制限は、善意の第三者に対抗することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="22">
                  <ArticleCaption>（支配人の登記）</ArticleCaption>
                  <ArticleTitle>第二十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人が支配人を選任したときは、その登記をしなければならない。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">支配人の代理権の消滅についても、同様とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="23">
                  <ArticleCaption>（支配人の競業の禁止）</ArticleCaption>
                  <ArticleTitle>第二十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">支配人は、商人の許可を受けなければ、次に掲げる行為をしてはならない。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">自ら営業を行うこと。</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">自己又は第三者のためにその商人の営業の部類に属する取引をすること。</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="3">
                      <ItemTitle>三</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">他の商人又は会社若しくは外国会社の使用人となること。</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="4">
                      <ItemTitle>四</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">会社の取締役、執行役又は業務を執行する社員となること。</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">支配人が前項の規定に違反して同項第二号に掲げる行為をしたときは、当該行為によって支配人又は第三者が得た利益の額は、商人に生じた損害の額と推定する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="24">
                  <ArticleCaption>（表見支配人）</ArticleCaption>
                  <ArticleTitle>第二十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">商人の営業所の営業の主任者であることを示す名称を付した使用人は、当該営業所の営業に関し、一切の裁判外の行為をする権限を有するものとみなす。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、相手方が悪意であったときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="25">
                  <ArticleCaption>（ある種類又は特定の事項の委任を受けた使用人）</ArticleCaption>
                  <ArticleTitle>第二十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人の営業に関するある種類又は特定の事項の委任を受けた使用人は、当該事項に関する一切の裁判外の行為をする権限を有する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の使用人の代理権に加えた制限は、善意の第三者に対抗することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="26">
                  <ArticleCaption>（物品の販売等を目的とする店舗の使用人）</ArticleCaption>
                  <ArticleTitle>第二十六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">物品の販売等（販売、賃貸その他これらに類する行為をいう。以下この条において同じ。）を目的とする店舗の使用人は、その店舗に在る物品の販売等をする権限を有するものとみなす。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、相手方が悪意であったときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="7">
                <ChapterTitle>第七章　代理商</ChapterTitle>
                <Article Num="27">
                  <ArticleCaption>（通知義務）</ArticleCaption>
                  <ArticleTitle>第二十七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">代理商（商人のためにその平常の営業の部類に属する取引の代理又は媒介をする者で、その商人の使用人でないものをいう。以下この章において同じ。）は、取引の代理又は媒介をしたときは、遅滞なく、商人に対して、その旨の通知を発しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="28">
                  <ArticleCaption>（代理商の競業の禁止）</ArticleCaption>
                  <ArticleTitle>第二十八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">代理商は、商人の許可を受けなければ、次に掲げる行為をしてはならない。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">自己又は第三者のためにその商人の営業の部類に属する取引をすること。</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">その商人の営業と同種の事業を行う会社の取締役、執行役又は業務を執行する社員となること。</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">代理商が前項の規定に違反して同項第一号に掲げる行為をしたときは、当該行為によって代理商又は第三者が得た利益の額は、商人に生じた損害の額と推定する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="29">
                  <ArticleCaption>（通知を受ける権限）</ArticleCaption>
                  <ArticleTitle>第二十九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">物品の販売又はその媒介の委託を受けた代理商は、第五百二十六条第二項の通知その他売買に関する通知を受ける権限を有する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="30">
                  <ArticleCaption>（契約の解除）</ArticleCaption>
                  <ArticleTitle>第三十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人及び代理商は、契約の期間を定めなかったときは、二箇月前までに予告し、その契約を解除することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の規定にかかわらず、やむを得ない事由があるときは、商人及び代理商は、いつでもその契約を解除することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="31">
                  <ArticleCaption>（代理商の留置権）</ArticleCaption>
                  <ArticleTitle>第三十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">代理商は、取引の代理又は媒介をしたことによって生じた債権の弁済期が到来しているときは、その弁済を受けるまでは、商人のために当該代理商が占有する物又は有価証券を留置することができる。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、当事者が別段の意思表示をしたときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="32:500">
                  <ArticleTitle>第三十二条から第五百条まで</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
            </Part>
            <Part Num="2">
              <PartTitle>第二編　商行為</PartTitle>
              <Chapter Num="1">
                <ChapterTitle>第一章　総則</ChapterTitle>
                <Article Num="501">
                  <ArticleCaption>（絶対的商行為）</ArticleCaption>
                  <ArticleTitle>第五百一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">次に掲げる行為は、商行為とする。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">利益を得て譲渡する意思をもってする動産、不動産若しくは有価証券の有償取得又はその取得したものの譲渡を目的とする行為</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">他人から取得する動産又は有価証券の供給契約及びその履行のためにする有償取得を目的とする行為</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="3">
                      <ItemTitle>三</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">取引所においてする取引</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="4">
                      <ItemTitle>四</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">手形その他の商業証券に関する行為</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                </Article>
                <Article Num="502">
                  <ArticleCaption>（営業的商行為）</ArticleCaption>
                  <ArticleTitle>第五百二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">次に掲げる行為は、営業としてするときは、商行為とする。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、専ら賃金を得る目的で物を製造し、又は労務に従事する者の行為は、この限りでない。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">賃貸する意思をもってする動産若しくは不動産の有償取得若しくは賃借又はその取得し若しくは賃借したものの賃貸を目的とする行為</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">他人のためにする製造又は加工に関する行為</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="3">
                      <ItemTitle>三</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">電気又はガスの供給に関する行為</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="4">
                      <ItemTitle>四</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">運送に関する行為</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="5">
                      <ItemTitle>五</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">作業又は労務の請負</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="6">
                      <ItemTitle>六</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">出版、印刷又は撮影に関する行為</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="7">
                      <ItemTitle>七</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">客の来集を目的とする場屋における取引</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="8">
                      <ItemTitle>八</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">両替その他の銀行取引</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="9">
                      <ItemTitle>九</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">保険</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="10">
                      <ItemTitle>十</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">寄託の引受け</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="11">
                      <ItemTitle>十一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">仲立ち又は取次ぎに関する行為</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="12">
                      <ItemTitle>十二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">商行為の代理の引受け</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="13">
                      <ItemTitle>十三</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">信託の引受け</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                </Article>
                <Article Num="503">
                  <ArticleCaption>（附属的商行為）</ArticleCaption>
                  <ArticleTitle>第五百三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人がその営業のためにする行為は、商行為とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人の行為は、その営業のためにするものと推定する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="504">
                  <ArticleCaption>（商行為の代理）</ArticleCaption>
                  <ArticleTitle>第五百四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">商行為の代理人が本人のためにすることを示さないでこれをした場合であっても、その行為は、本人に対してその効力を生ずる。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、相手方が、代理人が本人のためにすることを知らなかったときは、代理人に対して履行の請求をすることを妨げない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="505">
                  <ArticleCaption>（商行為の委任）</ArticleCaption>
                  <ArticleTitle>第五百五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商行為の受任者は、委任の本旨に反しない範囲内において、委任を受けていない行為をすることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="506">
                  <ArticleCaption>（商行為の委任による代理権の消滅事由の特例）</ArticleCaption>
                  <ArticleTitle>第五百六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商行為の委任による代理権は、本人の死亡によっては、消滅しない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="507">
                  <ArticleTitle>第五百七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="508">
                  <ArticleCaption>（隔地者間における契約の申込み）</ArticleCaption>
                  <ArticleTitle>第五百八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人である隔地者の間において承諾の期間を定めないで契約の申込みを受けた者が相当の期間内に承諾の通知を発しなかったときは、その申込みは、その効力を失う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">民法第五百二十四条の規定は、前項の場合について準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="509">
                  <ArticleCaption>（契約の申込みを受けた者の諾否通知義務）</ArticleCaption>
                  <ArticleTitle>第五百九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人が平常取引をする者からその営業の部類に属する契約の申込みを受けたときは、遅滞なく、契約の申込みに対する諾否の通知を発しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人が前項の通知を発することを怠ったときは、その商人は、同項の契約の申込みを承諾したものとみなす。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="510">
                  <ArticleCaption>（契約の申込みを受けた者の物品保管義務）</ArticleCaption>
                  <ArticleTitle>第五百十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">商人がその営業の部類に属する契約の申込みを受けた場合において、その申込みとともに受け取った物品があるときは、その申込みを拒絶したときであっても、申込者の費用をもってその物品を保管しなければならない。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その物品の価額がその費用を償うのに足りないとき、又は商人がその保管によって損害を受けるときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="511">
                  <ArticleCaption>（多数当事者間の債務の連帯）</ArticleCaption>
                  <ArticleTitle>第五百十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">数人の者がその一人又は全員のために商行為となる行為によって債務を負担したときは、その債務は、各自が連帯して負担する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">保証人がある場合において、債務が主たる債務者の商行為によって生じたものであるとき、又は保証が商行為であるときは、主たる債務者及び保証人が各別の行為によって債務を負担したときであっても、その債務は、各自が連帯して負担する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="512">
                  <ArticleCaption>（報酬請求権）</ArticleCaption>
                  <ArticleTitle>第五百十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人がその営業の範囲内において他人のために行為をしたときは、相当な報酬を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="513">
                  <ArticleCaption>（利息請求権）</ArticleCaption>
                  <ArticleTitle>第五百十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人間において金銭の消費貸借をしたときは、貸主は、法定利息を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人がその営業の範囲内において他人のために金銭の立替えをしたときは、その立替えの日以後の法定利息を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="514">
                  <ArticleTitle>第五百十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="515">
                  <ArticleCaption>（契約による質物の処分の禁止の適用除外）</ArticleCaption>
                  <ArticleTitle>第五百十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">民法第三百四十九条の規定は、商行為によって生じた債権を担保するために設定した質権については、適用しない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="516">
                  <ArticleCaption>（債務の履行の場所）</ArticleCaption>
                  <ArticleTitle>第五百十六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商行為によって生じた債務の履行をすべき場所がその行為の性質又は当事者の意思表示によって定まらないときは、特定物の引渡しはその行為の時にその物が存在した場所において、その他の債務の履行は債権者の現在の営業所（営業所がない場合にあっては、その住所）において、それぞれしなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="517:520">
                  <ArticleTitle>第五百十七条から第五百二十条まで</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="521">
                  <ArticleCaption>（商人間の留置権）</ArticleCaption>
                  <ArticleTitle>第五百二十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">商人間においてその双方のために商行為となる行為によって生じた債権が弁済期にあるときは、債権者は、その債権の弁済を受けるまで、その債務者との間における商行為によって自己の占有に属した債務者の所有する物又は有価証券を留置することができる。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、当事者の別段の意思表示があるときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="522:523">
                  <ArticleTitle>第五百二十二条及び第五百二十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="2">
                <ChapterTitle>第二章　売買</ChapterTitle>
                <Article Num="524">
                  <ArticleCaption>（売主による目的物の供託及び競売）</ArticleCaption>
                  <ArticleTitle>第五百二十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人間の売買において、買主がその目的物の受領を拒み、又はこれを受領することができないときは、売主は、その物を供託し、又は相当の期間を定めて催告をした後に競売に付することができる。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、売主がその物を供託し、又は競売に付したときは、遅滞なく、買主に対してその旨の通知を発しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">損傷その他の事由による価格の低落のおそれがある物は、前項の催告をしないで競売に付することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">前二項の規定により売買の目的物を競売に付したときは、売主は、その代価を供託しなければならない。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その代価の全部又は一部を代金に充当することを妨げない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="525">
                  <ArticleCaption>（定期売買の履行遅滞による解除）</ArticleCaption>
                  <ArticleTitle>第五百二十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人間の売買において、売買の性質又は当事者の意思表示により、特定の日時又は一定の期間内に履行をしなければ契約をした目的を達することができない場合において、当事者の一方が履行をしないでその時期を経過したときは、相手方は、直ちにその履行の請求をした場合を除き、契約の解除をしたものとみなす。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="526">
                  <ArticleCaption>（買主による目的物の検査及び通知）</ArticleCaption>
                  <ArticleTitle>第五百二十六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">商人間の売買において、買主は、その売買の目的物を受領したときは、遅滞なく、その物を検査しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項に規定する場合において、買主は、同項の規定による検査により売買の目的物が種類、品質又は数量に関して契約の内容に適合しないことを発見したときは、直ちに売主に対してその旨の通知を発しなければ、その不適合を理由とする履行の追完の請求、代金の減額の請求、損害賠償の請求及び契約の解除をすることができない。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">売買の目的物が種類又は品質に関して契約の内容に適合しないことを直ちに発見することができない場合において、買主が六箇月以内にその不適合を発見したときも、同様とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の規定は、売買の目的物が種類、品質又は数量に関して契約の内容に適合しないことにつき売主が悪意であった場合には、適用しない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="527">
                  <ArticleCaption>（買主による目的物の保管及び供託）</ArticleCaption>
                  <ArticleTitle>第五百二十七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">前条第一項に規定する場合においては、買主は、契約の解除をしたときであっても、売主の費用をもって売買の目的物を保管し、又は供託しなければならない。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その物について滅失又は損傷のおそれがあるときは、裁判所の許可を得てその物を競売に付し、かつ、その代価を保管し、又は供託しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項ただし書の許可に係る事件は、同項の売買の目的物の所在地を管轄する地方裁判所が管轄する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">第一項の規定により買主が売買の目的物を競売に付したときは、遅滞なく、売主に対してその旨の通知を発しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="4">
                    <ParagraphNum>４</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前三項の規定は、売主及び買主の営業所（営業所がない場合にあっては、その住所）が同一の市町村の区域内にある場合には、適用しない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="528">
                  <ArticleTitle>第五百二十八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前条の規定は、売主から買主に引き渡した物品が注文した物品と異なる場合における当該売主から買主に引き渡した物品及び売主から買主に引き渡した物品の数量が注文した数量を超過した場合における当該超過した部分の数量の物品について準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="3">
                <ChapterTitle>第三章　交互計算</ChapterTitle>
                <Article Num="529">
                  <ArticleCaption>（交互計算）</ArticleCaption>
                  <ArticleTitle>第五百二十九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">交互計算は、商人間又は商人と商人でない者との間で平常取引をする場合において、一定の期間内の取引から生ずる債権及び債務の総額について相殺をし、その残額の支払をすることを約することによって、その効力を生ずる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="530">
                  <ArticleCaption>（商業証券に係る債権債務に関する特則）</ArticleCaption>
                  <ArticleTitle>第五百三十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">手形その他の商業証券から生じた債権及び債務を交互計算に組み入れた場合において、その商業証券の債務者が弁済をしないときは、当事者は、その債務に関する項目を交互計算から除外することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="531">
                  <ArticleCaption>（交互計算の期間）</ArticleCaption>
                  <ArticleTitle>第五百三十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">当事者が相殺をすべき期間を定めなかったときは、その期間は、六箇月とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="532">
                  <ArticleCaption>（交互計算の承認）</ArticleCaption>
                  <ArticleTitle>第五百三十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">当事者は、債権及び債務の各項目を記載した計算書の承認をしたときは、当該各項目について異議を述べることができない。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、当該計算書の記載に錯誤又は脱漏があったときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="533">
                  <ArticleCaption>（残額についての利息請求権等）</ArticleCaption>
                  <ArticleTitle>第五百三十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">相殺によって生じた残額については、債権者は、計算の閉鎖の日以後の法定利息を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の規定は、当該相殺に係る債権及び債務の各項目を交互計算に組み入れた日からこれに利息を付することを妨げない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="534">
                  <ArticleCaption>（交互計算の解除）</ArticleCaption>
                  <ArticleTitle>第五百三十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">各当事者は、いつでも交互計算の解除をすることができる。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、交互計算の解除をしたときは、直ちに、計算を閉鎖して、残額の支払を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="4">
                <ChapterTitle>第四章　匿名組合</ChapterTitle>
                <Article Num="535">
                  <ArticleCaption>（匿名組合契約）</ArticleCaption>
                  <ArticleTitle>第五百三十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">匿名組合契約は、当事者の一方が相手方の営業のために出資をし、その営業から生ずる利益を分配することを約することによって、その効力を生ずる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="536">
                  <ArticleCaption>（匿名組合員の出資及び権利義務）</ArticleCaption>
                  <ArticleTitle>第五百三十六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">匿名組合員の出資は、営業者の財産に属する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">匿名組合員は、金銭その他の財産のみをその出資の目的とすることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">匿名組合員は、営業者の業務を執行し、又は営業者を代表することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="4">
                    <ParagraphNum>４</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">匿名組合員は、営業者の行為について、第三者に対して権利及び義務を有しない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="537">
                  <ArticleCaption>（自己の氏名等の使用を許諾した匿名組合員の責任）</ArticleCaption>
                  <ArticleTitle>第五百三十七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">匿名組合員は、自己の氏若しくは氏名を営業者の商号中に用いること又は自己の商号を営業者の商号として使用することを許諾したときは、その使用以後に生じた債務については、営業者と連帯してこれを弁済する責任を負う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="538">
                  <ArticleCaption>（利益の配当の制限）</ArticleCaption>
                  <ArticleTitle>第五百三十八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">出資が損失によって減少したときは、その損失をてん補した後でなければ、匿名組合員は、利益の配当を請求することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="539">
                  <ArticleCaption>（貸借対照表の閲覧等並びに業務及び財産状況に関する検査）</ArticleCaption>
                  <ArticleTitle>第五百三十九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">匿名組合員は、営業年度の終了時において、営業者の営業時間内に、次に掲げる請求をし、又は営業者の業務及び財産の状況を検査することができる。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">営業者の貸借対照表が書面をもって作成されているときは、当該書面の閲覧又は謄写の請求</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">営業者の貸借対照表が電磁的記録（電子的方式、磁気的方式その他人の知覚によっては認識することができない方式で作られる記録であって、電子計算機による情報処理の用に供されるもので法務省令で定めるものをいう。）をもって作成されているときは、当該電磁的記録に記録された事項を法務省令で定める方法により表示したものの閲覧又は謄写の請求</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">匿名組合員は、重要な事由があるときは、いつでも、裁判所の許可を得て、営業者の業務及び財産の状況を検査することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の許可に係る事件は、営業者の営業所の所在地（営業所がない場合にあっては、営業者の住所地）を管轄する地方裁判所が管轄する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="540">
                  <ArticleCaption>（匿名組合契約の解除）</ArticleCaption>
                  <ArticleTitle>第五百四十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">匿名組合契約で匿名組合の存続期間を定めなかったとき、又はある当事者の終身の間匿名組合が存続すべきことを定めたときは、各当事者は、営業年度の終了時において、契約の解除をすることができる。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、六箇月前にその予告をしなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">匿名組合の存続期間を定めたか否かにかかわらず、やむを得ない事由があるときは、各当事者は、いつでも匿名組合契約の解除をすることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="541">
                  <ArticleCaption>（匿名組合契約の終了事由）</ArticleCaption>
                  <ArticleTitle>第五百四十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前条の場合のほか、匿名組合契約は、次に掲げる事由によって終了する。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">匿名組合の目的である事業の成功又はその成功の不能</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">営業者の死亡又は営業者が後見開始の審判を受けたこと。</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="3">
                      <ItemTitle>三</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">営業者又は匿名組合員が破産手続開始の決定を受けたこと。</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                </Article>
                <Article Num="542">
                  <ArticleCaption>（匿名組合契約の終了に伴う出資の価額の返還）</ArticleCaption>
                  <ArticleTitle>第五百四十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">匿名組合契約が終了したときは、営業者は、匿名組合員にその出資の価額を返還しなければならない。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、出資が損失によって減少したときは、その残額を返還すれば足りる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="5">
                <ChapterTitle>第五章　仲立営業</ChapterTitle>
                <Article Num="543">
                  <ArticleCaption>（定義）</ArticleCaption>
                  <ArticleTitle>第五百四十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">この章において「仲立人」とは、他人間の商行為の媒介をすることを業とする者をいう。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="544">
                  <ArticleCaption>（当事者のために給付を受けることの制限）</ArticleCaption>
                  <ArticleTitle>第五百四十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">仲立人は、その媒介により成立させた行為について、当事者のために支払その他の給付を受けることができない。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、当事者の別段の意思表示又は別段の慣習があるときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="545">
                  <ArticleCaption>（見本保管義務）</ArticleCaption>
                  <ArticleTitle>第五百四十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">仲立人がその媒介に係る行為について見本を受け取ったときは、その行為が完了するまで、これを保管しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="546">
                  <ArticleCaption>（結約書の交付義務等）</ArticleCaption>
                  <ArticleTitle>第五百四十六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">当事者間において媒介に係る行為が成立したときは、仲立人は、遅滞なく、次に掲げる事項を記載した書面（以下この章において「結約書」という。）を作成し、かつ、署名し、又は記名押印した後、これを各当事者に交付しなければならない。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">各当事者の氏名又は名称</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">当該行為の年月日及びその要領</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の場合においては、当事者が直ちに履行をすべきときを除き、仲立人は、各当事者に結約書に署名させ、又は記名押印させた後、これをその相手方に交付しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前二項の場合において、当事者の一方が結約書を受領せず、又はこれに署名若しくは記名押印をしないときは、仲立人は、遅滞なく、相手方に対してその旨の通知を発しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="547">
                  <ArticleCaption>（帳簿記載義務等）</ArticleCaption>
                  <ArticleTitle>第五百四十七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">仲立人は、その帳簿に前条第一項各号に掲げる事項を記載しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">当事者は、いつでも、仲立人がその媒介により当該当事者のために成立させた行為について、前項の帳簿の謄本の交付を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="548">
                  <ArticleCaption>（当事者の氏名等を相手方に示さない場合）</ArticleCaption>
                  <ArticleTitle>第五百四十八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">当事者がその氏名又は名称を相手方に示してはならない旨を仲立人に命じたときは、仲立人は、結約書及び前条第二項の謄本にその氏名又は名称を記載することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="549">
                  <ArticleTitle>第五百四十九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">仲立人は、当事者の一方の氏名又は名称をその相手方に示さなかったときは、当該相手方に対して自ら履行をする責任を負う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="550">
                  <ArticleCaption>（仲立人の報酬）</ArticleCaption>
                  <ArticleTitle>第五百五十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">仲立人は、第五百四十六条の手続を終了した後でなければ、報酬を請求することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">仲立人の報酬は、当事者双方が等しい割合で負担する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="6">
                <ChapterTitle>第六章　問屋営業</ChapterTitle>
                <Article Num="551">
                  <ArticleCaption>（定義）</ArticleCaption>
                  <ArticleTitle>第五百五十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">この章において「問屋」とは、自己の名をもって他人のために物品の販売又は買入れをすることを業とする者をいう。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="552">
                  <ArticleCaption>（問屋の権利義務）</ArticleCaption>
                  <ArticleTitle>第五百五十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">問屋は、他人のためにした販売又は買入れにより、相手方に対して、自ら権利を取得し、義務を負う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">問屋と委託者との間の関係については、この章に定めるもののほか、委任及び代理に関する規定を準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="553">
                  <ArticleCaption>（問屋の担保責任）</ArticleCaption>
                  <ArticleTitle>第五百五十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">問屋は、委託者のためにした販売又は買入れにつき相手方がその債務を履行しないときに、自らその履行をする責任を負う。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、当事者の別段の意思表示又は別段の慣習があるときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="554">
                  <ArticleCaption>（問屋が委託者の指定した金額との差額を負担する場合の販売又は買入れの効力）</ArticleCaption>
                  <ArticleTitle>第五百五十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">問屋が委託者の指定した金額より低い価格で販売をし、又は高い価格で買入れをした場合において、自らその差額を負担するときは、その販売又は買入れは、委託者に対してその効力を生ずる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="555">
                  <ArticleCaption>（介入権）</ArticleCaption>
                  <ArticleTitle>第五百五十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">問屋は、取引所の相場がある物品の販売又は買入れの委託を受けたときは、自ら買主又は売主となることができる。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、売買の代価は、問屋が買主又は売主となったことの通知を発した時における取引所の相場によって定める。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の場合においても、問屋は、委託者に対して報酬を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="556">
                  <ArticleCaption>（問屋が買い入れた物品の供託及び競売）</ArticleCaption>
                  <ArticleTitle>第五百五十六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">問屋が買入れの委託を受けた場合において、委託者が買い入れた物品の受領を拒み、又はこれを受領することができないときは、第五百二十四条の規定を準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="557">
                  <ArticleCaption>（代理商に関する規定の準用）</ArticleCaption>
                  <ArticleTitle>第五百五十七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">第二十七条及び第三十一条の規定は、問屋について準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="558">
                  <ArticleCaption>（準問屋）</ArticleCaption>
                  <ArticleTitle>第五百五十八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">この章の規定は、自己の名をもって他人のために販売又は買入れ以外の行為をすることを業とする者について準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="7">
                <ChapterTitle>第七章　運送取扱営業</ChapterTitle>
                <Article Num="559">
                  <ArticleCaption>（定義等）</ArticleCaption>
                  <ArticleTitle>第五百五十九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">この章において「運送取扱人」とは、自己の名をもって物品運送の取次ぎをすることを業とする者をいう。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">運送取扱人については、この章に別段の定めがある場合を除き、第五百五十一条に規定する問屋に関する規定を準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="560">
                  <ArticleCaption>（運送取扱人の責任）</ArticleCaption>
                  <ArticleTitle>第五百六十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">運送取扱人は、運送品の受取から荷受人への引渡しまでの間にその運送品が滅失し若しくは損傷し、若しくはその滅失若しくは損傷の原因が生じ、又は運送品が延着したときは、これによって生じた損害を賠償する責任を負う。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、運送取扱人がその運送品の受取、保管及び引渡し、運送人の選択その他の運送の取次ぎについて注意を怠らなかったことを証明したときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="561">
                  <ArticleCaption>（運送取扱人の報酬）</ArticleCaption>
                  <ArticleTitle>第五百六十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">運送取扱人は、運送品を運送人に引き渡したときは、直ちにその報酬を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">運送取扱契約で運送賃の額を定めたときは、運送取扱人は、特約がなければ、別に報酬を請求することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="562">
                  <ArticleCaption>（運送取扱人の留置権）</ArticleCaption>
                  <ArticleTitle>第五百六十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">運送取扱人は、運送品に関して受け取るべき報酬、付随の費用及び運送賃その他の立替金についてのみ、その弁済を受けるまで、その運送品を留置することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="563">
                  <ArticleCaption>（介入権）</ArticleCaption>
                  <ArticleTitle>第五百六十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">運送取扱人は、自ら運送をすることができる。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、運送取扱人は、運送人と同一の権利義務を有する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">運送取扱人が委託者の請求によって船荷証券又は複合運送証券を作成したときは、自ら運送をするものとみなす。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="564">
                  <ArticleCaption>（物品運送に関する規定の準用）</ArticleCaption>
                  <ArticleTitle>第五百六十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">第五百七十二条、第五百七十七条、第五百七十九条（第三項を除く。）、第五百八十一条、第五百八十五条、第五百八十六条、第五百八十七条（第五百七十七条及び第五百八十五条の規定の準用に係る部分に限る。）及び第五百八十八条の規定は、運送取扱営業について準用する。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、第五百七十九条第二項中「前の運送人」とあるのは「前の運送取扱人又は運送人」と、第五百八十五条第一項中「運送品の引渡し」とあるのは「荷受人に対する運送品の引渡し」と読み替えるものとする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="565:568">
                  <ArticleTitle>第五百六十五条から第五百六十八条まで</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="8">
                <ChapterTitle>第八章　運送営業</ChapterTitle>
                <Section Num="1">
                  <SectionTitle>第一節　総則</SectionTitle>
                  <Article Num="569">
                    <ArticleTitle>第五百六十九条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">この法律において、次の各号に掲げる用語の意義は、当該各号に定めるところによる。</Sentence>
                      </ParagraphSentence>
                      <Item Num="1">
                        <ItemTitle>一</ItemTitle>
                        <ItemSentence>
                          <Column Num="1">
                            <Sentence Num="1" WritingMode="vertical">運送人</Sentence>
                          </Column>
                          <Column Num="2">
                            <Sentence Num="1" WritingMode="vertical">陸上運送、海上運送又は航空運送の引受けをすることを業とする者をいう。</Sentence>
                          </Column>
                        </ItemSentence>
                      </Item>
                      <Item Num="2">
                        <ItemTitle>二</ItemTitle>
                        <ItemSentence>
                          <Column Num="1">
                            <Sentence Num="1" WritingMode="vertical">陸上運送</Sentence>
                          </Column>
                          <Column Num="2">
                            <Sentence Num="1" WritingMode="vertical">陸上における物品又は旅客の運送をいう。</Sentence>
                          </Column>
                        </ItemSentence>
                      </Item>
                      <Item Num="3">
                        <ItemTitle>三</ItemTitle>
                        <ItemSentence>
                          <Column Num="1">
                            <Sentence Num="1" WritingMode="vertical">海上運送</Sentence>
                          </Column>
                          <Column Num="2">
                            <Sentence Num="1" WritingMode="vertical">第六百八十四条に規定する船舶（第七百四十七条に規定する非航海船を含む。）による物品又は旅客の運送をいう。</Sentence>
                          </Column>
                        </ItemSentence>
                      </Item>
                      <Item Num="4">
                        <ItemTitle>四</ItemTitle>
                        <ItemSentence>
                          <Column Num="1">
                            <Sentence Num="1" WritingMode="vertical">航空運送</Sentence>
                          </Column>
                          <Column Num="2">
                            <Sentence Num="1" WritingMode="vertical">航空法（昭和二十七年法律第二百三十一号）第二条第一項に規定する航空機による物品又は旅客の運送をいう。</Sentence>
                          </Column>
                        </ItemSentence>
                      </Item>
                    </Paragraph>
                  </Article>
                </Section>
                <Section Num="2">
                  <SectionTitle>第二節　物品運送</SectionTitle>
                  <Article Num="570">
                    <ArticleCaption>（物品運送契約）</ArticleCaption>
                    <ArticleTitle>第五百七十条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">物品運送契約は、運送人が荷送人からある物品を受け取りこれを運送して荷受人に引き渡すことを約し、荷送人がその結果に対してその運送賃を支払うことを約することによって、その効力を生ずる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="571">
                    <ArticleCaption>（送り状の交付義務等）</ArticleCaption>
                    <ArticleTitle>第五百七十一条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">荷送人は、運送人の請求により、次に掲げる事項を記載した書面（次項において「送り状」という。）を交付しなければならない。</Sentence>
                      </ParagraphSentence>
                      <Item Num="1">
                        <ItemTitle>一</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">運送品の種類</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="2">
                        <ItemTitle>二</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">運送品の容積若しくは重量又は包若しくは個品の数及び運送品の記号</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="3">
                        <ItemTitle>三</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">荷造りの種類</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="4">
                        <ItemTitle>四</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">荷送人及び荷受人の氏名又は名称</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="5">
                        <ItemTitle>五</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">発送地及び到達地</Sentence>
                        </ItemSentence>
                      </Item>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の荷送人は、送り状の交付に代えて、法務省令で定めるところにより、運送人の承諾を得て、送り状に記載すべき事項を電磁的方法（電子情報処理組織を使用する方法その他の情報通信の技術を利用する方法であって法務省令で定めるものをいう。以下同じ。）により提供することができる。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、当該荷送人は、送り状を交付したものとみなす。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="572">
                    <ArticleCaption>（危険物に関する通知義務）</ArticleCaption>
                    <ArticleTitle>第五百七十二条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">荷送人は、運送品が引火性、爆発性その他の危険性を有するものであるときは、その引渡しの前に、運送人に対し、その旨及び当該運送品の品名、性質その他の当該運送品の安全な運送に必要な情報を通知しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="573">
                    <ArticleCaption>（運送賃）</ArticleCaption>
                    <ArticleTitle>第五百七十三条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送賃は、到達地における運送品の引渡しと同時に、支払わなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送品がその性質又は<Ruby>瑕疵<Rt>かし</Rt></Ruby>によって滅失し、又は損傷したときは、荷送人は、運送賃の支払を拒むことができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="574">
                    <ArticleCaption>（運送人の留置権）</ArticleCaption>
                    <ArticleTitle>第五百七十四条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、運送品に関して受け取るべき運送賃、付随の費用及び立替金（以下この節において「運送賃等」という。）についてのみ、その弁済を受けるまで、その運送品を留置することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="575">
                    <ArticleCaption>（運送人の責任）</ArticleCaption>
                    <ArticleTitle>第五百七十五条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">運送人は、運送品の受取から引渡しまでの間にその運送品が滅失し若しくは損傷し、若しくはその滅失若しくは損傷の原因が生じ、又は運送品が延着したときは、これによって生じた損害を賠償する責任を負う。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、運送人がその運送品の受取、運送、保管及び引渡しについて注意を怠らなかったことを証明したときは、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="576">
                    <ArticleCaption>（損害賠償の額）</ArticleCaption>
                    <ArticleTitle>第五百七十六条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">運送品の滅失又は損傷の場合における損害賠償の額は、その引渡しがされるべき地及び時における運送品の市場価格（取引所の相場がある物品については、その相場）によって定める。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、市場価格がないときは、その地及び時における同種類で同一の品質の物品の正常な価格によって定める。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送品の滅失又は損傷のために支払うことを要しなくなった運送賃その他の費用は、前項の損害賠償の額から控除する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前二項の規定は、運送人の故意又は重大な過失によって運送品の滅失又は損傷が生じたときは、適用しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="577">
                    <ArticleCaption>（高価品の特則）</ArticleCaption>
                    <ArticleTitle>第五百七十七条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">貨幣、有価証券その他の高価品については、荷送人が運送を委託するに当たりその種類及び価額を通知した場合を除き、運送人は、その滅失、損傷又は延着について損害賠償の責任を負わない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の規定は、次に掲げる場合には、適用しない。</Sentence>
                      </ParagraphSentence>
                      <Item Num="1">
                        <ItemTitle>一</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">物品運送契約の締結の当時、運送品が高価品であることを運送人が知っていたとき。</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="2">
                        <ItemTitle>二</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">運送人の故意又は重大な過失によって高価品の滅失、損傷又は延着が生じたとき。</Sentence>
                        </ItemSentence>
                      </Item>
                    </Paragraph>
                  </Article>
                  <Article Num="578">
                    <ArticleCaption>（複合運送人の責任）</ArticleCaption>
                    <ArticleTitle>第五百七十八条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">陸上運送、海上運送又は航空運送のうち二以上の運送を一の契約で引き受けた場合における運送品の滅失等（運送品の滅失、損傷又は延着をいう。以下この節において同じ。）についての運送人の損害賠償の責任は、それぞれの運送においてその運送品の滅失等の原因が生じた場合に当該運送ごとに適用されることとなる我が国の法令又は我が国が締結した条約の規定に従う。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の規定は、陸上運送であってその区間ごとに異なる二以上の法令が適用されるものを一の契約で引き受けた場合について準用する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="579">
                    <ArticleCaption>（相次運送人の権利義務）</ArticleCaption>
                    <ArticleTitle>第五百七十九条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">数人の運送人が相次いで陸上運送をするときは、後の運送人は、前の運送人に代わってその権利を行使する義務を負う。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の場合において、後の運送人が前の運送人に弁済をしたときは、後の運送人は、前の運送人の権利を取得する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">ある運送人が引き受けた陸上運送についてその荷送人のために他の運送人が相次いで当該陸上運送の一部を引き受けたときは、各運送人は、運送品の滅失等につき連帯して損害賠償の責任を負う。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="4">
                      <ParagraphNum>４</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前三項の規定は、海上運送及び航空運送について準用する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="580">
                    <ArticleCaption>（荷送人による運送の中止等の請求）</ArticleCaption>
                    <ArticleTitle>第五百八十条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">荷送人は、運送人に対し、運送の中止、荷受人の変更その他の処分を請求することができる。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、運送人は、既にした運送の割合に応じた運送賃、付随の費用、立替金及びその処分によって生じた費用の弁済を請求することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="581">
                    <ArticleCaption>（荷受人の権利義務等）</ArticleCaption>
                    <ArticleTitle>第五百八十一条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">荷受人は、運送品が到達地に到着し、又は運送品の全部が滅失したときは、物品運送契約によって生じた荷送人の権利と同一の権利を取得する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の場合において、荷受人が運送品の引渡し又はその損害賠償の請求をしたときは、荷送人は、その権利を行使することができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">荷受人は、運送品を受け取ったときは、運送人に対し、運送賃等を支払う義務を負う。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="582">
                    <ArticleCaption>（運送品の供託及び競売）</ArticleCaption>
                    <ArticleTitle>第五百八十二条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、荷受人を確知することができないときは、運送品を供託することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項に規定する場合において、運送人が荷送人に対し相当の期間を定めて運送品の処分につき指図をすべき旨を催告したにもかかわらず、荷送人がその指図をしないときは、運送人は、その運送品を競売に付することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">損傷その他の事由による価格の低落のおそれがある運送品は、前項の催告をしないで競売に付することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="4">
                      <ParagraphNum>４</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">前二項の規定により運送品を競売に付したときは、運送人は、その代価を供託しなければならない。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その代価の全部又は一部を運送賃等に充当することを妨げない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="5">
                      <ParagraphNum>５</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、第一項から第三項までの規定により運送品を供託し、又は競売に付したときは、遅滞なく、荷送人に対してその旨の通知を発しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="583">
                    <ArticleTitle>第五百八十三条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前条の規定は、荷受人が運送品の受取を拒み、又はこれを受け取ることができない場合について準用する。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、同条第二項中「運送人が」とあるのは「運送人が、荷受人に対し相当の期間を定めて運送品の受取を催告し、かつ、その期間の経過後に」と、同条第五項中「荷送人」とあるのは「荷送人及び荷受人」と読み替えるものとする。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="584">
                    <ArticleCaption>（運送人の責任の消滅）</ArticleCaption>
                    <ArticleTitle>第五百八十四条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">運送品の損傷又は一部滅失についての運送人の責任は、荷受人が異議をとどめないで運送品を受け取ったときは、消滅する。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、運送品に直ちに発見することができない損傷又は一部滅失があった場合において、荷受人が引渡しの日から二週間以内に運送人に対してその旨の通知を発したときは、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の規定は、運送品の引渡しの当時、運送人がその運送品に損傷又は一部滅失があることを知っていたときは、適用しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人が更に第三者に対して運送を委託した場合において、荷受人が第一項ただし書の期間内に運送人に対して同項ただし書の通知を発したときは、運送人に対する第三者の責任に係る同項ただし書の期間は、運送人が当該通知を受けた日から二週間を経過する日まで延長されたものとみなす。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="585">
                    <ArticleTitle>第五百八十五条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送品の滅失等についての運送人の責任は、運送品の引渡しがされた日（運送品の全部滅失の場合にあっては、その引渡しがされるべき日）から一年以内に裁判上の請求がされないときは、消滅する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の期間は、運送品の滅失等による損害が発生した後に限り、合意により、延長することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人が更に第三者に対して運送を委託した場合において、運送人が第一項の期間内に損害を賠償し又は裁判上の請求をされたときは、運送人に対する第三者の責任に係る同項の期間は、運送人が損害を賠償し又は裁判上の請求をされた日から三箇月を経過する日まで延長されたものとみなす。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="586">
                    <ArticleCaption>（運送人の債権の消滅時効）</ArticleCaption>
                    <ArticleTitle>第五百八十六条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人の荷送人又は荷受人に対する債権は、これを行使することができる時から一年間行使しないときは、時効によって消滅する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="587">
                    <ArticleCaption>（運送人の不法行為責任）</ArticleCaption>
                    <ArticleTitle>第五百八十七条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">第五百七十六条、第五百七十七条、第五百八十四条及び第五百八十五条の規定は、運送品の滅失等についての運送人の荷送人又は荷受人に対する不法行為による損害賠償の責任について準用する。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、荷受人があらかじめ荷送人の委託による運送を拒んでいたにもかかわらず荷送人から運送を引き受けた運送人の荷受人に対する責任については、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="588">
                    <ArticleCaption>（運送人の被用者の不法行為責任）</ArticleCaption>
                    <ArticleTitle>第五百八十八条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前条の規定により運送品の滅失等についての運送人の損害賠償の責任が免除され、又は軽減される場合には、その責任が免除され、又は軽減される限度において、その運送品の滅失等についての運送人の被用者の荷送人又は荷受人に対する不法行為による損害賠償の責任も、免除され、又は軽減される。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の規定は、運送人の被用者の故意又は重大な過失によって運送品の滅失等が生じたときは、適用しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                </Section>
                <Section Num="3">
                  <SectionTitle>第三節　旅客運送</SectionTitle>
                  <Article Num="589">
                    <ArticleCaption>（旅客運送契約）</ArticleCaption>
                    <ArticleTitle>第五百八十九条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">旅客運送契約は、運送人が旅客を運送することを約し、相手方がその結果に対してその運送賃を支払うことを約することによって、その効力を生ずる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="590">
                    <ArticleCaption>（運送人の責任）</ArticleCaption>
                    <ArticleTitle>第五百九十条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">運送人は、旅客が運送のために受けた損害を賠償する責任を負う。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、運送人が運送に関し注意を怠らなかったことを証明したときは、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="591">
                    <ArticleCaption>（特約禁止）</ArticleCaption>
                    <ArticleTitle>第五百九十一条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">旅客の生命又は身体の侵害による運送人の損害賠償の責任（運送の遅延を主たる原因とするものを除く。）を免除し、又は軽減する特約は、無効とする。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の規定は、次に掲げる場合には、適用しない。</Sentence>
                      </ParagraphSentence>
                      <Item Num="1">
                        <ItemTitle>一</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">大規模な火災、震災その他の災害が発生し、又は発生するおそれがある場合において運送を行うとき。</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="2">
                        <ItemTitle>二</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">運送に伴い通常生ずる振動その他の事情により生命又は身体に重大な危険が及ぶおそれがある者の運送を行うとき。</Sentence>
                        </ItemSentence>
                      </Item>
                    </Paragraph>
                  </Article>
                  <Article Num="592">
                    <ArticleCaption>（引渡しを受けた手荷物に関する運送人の責任等）</ArticleCaption>
                    <ArticleTitle>第五百九十二条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、旅客から引渡しを受けた手荷物については、運送賃を請求しないときであっても、物品運送契約における運送人と同一の責任を負う。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人の被用者は、前項に規定する手荷物について、物品運送契約における運送人の被用者と同一の責任を負う。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">第一項に規定する手荷物が到達地に到着した日から一週間以内に旅客がその引渡しを請求しないときは、運送人は、その手荷物を供託し、又は相当の期間を定めて催告をした後に競売に付することができる。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、運送人がその手荷物を供託し、又は競売に付したときは、遅滞なく、旅客に対してその旨の通知を発しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="4">
                      <ParagraphNum>４</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">損傷その他の事由による価格の低落のおそれがある手荷物は、前項の催告をしないで競売に付することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="5">
                      <ParagraphNum>５</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">前二項の規定により手荷物を競売に付したときは、運送人は、その代価を供託しなければならない。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その代価の全部又は一部を運送賃に充当することを妨げない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="6">
                      <ParagraphNum>６</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">旅客の住所又は居所が知れないときは、第三項の催告及び通知は、することを要しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="593">
                    <ArticleCaption>（引渡しを受けていない手荷物に関する運送人の責任等）</ArticleCaption>
                    <ArticleTitle>第五百九十三条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、旅客から引渡しを受けていない手荷物（身の回り品を含む。）の滅失又は損傷については、故意又は過失がある場合を除き、損害賠償の責任を負わない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">第五百七十六条第一項及び第三項、第五百八十四条第一項、第五百八十五条第一項及び第二項、第五百八十七条（第五百七十六条第一項及び第三項、第五百八十四条第一項並びに第五百八十五条第一項及び第二項の規定の準用に係る部分に限る。）並びに第五百八十八条の規定は、運送人が前項に規定する手荷物の滅失又は損傷に係る損害賠償の責任を負う場合について準用する。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、第五百七十六条第一項中「その引渡しがされるべき」とあるのは「その運送が終了すべき」と、第五百八十四条第一項中「荷受人が異議をとどめないで運送品を受け取った」とあるのは「旅客が運送の終了の時までに異議をとどめなかった」と、「荷受人が引渡しの日」とあるのは「旅客が運送の終了の日」と、第五百八十五条第一項中「運送品の引渡しがされた日（運送品の全部滅失の場合にあっては、その引渡しがされるべき日）」とあるのは「運送の終了の日」と読み替えるものとする。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="594">
                    <ArticleCaption>（運送人の債権の消滅時効）</ArticleCaption>
                    <ArticleTitle>第五百九十四条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">第五百八十六条の規定は、旅客運送について準用する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                </Section>
              </Chapter>
              <Chapter Num="9">
                <ChapterTitle>第九章　寄託</ChapterTitle>
                <Section Num="1">
                  <SectionTitle>第一節　総則</SectionTitle>
                  <Article Num="595">
                    <ArticleCaption>（受寄者の注意義務）</ArticleCaption>
                    <ArticleTitle>第五百九十五条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">商人がその営業の範囲内において寄託を受けた場合には、報酬を受けないときであっても、善良な管理者の注意をもって、寄託物を保管しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="596">
                    <ArticleCaption>（場屋営業者の責任）</ArticleCaption>
                    <ArticleTitle>第五百九十六条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">旅館、飲食店、浴場その他の客の来集を目的とする場屋における取引をすることを業とする者（以下この節において「場屋営業者」という。）は、客から寄託を受けた物品の滅失又は損傷については、不可抗力によるものであったことを証明しなければ、損害賠償の責任を免れることができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">客が寄託していない物品であっても、場屋の中に携帯した物品が、場屋営業者が注意を怠ったことによって滅失し、又は損傷したときは、場屋営業者は、損害賠償の責任を負う。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">客が場屋の中に携帯した物品につき責任を負わない旨を表示したときであっても、場屋営業者は、前二項の責任を免れることができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="597">
                    <ArticleCaption>（高価品の特則）</ArticleCaption>
                    <ArticleTitle>第五百九十七条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">貨幣、有価証券その他の高価品については、客がその種類及び価額を通知してこれを場屋営業者に寄託した場合を除き、場屋営業者は、その滅失又は損傷によって生じた損害を賠償する責任を負わない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="598">
                    <ArticleCaption>（場屋営業者の責任に係る債権の消滅時効）</ArticleCaption>
                    <ArticleTitle>第五百九十八条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前二条の場屋営業者の責任に係る債権は、場屋営業者が寄託を受けた物品を返還し、又は客が場屋の中に携帯した物品を持ち去った時（物品の全部滅失の場合にあっては、客が場屋を去った時）から一年間行使しないときは、時効によって消滅する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の規定は、場屋営業者が同項に規定する物品の滅失又は損傷につき悪意であった場合には、適用しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                </Section>
                <Section Num="2">
                  <SectionTitle>第二節　倉庫営業</SectionTitle>
                  <Article Num="599">
                    <ArticleCaption>（定義）</ArticleCaption>
                    <ArticleTitle>第五百九十九条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">この節において「倉庫営業者」とは、他人のために物品を倉庫に保管することを業とする者をいう。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="600">
                    <ArticleCaption>（倉荷証券の交付義務）</ArticleCaption>
                    <ArticleTitle>第六百条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">倉庫営業者は、寄託者の請求により、寄託物の倉荷証券を交付しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="601">
                    <ArticleCaption>（倉荷証券の記載事項）</ArticleCaption>
                    <ArticleTitle>第六百一条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">倉荷証券には、次に掲げる事項及びその番号を記載し、倉庫営業者がこれに署名し、又は記名押印しなければならない。</Sentence>
                      </ParagraphSentence>
                      <Item Num="1">
                        <ItemTitle>一</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">寄託物の種類、品質及び数量並びにその荷造りの種類、個数及び記号</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="2">
                        <ItemTitle>二</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">寄託者の氏名又は名称</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="3">
                        <ItemTitle>三</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">保管場所</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="4">
                        <ItemTitle>四</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">保管料</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="5">
                        <ItemTitle>五</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">保管期間を定めたときは、その期間</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="6">
                        <ItemTitle>六</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">寄託物を保険に付したときは、保険金額、保険期間及び保険者の氏名又は名称</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="7">
                        <ItemTitle>七</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">作成地及び作成の年月日</Sentence>
                        </ItemSentence>
                      </Item>
                    </Paragraph>
                  </Article>
                  <Article Num="602">
                    <ArticleCaption>（帳簿記載義務）</ArticleCaption>
                    <ArticleTitle>第六百二条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">倉庫営業者は、倉荷証券を寄託者に交付したときは、その帳簿に次に掲げる事項を記載しなければならない。</Sentence>
                      </ParagraphSentence>
                      <Item Num="1">
                        <ItemTitle>一</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">前条第一号、第二号及び第四号から第六号までに掲げる事項</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="2">
                        <ItemTitle>二</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">倉荷証券の番号及び作成の年月日</Sentence>
                        </ItemSentence>
                      </Item>
                    </Paragraph>
                  </Article>
                  <Article Num="603">
                    <ArticleCaption>（寄託物の分割請求）</ArticleCaption>
                    <ArticleTitle>第六百三条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">倉荷証券の所持人は、倉庫営業者に対し、寄託物の分割及びその各部分に対する倉荷証券の交付を請求することができる。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、所持人は、その所持する倉荷証券を倉庫営業者に返還しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の規定による寄託物の分割及び倉荷証券の交付に関する費用は、所持人が負担する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="604">
                    <ArticleCaption>（倉荷証券の不実記載）</ArticleCaption>
                    <ArticleTitle>第六百四条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">倉庫営業者は、倉荷証券の記載が事実と異なることをもって善意の所持人に対抗することができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="605">
                    <ArticleCaption>（寄託物に関する処分）</ArticleCaption>
                    <ArticleTitle>第六百五条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">倉荷証券が作成されたときは、寄託物に関する処分は、倉荷証券によってしなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="606">
                    <ArticleCaption>（倉荷証券の譲渡又は質入れ）</ArticleCaption>
                    <ArticleTitle>第六百六条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">倉荷証券は、記名式であるときであっても、裏書によって、譲渡し、又は質権の目的とすることができる。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、倉荷証券に裏書を禁止する旨を記載したときは、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="607">
                    <ArticleCaption>（倉荷証券の引渡しの効力）</ArticleCaption>
                    <ArticleTitle>第六百七条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">倉荷証券により寄託物を受け取ることができる者に倉荷証券を引き渡したときは、その引渡しは、寄託物について行使する権利の取得に関しては、寄託物の引渡しと同一の効力を有する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="608">
                    <ArticleCaption>（倉荷証券の再交付）</ArticleCaption>
                    <ArticleTitle>第六百八条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">倉荷証券の所持人は、その倉荷証券を喪失したときは、相当の担保を供して、その再交付を請求することができる。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、倉庫営業者は、その旨を帳簿に記載しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="609">
                    <ArticleCaption>（寄託物の点検等）</ArticleCaption>
                    <ArticleTitle>第六百九条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">寄託者又は倉荷証券の所持人は、倉庫営業者の営業時間内は、いつでも、寄託物の点検若しくはその見本の提供を求め、又はその保存に必要な処分をすることができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="610">
                    <ArticleCaption>（倉庫営業者の責任）</ArticleCaption>
                    <ArticleTitle>第六百十条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">倉庫営業者は、寄託物の保管に関し注意を怠らなかったことを証明しなければ、その滅失又は損傷につき損害賠償の責任を免れることができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="611">
                    <ArticleCaption>（保管料等の支払時期）</ArticleCaption>
                    <ArticleTitle>第六百十一条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">倉庫営業者は、寄託物の出庫の時以後でなければ、保管料及び立替金その他寄託物に関する費用（第六百十六条第一項において「保管料等」という。）の支払を請求することができない。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、寄託物の一部を出庫するときは、出庫の割合に応じて、その支払を請求することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="612">
                    <ArticleCaption>（寄託物の返還の制限）</ArticleCaption>
                    <ArticleTitle>第六百十二条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">当事者が寄託物の保管期間を定めなかったときは、倉庫営業者は、寄託物の入庫の日から六箇月を経過した後でなければ、その返還をすることができない。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、やむを得ない事由があるときは、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="613">
                    <ArticleCaption>（倉荷証券が作成された場合における寄託物の返還請求）</ArticleCaption>
                    <ArticleTitle>第六百十三条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">倉荷証券が作成されたときは、これと引換えでなければ、寄託物の返還を請求することができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="614">
                    <ArticleCaption>（倉荷証券を質入れした場合における寄託物の一部の返還請求）</ArticleCaption>
                    <ArticleTitle>第六百十四条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">倉荷証券を質権の目的とした場合において、質権者の承諾があるときは、寄託者は、当該質権の被担保債権の弁済期前であっても、寄託物の一部の返還を請求することができる。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、倉庫営業者は、返還した寄託物の種類、品質及び数量を倉荷証券に記載し、かつ、その旨を帳簿に記載しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="615">
                    <ArticleCaption>（寄託物の供託及び競売）</ArticleCaption>
                    <ArticleTitle>第六百十五条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">第五百二十四条第一項及び第二項の規定は、寄託者又は倉荷証券の所持人が寄託物の受領を拒み、又はこれを受領することができない場合について準用する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="616">
                    <ArticleCaption>（倉庫営業者の責任の消滅）</ArticleCaption>
                    <ArticleTitle>第六百十六条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">寄託物の損傷又は一部滅失についての倉庫営業者の責任は、寄託者又は倉荷証券の所持人が異議をとどめないで寄託物を受け取り、かつ、保管料等を支払ったときは、消滅する。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、寄託物に直ちに発見することができない損傷又は一部滅失があった場合において、寄託者又は倉荷証券の所持人が引渡しの日から二週間以内に倉庫営業者に対してその旨の通知を発したときは、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の規定は、倉庫営業者が寄託物の損傷又は一部滅失につき悪意であった場合には、適用しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="617">
                    <ArticleCaption>（倉庫営業者の責任に係る債権の消滅時効）</ArticleCaption>
                    <ArticleTitle>第六百十七条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">寄託物の滅失又は損傷についての倉庫営業者の責任に係る債権は、寄託物の出庫の日から一年間行使しないときは、時効によって消滅する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の期間は、寄託物の全部滅失の場合においては、倉庫営業者が倉荷証券の所持人（倉荷証券を作成していないとき又は倉荷証券の所持人が知れないときは、寄託者）に対してその旨の通知を発した日から起算する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前二項の規定は、倉庫営業者が寄託物の滅失又は損傷につき悪意であった場合には、適用しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="618:683">
                    <ArticleTitle>第六百十八条から第六百八十三条まで</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                </Section>
              </Chapter>
            </Part>
            <Part Num="3">
              <PartTitle>第三編　海商</PartTitle>
              <Chapter Num="1">
                <ChapterTitle>第一章　船舶</ChapterTitle>
                <Section Num="1">
                  <SectionTitle>第一節　総則</SectionTitle>
                  <Article Num="684">
                    <ArticleCaption>（定義）</ArticleCaption>
                    <ArticleTitle>第六百八十四条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">この編（第七百四十七条を除く。）において「船舶」とは、商行為をする目的で航海の用に供する船舶（端舟その他ろかいのみをもって運転し、又は主としてろかいをもって運転する舟を除く。）をいう。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="685">
                    <ArticleCaption>（従物の推定等）</ArticleCaption>
                    <ArticleTitle>第六百八十五条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">船舶の属具目録に記載した物は、その従物と推定する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">属具目録の書式は、国土交通省令で定める。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                </Section>
                <Section Num="2">
                  <SectionTitle>第二節　船舶の所有</SectionTitle>
                  <Subsection Num="1">
                    <SubsectionTitle>第一款　総則</SubsectionTitle>
                    <Article Num="686">
                      <ArticleCaption>（船舶の登記等）</ArticleCaption>
                      <ArticleTitle>第六百八十六条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶所有者は、船舶法（明治三十二年法律第四十六号）の定めるところに従い、登記をし、かつ、船舶国籍証書の交付を受けなければならない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                      <Paragraph Num="2">
                        <ParagraphNum>２</ParagraphNum>
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">前項の規定は、総トン数二十トン未満の船舶については、適用しない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="687">
                      <ArticleCaption>（船舶所有権の移転の対抗要件）</ArticleCaption>
                      <ArticleTitle>第六百八十七条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶所有権の移転は、その登記をし、かつ、船舶国籍証書に記載しなければ、第三者に対抗することができない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="688">
                      <ArticleCaption>（航海中の船舶を譲渡した場合の損益の帰属）</ArticleCaption>
                      <ArticleTitle>第六百八十八条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">航海中の船舶を譲渡したときは、その航海によって生ずる損益は、譲受人に帰属する。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="689">
                      <ArticleCaption>（航海中の船舶に対する差押え等の制限）</ArticleCaption>
                      <ArticleTitle>第六百八十九条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">差押え及び仮差押えの執行（仮差押えの登記をする方法によるものを除く。）は、航海中の船舶（停泊中のものを除く。）に対してはすることができない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="690">
                      <ArticleCaption>（船舶所有者の責任）</ArticleCaption>
                      <ArticleTitle>第六百九十条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶所有者は、船長その他の船員がその職務を行うについて故意又は過失によって他人に加えた損害を賠償する責任を負う。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="691">
                      <ArticleCaption>（社員の持分の売渡しの請求）</ArticleCaption>
                      <ArticleTitle>第六百九十一条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">持分会社の業務を執行する社員の持分の移転により当該持分会社の所有する船舶が日本の国籍を喪失することとなるときは、他の業務を執行する社員は、相当の対価でその持分を売り渡すことを請求することができる。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                  </Subsection>
                  <Subsection Num="2">
                    <SubsectionTitle>第二款　船舶の共有</SubsectionTitle>
                    <Article Num="692">
                      <ArticleCaption>（共有に係る船舶の利用）</ArticleCaption>
                      <ArticleTitle>第六百九十二条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶共有者の間においては、船舶の利用に関する事項は、各船舶共有者の持分の価格に従い、その過半数で決する。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="693">
                      <ArticleTitle>第六百九十三条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶共有者は、その持分の価格に応じ、船舶の利用に関する費用を負担しなければならない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="694">
                      <ArticleCaption>（船舶共有者の持分買取請求）</ArticleCaption>
                      <ArticleTitle>第六百九十四条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶共有者が次に掲げる事項を決定したときは、その決定について異議のある船舶共有者は、他の船舶共有者に対し、相当の対価で自己の持分を買い取ることを請求することができる。</Sentence>
                        </ParagraphSentence>
                        <Item Num="1">
                          <ItemTitle>一</ItemTitle>
                          <ItemSentence>
                            <Sentence Num="1" WritingMode="vertical">新たな航海（船舶共有者の間で予定されていなかったものに限る。）をすること。</Sentence>
                          </ItemSentence>
                        </Item>
                        <Item Num="2">
                          <ItemTitle>二</ItemTitle>
                          <ItemSentence>
                            <Sentence Num="1" WritingMode="vertical">船舶の大修繕をすること。</Sentence>
                          </ItemSentence>
                        </Item>
                      </Paragraph>
                      <Paragraph Num="2">
                        <ParagraphNum>２</ParagraphNum>
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">前項の規定による請求をしようとする者は、同項の決定の日（当該決定に加わらなかった場合にあっては、当該決定の通知を受けた日の翌日）から三日以内に、他の船舶共有者又は船舶管理人に対してその旨の通知を発しなければならない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="695">
                      <ArticleCaption>（船舶共有者の第三者に対する責任）</ArticleCaption>
                      <ArticleTitle>第六百九十五条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶共有者は、その持分の価格に応じ、船舶の利用について生じた債務を弁済する責任を負う。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="696">
                      <ArticleCaption>（持分の譲渡）</ArticleCaption>
                      <ArticleTitle>第六百九十六条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶共有者の間に組合契約があるときであっても、各船舶共有者（船舶管理人であるものを除く。）は、他の船舶共有者の承諾を得ないで、その持分の全部又は一部を他人に譲渡することができる。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                      <Paragraph Num="2">
                        <ParagraphNum>２</ParagraphNum>
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶管理人である船舶共有者は、他の船舶共有者の全員の承諾を得なければ、その持分の全部又は一部を他人に譲渡することができない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="697">
                      <ArticleCaption>（船舶管理人）</ArticleCaption>
                      <ArticleTitle>第六百九十七条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶共有者は、船舶管理人を選任しなければならない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                      <Paragraph Num="2">
                        <ParagraphNum>２</ParagraphNum>
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶共有者でない者を船舶管理人とするには、船舶共有者の全員の同意がなければならない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                      <Paragraph Num="3">
                        <ParagraphNum>３</ParagraphNum>
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶共有者が船舶管理人を選任したときは、その登記をしなければならない。</Sentence>
                          <Sentence Num="2" WritingMode="vertical">船舶管理人の代理権の消滅についても、同様とする。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                      <Paragraph Num="4">
                        <ParagraphNum>４</ParagraphNum>
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">第九条の規定は、前項の規定による登記について準用する。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="698">
                      <ArticleCaption>（船舶管理人の代理権）</ArticleCaption>
                      <ArticleTitle>第六百九十八条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶管理人は、次に掲げる行為を除き、船舶共有者に代わって船舶の利用に関する一切の裁判上又は裁判外の行為をする権限を有する。</Sentence>
                        </ParagraphSentence>
                        <Item Num="1">
                          <ItemTitle>一</ItemTitle>
                          <ItemSentence>
                            <Sentence Num="1" WritingMode="vertical">船舶を賃貸し、又はこれについて抵当権を設定すること。</Sentence>
                          </ItemSentence>
                        </Item>
                        <Item Num="2">
                          <ItemTitle>二</ItemTitle>
                          <ItemSentence>
                            <Sentence Num="1" WritingMode="vertical">船舶を保険に付すること。</Sentence>
                          </ItemSentence>
                        </Item>
                        <Item Num="3">
                          <ItemTitle>三</ItemTitle>
                          <ItemSentence>
                            <Sentence Num="1" WritingMode="vertical">新たな航海（船舶共有者の間で予定されていなかったものに限る。）をすること。</Sentence>
                          </ItemSentence>
                        </Item>
                        <Item Num="4">
                          <ItemTitle>四</ItemTitle>
                          <ItemSentence>
                            <Sentence Num="1" WritingMode="vertical">船舶の大修繕をすること。</Sentence>
                          </ItemSentence>
                        </Item>
                        <Item Num="5">
                          <ItemTitle>五</ItemTitle>
                          <ItemSentence>
                            <Sentence Num="1" WritingMode="vertical">借財をすること。</Sentence>
                          </ItemSentence>
                        </Item>
                      </Paragraph>
                      <Paragraph Num="2">
                        <ParagraphNum>２</ParagraphNum>
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶管理人の代理権に加えた制限は、善意の第三者に対抗することができない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="699">
                      <ArticleCaption>（船舶管理人の義務）</ArticleCaption>
                      <ArticleTitle>第六百九十九条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶管理人は、その職務に関する帳簿を備え、船舶の利用に関する一切の事項を記載しなければならない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                      <Paragraph Num="2">
                        <ParagraphNum>２</ParagraphNum>
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶管理人は、一定の期間ごとに、船舶の利用に関する計算を行い、各船舶共有者の承認を求めなければならない。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                    <Article Num="700">
                      <ArticleCaption>（船舶共有者の持分の売渡しの請求等）</ArticleCaption>
                      <ArticleTitle>第七百条</ArticleTitle>
                      <Paragraph Num="1">
                        <ParagraphNum />
                        <ParagraphSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶共有者の持分の移転又は国籍の喪失により船舶が日本の国籍を喪失することとなるときは、他の船舶共有者は、相当の対価でその持分を売り渡すことを請求し、又は競売に付することができる。</Sentence>
                        </ParagraphSentence>
                      </Paragraph>
                    </Article>
                  </Subsection>
                </Section>
                <Section Num="3">
                  <SectionTitle>第三節　船舶賃貸借</SectionTitle>
                  <Article Num="701">
                    <ArticleCaption>（船舶賃貸借の対抗力）</ArticleCaption>
                    <ArticleTitle>第七百一条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">船舶の賃貸借は、これを登記したときは、その後その船舶について物権を取得した者に対しても、その効力を生ずる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="702">
                    <ArticleCaption>（船舶の賃借人による修繕）</ArticleCaption>
                    <ArticleTitle>第七百二条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">船舶の賃借人であって商行為をする目的でその船舶を航海の用に供しているものは、その船舶を受け取った後にこれに生じた損傷があるときは、その利用に必要な修繕をする義務を負う。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その損傷が賃貸人の責めに帰すべき事由によるものであるときは、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="703">
                    <ArticleCaption>（船舶の賃借人の権利義務等）</ArticleCaption>
                    <ArticleTitle>第七百三条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前条に規定する船舶の賃借人は、その船舶の利用に関する事項については、第三者に対して、船舶所有者と同一の権利義務を有する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">前項の場合において、その船舶の利用について生じた先取特権は、船舶所有者に対しても、その効力を生ずる。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、船舶の賃借人によるその利用の態様が船舶所有者との契約に反することを先取特権者が知っていたときは、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                </Section>
                <Section Num="4">
                  <SectionTitle>第四節　定期<Ruby>傭<Rt>よう</Rt></Ruby>船</SectionTitle>
                  <Article Num="704">
                    <ArticleCaption>（定期<Ruby>傭<Rt>よう</Rt></Ruby>船契約）</ArticleCaption>
                    <ArticleTitle>第七百四条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">定期<Ruby>傭<Rt>よう</Rt></Ruby>船契約は、当事者の一方が<Ruby>艤<Rt>ぎ</Rt></Ruby>装した船舶に船員を乗り組ませて当該船舶を一定の期間相手方の利用に供することを約し、相手方がこれに対してその傭船料を支払うことを約することによって、その効力を生ずる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="705">
                    <ArticleCaption>（定期傭船者による指示）</ArticleCaption>
                    <ArticleTitle>第七百五条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">定期傭船者は、船長に対し、航路の決定その他の船舶の利用に関し必要な事項を指示することができる。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、発航前の検査その他の航海の安全に関する事項については、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="706">
                    <ArticleCaption>（費用の負担）</ArticleCaption>
                    <ArticleTitle>第七百六条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">船舶の燃料、水先料、入港料その他船舶の利用に関する通常の費用は、定期傭船者の負担とする。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="707">
                    <ArticleCaption>（運送及び船舶賃貸借に関する規定の準用）</ArticleCaption>
                    <ArticleTitle>第七百七条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">第五百七十二条、第七百三十九条第一項並びに第七百四十条第一項及び第三項の規定は定期傭船契約に係る船舶により物品を運送する場合について、第七百三条第二項の規定は定期傭船者の船舶の利用について生ずる先取特権について、それぞれ準用する。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、第七百三十九条第一項中「発航の当時」とあるのは、「各航海に係る発航の当時」と読み替えるものとする。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                </Section>
              </Chapter>
              <Chapter Num="2">
                <ChapterTitle>第二章　船長</ChapterTitle>
                <Article Num="708">
                  <ArticleCaption>（船長の代理権）</ArticleCaption>
                  <ArticleTitle>第七百八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船長は、船籍港外においては、次に掲げる行為を除き、船舶所有者に代わって航海のために必要な一切の裁判上又は裁判外の行為をする権限を有する。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">船舶について抵当権を設定すること。</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">借財をすること。</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船長の代理権に加えた制限は、善意の第三者に対抗することができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="709">
                  <ArticleCaption>（船長による職務代行者の選任）</ArticleCaption>
                  <ArticleTitle>第七百九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船長は、やむを得ない事由により自ら船舶を指揮することができない場合には、法令に別段の定めがあるときを除き、自己に代わって船長の職務を行うべき者を選任することができる。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、船長は、船舶所有者に対してその選任についての責任を負う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="710">
                  <ArticleCaption>（属具目録の備置き）</ArticleCaption>
                  <ArticleTitle>第七百十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船長は、属具目録を船内に備え置かなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="711">
                  <ArticleCaption>（船長による積荷の処分）</ArticleCaption>
                  <ArticleTitle>第七百十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船長は、航海中に積荷の利害関係人の利益のため必要があるときは、利害関係人に代わり、最もその利益に適合する方法によって、その積荷の処分をしなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">積荷の利害関係人は、前項の処分によりその積荷について債務を負担したときは、当該債務に係る債権者にその積荷について有する権利を移転して、その責任を免れることができる。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、利害関係人に過失があったときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="712">
                  <ArticleCaption>（航海継続のための積荷の使用）</ArticleCaption>
                  <ArticleTitle>第七百十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船長は、航海を継続するため必要があるときは、積荷を航海の用に供することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">第五百七十六条第一項及び第二項の規定は、前項の場合において船舶所有者が支払うべき償金の額について準用する。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、同条第一項中「引渡し」とあるのは、「陸揚げ」と読み替えるものとする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="713">
                  <ArticleCaption>（船長の責任）</ArticleCaption>
                  <ArticleTitle>第七百十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">船長は、海員がその職務を行うについて故意又は過失によって他人に加えた損害を賠償する責任を負う。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、船長が海員の監督について注意を怠らなかったことを証明したときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="714">
                  <ArticleCaption>（船長の報告義務）</ArticleCaption>
                  <ArticleTitle>第七百十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船長は、遅滞なく、航海に関する重要な事項を船舶所有者に報告しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="715">
                  <ArticleCaption>（船長の解任）</ArticleCaption>
                  <ArticleTitle>第七百十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶所有者は、いつでも、船長を解任することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の規定により解任された船長は、その解任について正当な理由がある場合を除き、船舶所有者に対し、解任によって生じた損害の賠償を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船長が船舶共有者である場合において、その意に反して解任されたときは、船長は、他の船舶共有者に対し、相当の対価で自己の持分を買い取ることを請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="4">
                    <ParagraphNum>４</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船長は、前項の規定による請求をしようとするときは、遅滞なく、他の船舶共有者又は船舶管理人に対してその旨の通知を発しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="716:736">
                  <ArticleTitle>第七百十六条から第七百三十六条まで</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="3">
                <ChapterTitle>第三章　海上物品運送に関する特則</ChapterTitle>
                <Section Num="1">
                  <SectionTitle>第一節　個品運送</SectionTitle>
                  <Article Num="737">
                    <ArticleCaption>（運送品の船積み等）</ArticleCaption>
                    <ArticleTitle>第七百三十七条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、個品運送契約（個々の運送品を目的とする運送契約をいう。以下この節において同じ。）に基づいて荷送人から運送品を受け取ったときは、その船積み及び積付けをしなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">荷送人が運送品の引渡しを怠ったときは、船長は、直ちに発航することができる。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、荷送人は、運送賃の全額（運送人がその運送品に代わる他の運送品について運送賃を得た場合にあっては、当該運送賃の額を控除した額）を支払わなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="738">
                    <ArticleCaption>（船長に対する必要書類の交付）</ArticleCaption>
                    <ArticleTitle>第七百三十八条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">荷送人は、船積期間内に、運送に必要な書類を船長に交付しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="739">
                    <ArticleCaption>（航海に堪える能力に関する注意義務）</ArticleCaption>
                    <ArticleTitle>第七百三十九条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">運送人は、発航の当時次に掲げる事項を欠いたことにより生じた運送品の滅失、損傷又は延着について、損害賠償の責任を負う。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、運送人がその当時当該事項について注意を怠らなかったことを証明したときは、この限りでない。</Sentence>
                      </ParagraphSentence>
                      <Item Num="1">
                        <ItemTitle>一</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶を航海に堪える状態に置くこと。</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="2">
                        <ItemTitle>二</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">船員の乗組み、船舶の艤装及び需品の補給を適切に行うこと。</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="3">
                        <ItemTitle>三</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">船倉、冷蔵室その他運送品を積み込む場所を運送品の受入れ、運送及び保存に適する状態に置くこと。</Sentence>
                        </ItemSentence>
                      </Item>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の規定による運送人の損害賠償の責任を免除し、又は軽減する特約は、無効とする。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="740">
                    <ArticleCaption>（違法な船積品の陸揚げ等）</ArticleCaption>
                    <ArticleTitle>第七百四十条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">法令に違反して又は個品運送契約によらないで船積みがされた運送品については、運送人は、いつでも、これを陸揚げすることができ、船舶又は積荷に危害を及ぼすおそれがあるときは、これを放棄することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、前項に規定する運送品を運送したときは、船積みがされた地及び時における同種の運送品に係る運送賃の最高額を請求することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前二項の規定は、運送人その他の利害関係人の荷送人に対する損害賠償の請求を妨げない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="741">
                    <ArticleCaption>（荷受人の運送賃支払義務等）</ArticleCaption>
                    <ArticleTitle>第七百四十一条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">荷受人は、運送品を受け取ったときは、個品運送契約又は船荷証券の趣旨に従い、運送人に対し、次に掲げる金額の合計額（以下この節において「運送賃等」という。）を支払う義務を負う。</Sentence>
                      </ParagraphSentence>
                      <Item Num="1">
                        <ItemTitle>一</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">運送賃、付随の費用及び立替金の額</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="2">
                        <ItemTitle>二</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">運送品の価格に応じて支払うべき救助料の額及び共同海損の分担額</Sentence>
                        </ItemSentence>
                      </Item>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、運送賃等の支払を受けるまで、運送品を留置することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="742">
                    <ArticleCaption>（運送品の競売）</ArticleCaption>
                    <ArticleTitle>第七百四十二条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">運送人は、荷受人に運送品を引き渡した後においても、運送賃等の支払を受けるため、その運送品を競売に付することができる。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、第三者がその占有を取得したときは、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="743">
                    <ArticleCaption>（荷送人による発航前の解除）</ArticleCaption>
                    <ArticleTitle>第七百四十三条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">発航前においては、荷送人は、運送賃の全額を支払って個品運送契約の解除をすることができる。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、個品運送契約の解除によって運送人に生ずる損害の額が運送賃の全額を下回るときは、その損害を賠償すれば足りる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の規定は、運送品の全部又は一部の船積みがされた場合には、他の荷送人及び傭船者の全員の同意を得たときに限り、適用する。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、荷送人は、運送品の船積み及び陸揚げに要する費用を負担しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="744">
                    <ArticleTitle>第七百四十四条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">荷送人は、前条の規定により個品運送契約の解除をしたときであっても、運送人に対する付随の費用及び立替金の支払義務を免れることができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="745">
                    <ArticleCaption>（荷送人による発航後の解除）</ArticleCaption>
                    <ArticleTitle>第七百四十五条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">発航後においては、荷送人は、他の荷送人及び傭船者の全員の同意を得、かつ、運送賃等及び運送品の陸揚げによって生ずべき損害の額の合計額を支払い、又は相当の担保を供しなければ、個品運送契約の解除をすることができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="746">
                    <ArticleCaption>（積荷を航海の用に供した場合の運送賃）</ArticleCaption>
                    <ArticleTitle>第七百四十六条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、船長が第七百十二条第一項の規定により積荷を航海の用に供したときにおいても、運送賃の全額を請求することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="747">
                    <ArticleCaption>（非航海船による物品運送への準用）</ArticleCaption>
                    <ArticleTitle>第七百四十七条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">この節の規定は、商行為をする目的で専ら湖川、港湾その他の海以外の水域において航行の用に供する船舶（端舟その他ろかいのみをもって運転し、又は主としてろかいをもって運転する舟を除く。以下この編において「非航海船」という。）によって物品を運送する場合について準用する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                </Section>
                <Section Num="2">
                  <SectionTitle>第二節　航海傭船</SectionTitle>
                  <Article Num="748">
                    <ArticleCaption>（運送品の船積み）</ArticleCaption>
                    <ArticleTitle>第七百四十八条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">航海傭船契約（船舶の全部又は一部を目的とする運送契約をいう。以下この節において同じ。）に基づいて運送品の船積みのために必要な準備を完了したときは、船長は、遅滞なく、傭船者に対してその旨の通知を発しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">船積期間の定めがある航海傭船契約において始期を定めなかったときは、その期間は、前項の通知があった時から起算する。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、不可抗力によって船積みをすることができない期間は、船積期間に算入しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">傭船者が船積期間の経過後に運送品の船積みをした場合には、運送人は、特約がないときであっても、相当な滞船料を請求することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="749">
                    <ArticleCaption>（第三者による船積み）</ArticleCaption>
                    <ArticleTitle>第七百四十九条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">船長は、第三者から運送品を受け取るべき場合において、その第三者を確知することができないとき、又はその第三者が運送品の船積みをしないときは、直ちに傭船者に対してその旨の通知を発しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の場合において、傭船者は、船積期間内に限り、運送品の船積みをすることができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="750">
                    <ArticleCaption>（傭船者による発航の請求）</ArticleCaption>
                    <ArticleTitle>第七百五十条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">傭船者は、運送品の全部の船積みをしていないときであっても、船長に対し、発航の請求をすることができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">傭船者は、前項の請求をしたときは、運送人に対し、運送賃の全額のほか、運送品の全部の船積みをしないことによって生じた費用を支払う義務を負い、かつ、その請求により、当該費用の支払について相当の担保を供しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="751">
                    <ArticleCaption>（船長の発航権）</ArticleCaption>
                    <ArticleTitle>第七百五十一条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">船長は、船積期間が経過した後は、傭船者が運送品の全部の船積みをしていないときであっても、直ちに発航することができる。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合においては、前条第二項の規定を準用する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="752">
                    <ArticleCaption>（運送品の陸揚げ）</ArticleCaption>
                    <ArticleTitle>第七百五十二条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送品の陸揚げのために必要な準備を完了したときは、船長は、遅滞なく、荷受人に対してその旨の通知を発しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">陸揚期間の定めがある航海傭船契約において始期を定めなかったときは、その期間は、前項の通知があった時から起算する。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、不可抗力によって陸揚げをすることができない期間は、陸揚期間に算入しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">荷受人が陸揚期間の経過後に運送品の陸揚げをした場合には、運送人は、特約がないときであっても、相当な滞船料を請求することができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="753">
                    <ArticleCaption>（全部航海傭船契約の傭船者による発航前の解除）</ArticleCaption>
                    <ArticleTitle>第七百五十三条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">発航前においては、全部航海傭船契約（船舶の全部を目的とする航海傭船契約をいう。以下この節において同じ。）の傭船者は、運送賃の全額及び滞船料を支払って全部航海傭船契約の解除をすることができる。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、全部航海傭船契約の解除によって運送人に生ずる損害の額が運送賃の全額及び滞船料を下回るときは、その損害を賠償すれば足りる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">傭船者は、運送品の全部又は一部の船積みをした後に前項の規定により全部航海傭船契約の解除をしたときは、その船積み及び陸揚げに要する費用を負担しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">全部航海傭船契約の傭船者が船積期間内に運送品の船積みをしなかったときは、運送人は、その傭船者が全部航海傭船契約の解除をしたものとみなすことができる。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="754">
                    <ArticleCaption>（全部航海傭船契約の傭船者による発航後の解除）</ArticleCaption>
                    <ArticleTitle>第七百五十四条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">発航後においては、全部航海傭船契約の傭船者は、第七百四十五条に規定する合計額及び滞船料を支払い、又は相当の担保を供しなければ、全部航海傭船契約の解除をすることができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="755">
                    <ArticleCaption>（一部航海傭船契約の解除への準用）</ArticleCaption>
                    <ArticleTitle>第七百五十五条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">第七百四十三条、第七百四十五条及び第七百五十三条第三項の規定は、船舶の一部を目的とする航海傭船契約の解除について準用する。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、第七百四十三条第一項中「全額」とあるのは「全額及び滞船料」と、第七百四十五条中「合計額」とあるのは「合計額並びに滞船料」と読み替えるものとする。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="756">
                    <ArticleCaption>（個品運送契約に関する規定の準用等）</ArticleCaption>
                    <ArticleTitle>第七百五十六条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">第七百三十八条から第七百四十二条まで（第七百三十九条第二項を除く。）、第七百四十四条、第七百四十六条及び第七百四十七条の規定は、航海傭船契約について準用する。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、第七百四十一条第一項中「金額」とあるのは「金額及び滞船料」と、第七百四十四条中「前条」とあるのは「第七百五十三条第一項又は第七百五十五条において準用する前条」と、第七百四十七条中「この節」とあるのは「次節」と読み替えるものとする。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、前項において準用する第七百三十九条第一項の規定による運送人の損害賠償の責任を免除し、又は軽減する特約をもって船荷証券の所持人に対抗することができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                </Section>
                <Section Num="3">
                  <SectionTitle>第三節　船荷証券等</SectionTitle>
                  <Article Num="757">
                    <ArticleCaption>（船荷証券の交付義務）</ArticleCaption>
                    <ArticleTitle>第七百五十七条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人又は船長は、荷送人又は傭船者の請求により、運送品の船積み後遅滞なく、船積みがあった旨を記載した船荷証券（以下この節において「船積船荷証券」という。）の一通又は数通を交付しなければならない。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">運送品の船積み前においても、その受取後は、荷送人又は傭船者の請求により、受取があった旨を記載した船荷証券（以下この節において「受取船荷証券」という。）の一通又は数通を交付しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">受取船荷証券が交付された場合には、受取船荷証券の全部と引換えでなければ、船積船荷証券の交付を請求することができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前二項の規定は、運送品について現に海上運送状が交付されているときは、適用しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="758">
                    <ArticleCaption>（船荷証券の記載事項）</ArticleCaption>
                    <ArticleTitle>第七百五十八条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">船荷証券には、次に掲げる事項（受取船荷証券にあっては、第七号及び第八号に掲げる事項を除く。）を記載し、運送人又は船長がこれに署名し、又は記名押印しなければならない。</Sentence>
                      </ParagraphSentence>
                      <Item Num="1">
                        <ItemTitle>一</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">運送品の種類</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="2">
                        <ItemTitle>二</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">運送品の容積若しくは重量又は包若しくは個品の数及び運送品の記号</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="3">
                        <ItemTitle>三</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">外部から認められる運送品の状態</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="4">
                        <ItemTitle>四</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">荷送人又は傭船者の氏名又は名称</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="5">
                        <ItemTitle>五</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">荷受人の氏名又は名称</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="6">
                        <ItemTitle>六</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">運送人の氏名又は名称</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="7">
                        <ItemTitle>七</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">船舶の名称</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="8">
                        <ItemTitle>八</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">船積港及び船積みの年月日</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="9">
                        <ItemTitle>九</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">陸揚港</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="10">
                        <ItemTitle>十</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">運送賃</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="11">
                        <ItemTitle>十一</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">数通の船荷証券を作成したときは、その数</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="12">
                        <ItemTitle>十二</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">作成地及び作成の年月日</Sentence>
                        </ItemSentence>
                      </Item>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">受取船荷証券と引換えに船積船荷証券の交付の請求があったときは、その受取船荷証券に船積みがあった旨を記載し、かつ、署名し、又は記名押印して、船積船荷証券の作成に代えることができる。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合においては、前項第七号及び第八号に掲げる事項をも記載しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="759">
                    <ArticleCaption>（荷送人又は傭船者の通知）</ArticleCaption>
                    <ArticleTitle>第七百五十九条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前条第一項第一号及び第二号に掲げる事項は、その事項につき荷送人又は傭船者の書面又は電磁的方法による通知があったときは、その通知に従って記載しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前項の規定は、同項の通知が正確でないと信ずべき正当な理由がある場合及び当該通知が正確であることを確認する適当な方法がない場合には、適用しない。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">運送品の記号について、運送品又はその容器若しくは包装に航海の終了の時まで判読に堪える表示がされていない場合も、同様とする。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">荷送人又は傭船者は、運送人に対し、第一項の通知が正確でないことによって生じた損害を賠償する責任を負う。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="760">
                    <ArticleCaption>（船荷証券の不実記載）</ArticleCaption>
                    <ArticleTitle>第七百六十条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、船荷証券の記載が事実と異なることをもって善意の所持人に対抗することができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="761">
                    <ArticleCaption>（運送品に関する処分）</ArticleCaption>
                    <ArticleTitle>第七百六十一条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">船荷証券が作成されたときは、運送品に関する処分は、船荷証券によってしなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="762">
                    <ArticleCaption>（船荷証券の譲渡又は質入れ）</ArticleCaption>
                    <ArticleTitle>第七百六十二条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">船荷証券は、記名式であるときであっても、裏書によって、譲渡し、又は質権の目的とすることができる。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、船荷証券に裏書を禁止する旨を記載したときは、この限りでない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="763">
                    <ArticleCaption>（船荷証券の引渡しの効力）</ArticleCaption>
                    <ArticleTitle>第七百六十三条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">船荷証券により運送品を受け取ることができる者に船荷証券を引き渡したときは、その引渡しは、運送品について行使する権利の取得に関しては、運送品の引渡しと同一の効力を有する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="764">
                    <ArticleCaption>（運送品の引渡請求）</ArticleCaption>
                    <ArticleTitle>第七百六十四条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">船荷証券が作成されたときは、これと引換えでなければ、運送品の引渡しを請求することができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="765">
                    <ArticleCaption>（数通の船荷証券を作成した場合における運送品の引渡し）</ArticleCaption>
                    <ArticleTitle>第七百六十五条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">陸揚港においては、運送人は、数通の船荷証券のうち一通の所持人が運送品の引渡しを請求したときであっても、その引渡しを拒むことができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">陸揚港外においては、運送人は、船荷証券の全部の返還を受けなければ、運送品の引渡しをすることができない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="766">
                    <ArticleTitle>第七百六十六条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">二人以上の船荷証券の所持人がある場合において、その一人が他の所持人より先に運送人から運送品の引渡しを受けたときは、当該他の所持人の船荷証券は、その効力を失う。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="767">
                    <ArticleCaption>（二人以上の船荷証券の所持人から請求を受けた場合の供託）</ArticleCaption>
                    <ArticleTitle>第七百六十七条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">二人以上の船荷証券の所持人が運送品の引渡しを請求したときは、運送人は、その運送品を供託することができる。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">運送人が第七百六十五条第一項の規定により運送品の一部を引き渡した後に他の所持人が運送品の引渡しを請求したときにおけるその運送品の残部についても、同様とする。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人は、前項の規定により運送品を供託したときは、遅滞なく、請求をした各所持人に対してその旨の通知を発しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">第一項に規定する場合においては、最も先に発送され、又は引き渡された船荷証券の所持人が他の所持人に優先する。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="768">
                    <ArticleCaption>（船荷証券が作成された場合の特則）</ArticleCaption>
                    <ArticleTitle>第七百六十八条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">船荷証券が作成された場合における前編第八章第二節の規定の適用については、第五百八十条中「荷送人」とあるのは、「船荷証券の所持人」とし、第五百八十一条、第五百八十二条第二項及び第五百八十七条ただし書の規定は、適用しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="769">
                    <ArticleCaption>（複合運送証券）</ArticleCaption>
                    <ArticleTitle>第七百六十九条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人又は船長は、陸上運送及び海上運送を一の契約で引き受けたときは、荷送人の請求により、運送品の船積み後遅滞なく、船積みがあった旨を記載した複合運送証券の一通又は数通を交付しなければならない。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">運送品の船積み前においても、その受取後は、荷送人の請求により、受取があった旨を記載した複合運送証券の一通又は数通を交付しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">第七百五十七条第二項及び第七百五十八条から前条までの規定は、複合運送証券について準用する。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、第七百五十八条第一項中「除く。）」とあるのは、「除く。）並びに発送地及び到達地」と読み替えるものとする。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                </Section>
                <Section Num="4">
                  <SectionTitle>第四節　海上運送状</SectionTitle>
                  <Article Num="770">
                    <ArticleTitle>第七百七十条</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">運送人又は船長は、荷送人又は傭船者の請求により、運送品の船積み後遅滞なく、船積みがあった旨を記載した海上運送状を交付しなければならない。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">運送品の船積み前においても、その受取後は、荷送人又は傭船者の請求により、受取があった旨を記載した海上運送状を交付しなければならない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="2">
                      <ParagraphNum>２</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">海上運送状には、次に掲げる事項を記載しなければならない。</Sentence>
                      </ParagraphSentence>
                      <Item Num="1">
                        <ItemTitle>一</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">第七百五十八条第一項各号（第十一号を除く。）に掲げる事項（運送品の受取があった旨を記載した海上運送状にあっては、同項第七号及び第八号に掲げる事項を除く。）</Sentence>
                        </ItemSentence>
                      </Item>
                      <Item Num="2">
                        <ItemTitle>二</ItemTitle>
                        <ItemSentence>
                          <Sentence Num="1" WritingMode="vertical">数通の海上運送状を作成したときは、その数</Sentence>
                        </ItemSentence>
                      </Item>
                    </Paragraph>
                    <Paragraph Num="3">
                      <ParagraphNum>３</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">第一項の運送人又は船長は、海上運送状の交付に代えて、法務省令で定めるところにより、荷送人又は傭船者の承諾を得て、海上運送状に記載すべき事項を電磁的方法により提供することができる。</Sentence>
                        <Sentence Num="2" WritingMode="vertical">この場合において、当該運送人又は船長は、海上運送状を交付したものとみなす。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                    <Paragraph Num="4">
                      <ParagraphNum>４</ParagraphNum>
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">前三項の規定は、運送品について現に船荷証券が交付されているときは、適用しない。</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                  <Article Num="771:787">
                    <ArticleTitle>第七百七十一条から第七百八十七条まで</ArticleTitle>
                    <Paragraph Num="1">
                      <ParagraphNum />
                      <ParagraphSentence>
                        <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                      </ParagraphSentence>
                    </Paragraph>
                  </Article>
                </Section>
              </Chapter>
              <Chapter Num="4">
                <ChapterTitle>第四章　船舶の衝突</ChapterTitle>
                <Article Num="788">
                  <ArticleCaption>（船舶所有者間の責任の分担）</ArticleCaption>
                  <ArticleTitle>第七百八十八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶と他の船舶との衝突（次条において「船舶の衝突」という。）に係る事故が生じた場合において、衝突したいずれの船舶についてもその船舶所有者又は船員に過失があったときは、裁判所は、これらの過失の軽重を考慮して、各船舶所有者について、その衝突による損害賠償の責任及びその額を定める。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、過失の軽重を定めることができないときは、損害賠償の責任及びその額は、各船舶所有者が等しい割合で負担する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="789">
                  <ArticleCaption>（船舶の衝突による損害賠償請求権の消滅時効）</ArticleCaption>
                  <ArticleTitle>第七百八十九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶の衝突を原因とする不法行為による損害賠償請求権（財産権が侵害されたことによるものに限る。）は、不法行為の時から二年間行使しないときは、時効によって消滅する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="790">
                  <ArticleCaption>（準衝突）</ArticleCaption>
                  <ArticleTitle>第七百九十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前二条の規定は、船舶がその航行若しくは船舶の取扱いに関する行為又は船舶に関する法令に違反する行為により他の船舶に著しく接近し、当該他の船舶又は当該他の船舶内にある人若しくは物に損害を加えた事故について準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="791">
                  <ArticleCaption>（非航海船との衝突等への準用）</ArticleCaption>
                  <ArticleTitle>第七百九十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前三条の規定は、船舶と非航海船との事故について準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="5">
                <ChapterTitle>第五章　海難救助</ChapterTitle>
                <Article Num="792">
                  <ArticleCaption>（救助料の支払の請求等）</ArticleCaption>
                  <ArticleTitle>第七百九十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶又は積荷その他の船舶内にある物（以下この編において「積荷等」という。）の全部又は一部が海難に遭遇した場合において、これを救助した者があるときは、その者（以下この章において「救助者」という。）は、契約に基づかないで救助したときであっても、その結果に対して救助料の支払を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶所有者及び船長は、積荷等の所有者に代わってその救助に係る契約を締結する権限を有する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="793">
                  <ArticleCaption>（救助料の額）</ArticleCaption>
                  <ArticleTitle>第七百九十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">救助料につき特約がない場合において、その額につき争いがあるときは、裁判所は、危険の程度、救助の結果、救助のために要した労力及び費用（海洋の汚染の防止又は軽減のためのものを含む。）その他一切の事情を考慮して、これを定める。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="794">
                  <ArticleCaption>（救助料の増減の請求）</ArticleCaption>
                  <ArticleTitle>第七百九十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">海難に際し契約で救助料を定めた場合において、その額が著しく不相当であるときは、当事者は、その増減を請求することができる。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合においては、前条の規定を準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="795">
                  <ArticleCaption>（救助料の上限額）</ArticleCaption>
                  <ArticleTitle>第七百九十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">救助料の額は、特約がないときは、救助された物の価額（救助された積荷の運送賃の額を含む。）の合計額を超えることができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="796">
                  <ArticleCaption>（救助料の割合等）</ArticleCaption>
                  <ArticleTitle>第七百九十六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">数人が共同して救助した場合において、各救助者に支払うべき救助料の割合については、第七百九十三条の規定を準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">第七百九十二条第一項に規定する場合において、人命の救助に従事した者があるときは、その者も、前項の規定に従って救助料の支払を受けることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="797">
                  <ArticleTitle>第七百九十七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">救助に従事した船舶に係る救助料については、その三分の二を船舶所有者に支払い、その三分の一を船員に支払わなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の規定に反する特約で船員に不利なものは、無効とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前二項の規定にかかわらず、救助料の割合が著しく不相当であるときは、船舶所有者又は船員の一方は、他の一方に対し、その増減を請求することができる。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合においては、第七百九十三条の規定を準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="4">
                    <ParagraphNum>４</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">各船員に支払うべき救助料の割合は、救助に従事した船舶の船舶所有者が決定する。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合においては、前条の規定を準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="5">
                    <ParagraphNum>５</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">救助者が救助することを業とする者であるときは、前各項の規定にかかわらず、救助料の全額をその救助者に支払わなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="798">
                  <ArticleCaption>（救助料の割合の案）</ArticleCaption>
                  <ArticleTitle>第七百九十八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶所有者が前条第四項の規定により救助料の割合を決定するには、航海を終了するまでにその案を作成し、これを船員に示さなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="799">
                  <ArticleTitle>第七百九十九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船員は、前条の案に対し、異議の申立てをすることができる。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、当該異議の申立ては、その案が示された後、当該異議の申立てをすることができる最初の港の管海官庁にしなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">管海官庁は、前項の規定による異議の申立てを理由があると認めるときは、前条の案を更正することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶所有者は、第一項の規定による異議の申立てについての管海官庁の決定があるまでは、船員に対し、救助料の支払をすることができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="800">
                  <ArticleTitle>第八百条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶所有者が第七百九十八条の案の作成を怠ったときは、管海官庁は、船員の請求により、船舶所有者に対し、その案の作成を命ずることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶所有者が前項の規定による命令に従わないときは、管海官庁は、自ら第七百九十七条第四項の規定による決定をすることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="801">
                  <ArticleCaption>（救助料を請求することができない場合）</ArticleCaption>
                  <ArticleTitle>第八百一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">次に掲げる場合には、救助者は、救助料を請求することができない。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">故意に海難を発生させたとき。</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">正当な事由により救助を拒まれたにもかかわらず、救助したとき。</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                </Article>
                <Article Num="802">
                  <ArticleCaption>（積荷等についての先取特権）</ArticleCaption>
                  <ArticleTitle>第八百二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">救助料に係る債権を有する者は、救助された積荷等について先取特権を有する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の先取特権については、第八百四十三条第二項、第八百四十四条及び第八百四十六条の規定を準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="803">
                  <ArticleCaption>（救助料の支払等に係る船長の権限）</ArticleCaption>
                  <ArticleTitle>第八百三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">救助された船舶の船長は、救助料の債務者に代わってその支払に関する一切の裁判上又は裁判外の行為をする権限を有する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">救助された船舶の船長は、救助料に関し、救助料の債務者のために、原告又は被告となることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前二項の規定は、救助に従事した船舶の船長について準用する。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、これらの規定中「債務者」とあるのは、「債権者（当該船舶の船舶所有者及び海員に限る。）」と読み替えるものとする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="4">
                    <ParagraphNum>４</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前三項の規定は、契約に基づく救助については、適用しない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="804">
                  <ArticleCaption>（積荷等の所有者の責任）</ArticleCaption>
                  <ArticleTitle>第八百四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">積荷等の全部又は一部が救助されたときは、当該積荷等の所有者は、当該積荷等をもって救助料に係る債務を弁済する責任を負う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="805">
                  <ArticleCaption>（特別補償料）</ArticleCaption>
                  <ArticleTitle>第八百五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">海難に遭遇した船舶から排出された油その他の物により海洋が汚染され、当該汚染が広範囲の沿岸海域において海洋環境の保全に著しい障害を及ぼし、若しくは人の健康を害し、又はこれらの障害を及ぼすおそれがある場合において、当該船舶の救助に従事した者が当該障害の防止又は軽減のための措置をとったときは、その者（以下この条において「汚染対処船舶救助従事者」という。）は、特約があるときを除き、船舶所有者に対し、特別補償料の支払を請求することができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">特別補償料の額は、前項に規定する措置として必要又は有益であった費用に相当する額とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">汚染対処船舶救助従事者がその措置により第一項に規定する障害を防止し、又は軽減したときは、特別補償料は、当事者の請求により、前項に規定する費用に相当する額以上当該額に百分の三十（当該額が当該障害の防止又は軽減の結果に比して著しく少ないことその他の特別の事情がある場合にあっては、百分の百）を乗じて得た額を加算した額以下の範囲内において、裁判所がこれを定める。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合においては、第七百九十三条の規定を準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="4">
                    <ParagraphNum>４</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">汚染対処船舶救助従事者が同一の海難につき救助料に係る債権を有するときは、特別補償料の額は、当該救助料の額を控除した額とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="5">
                    <ParagraphNum>５</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">汚染対処船舶救助従事者の過失によって第一項に規定する障害を防止し、又は軽減することができなかったときは、裁判所は、これを考慮して、特別補償料の額を定めることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="806">
                  <ArticleCaption>（救助料に係る債権等の消滅時効）</ArticleCaption>
                  <ArticleTitle>第八百六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">救助料又は特別補償料に係る債権は、救助の作業が終了した時から二年間行使しないときは、時効によって消滅する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="807">
                  <ArticleCaption>（非航海船の救助への準用）</ArticleCaption>
                  <ArticleTitle>第八百七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">この章の規定は、非航海船又は非航海船内にある積荷その他の物を救助する場合について準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="6">
                <ChapterTitle>第六章　共同海損</ChapterTitle>
                <Article Num="808">
                  <ArticleCaption>（共同海損の成立）</ArticleCaption>
                  <ArticleTitle>第八百八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶及び積荷等に対する共同の危険を避けるために船舶又は積荷等について処分がされたときは、当該処分（以下この章において「共同危険回避処分」という。）によって生じた損害及び費用は、共同海損とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前項の規定は、同項の危険が過失によって生じた場合における利害関係人から当該過失のある者に対する求償権の行使を妨げない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="809">
                  <ArticleCaption>（共同海損となる損害又は費用）</ArticleCaption>
                  <ArticleTitle>第八百九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">共同海損となる損害の額は、次の各号に掲げる区分に応じ、当該各号に定める額によって算定する。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、第二号及び第四号に定める額については、積荷の滅失又は損傷のために支払うことを要しなくなった一切の費用の額を控除するものとする。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Column Num="1">
                          <Sentence Num="1" WritingMode="vertical">船舶</Sentence>
                        </Column>
                        <Column Num="2">
                          <Sentence Num="1" WritingMode="vertical">到達の地及び時における当該船舶の価格</Sentence>
                        </Column>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Column Num="1">
                          <Sentence Num="1" WritingMode="vertical">積荷</Sentence>
                        </Column>
                        <Column Num="2">
                          <Sentence Num="1" WritingMode="vertical">陸揚げの地及び時における当該積荷の価格</Sentence>
                        </Column>
                      </ItemSentence>
                    </Item>
                    <Item Num="3">
                      <ItemTitle>三</ItemTitle>
                      <ItemSentence>
                        <Column Num="1">
                          <Sentence Num="1" WritingMode="vertical">積荷以外の船舶内にある物</Sentence>
                        </Column>
                        <Column Num="2">
                          <Sentence Num="1" WritingMode="vertical">到達の地及び時における当該物の価格</Sentence>
                        </Column>
                      </ItemSentence>
                    </Item>
                    <Item Num="4">
                      <ItemTitle>四</ItemTitle>
                      <ItemSentence>
                        <Column Num="1">
                          <Sentence Num="1" WritingMode="vertical">運送賃</Sentence>
                        </Column>
                        <Column Num="2">
                          <Sentence Num="1" WritingMode="vertical">陸揚げの地及び時において請求することができる運送賃の額</Sentence>
                        </Column>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船荷証券その他積荷の価格を評定するに足りる書類（以下この章において「価格評定書類」という。）に積荷の実価より低い価額を記載したときは、その積荷に加えた損害の額は、当該価格評定書類に記載された価額によって定める。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">積荷の価格に影響を及ぼす事項につき価格評定書類に虚偽の記載をした場合において、当該記載によることとすれば積荷の実価より低い価格が評定されることとなるときも、同様とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">次に掲げる損害又は費用は、利害関係人が分担することを要しない。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Function="main" Num="1" WritingMode="vertical">次に掲げる物に加えた損害。</Sentence>
                        <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、次のハに掲げる物にあっては第五百七十七条第二項第一号に掲げる場合を、次のニに掲げる物にあっては甲板積みをする商慣習がある場合を除く。</Sentence>
                      </ItemSentence>
                      <Subitem1 Num="1">
                        <Subitem1Title>イ</Subitem1Title>
                        <Subitem1Sentence>
                          <Sentence Num="1" WritingMode="vertical">船舶所有者に無断で船積みがされた積荷</Sentence>
                        </Subitem1Sentence>
                      </Subitem1>
                      <Subitem1 Num="2">
                        <Subitem1Title>ロ</Subitem1Title>
                        <Subitem1Sentence>
                          <Sentence Num="1" WritingMode="vertical">船積みに際して故意に虚偽の申告がされた積荷</Sentence>
                        </Subitem1Sentence>
                      </Subitem1>
                      <Subitem1 Num="3">
                        <Subitem1Title>ハ</Subitem1Title>
                        <Subitem1Sentence>
                          <Sentence Num="1" WritingMode="vertical">高価品である積荷であって、荷送人又は傭船者が運送を委託するに当たりその種類及び価額を通知していないもの</Sentence>
                        </Subitem1Sentence>
                      </Subitem1>
                      <Subitem1 Num="4">
                        <Subitem1Title>ニ</Subitem1Title>
                        <Subitem1Sentence>
                          <Sentence Num="1" WritingMode="vertical">甲板上の積荷</Sentence>
                        </Subitem1Sentence>
                      </Subitem1>
                      <Subitem1 Num="5">
                        <Subitem1Title>ホ</Subitem1Title>
                        <Subitem1Sentence>
                          <Sentence Num="1" WritingMode="vertical">属具目録に記載がない属具</Sentence>
                        </Subitem1Sentence>
                      </Subitem1>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">特別補償料</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                </Article>
                <Article Num="810">
                  <ArticleCaption>（共同海損の分担額）</ArticleCaption>
                  <ArticleTitle>第八百十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">共同海損は、次の各号に掲げる者（船員及び旅客を除く。）が当該各号に定める額の割合に応じて分担する。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Column Num="1">
                          <Sentence Num="1" WritingMode="vertical">船舶の利害関係人</Sentence>
                        </Column>
                        <Column Num="2">
                          <Sentence Num="1" WritingMode="vertical">到達の地及び時における当該船舶の価格</Sentence>
                        </Column>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Column Num="1">
                          <Sentence Num="1" WritingMode="vertical">積荷の利害関係人</Sentence>
                        </Column>
                        <Column Num="2">
                          <Sentence Num="1" WritingMode="vertical">次のイに掲げる額から次のロに掲げる額を控除した額</Sentence>
                        </Column>
                      </ItemSentence>
                      <Subitem1 Num="1">
                        <Subitem1Title>イ</Subitem1Title>
                        <Subitem1Sentence>
                          <Sentence Num="1" WritingMode="vertical">陸揚げの地及び時における当該積荷の価格</Sentence>
                        </Subitem1Sentence>
                      </Subitem1>
                      <Subitem1 Num="2">
                        <Subitem1Title>ロ</Subitem1Title>
                        <Subitem1Sentence>
                          <Sentence Num="1" WritingMode="vertical">共同危険回避処分の時においてイに規定する積荷の全部が滅失したとした場合に当該積荷の利害関係人が支払うことを要しないこととなる運送賃その他の費用の額</Sentence>
                        </Subitem1Sentence>
                      </Subitem1>
                    </Item>
                    <Item Num="3">
                      <ItemTitle>三</ItemTitle>
                      <ItemSentence>
                        <Column Num="1">
                          <Sentence Num="1" WritingMode="vertical">積荷以外の船舶内にある物（船舶に備え付けた武器を除く。）の利害関係人</Sentence>
                        </Column>
                        <Column Num="2">
                          <Sentence Num="1" WritingMode="vertical">到達の地及び時における当該物の価格</Sentence>
                        </Column>
                      </ItemSentence>
                    </Item>
                    <Item Num="4">
                      <ItemTitle>四</ItemTitle>
                      <ItemSentence>
                        <Column Num="1">
                          <Sentence Num="1" WritingMode="vertical">運送人</Sentence>
                        </Column>
                        <Column Num="2">
                          <Sentence Num="1" WritingMode="vertical">次のイに掲げる額から次のロに掲げる額を控除した額</Sentence>
                        </Column>
                      </ItemSentence>
                      <Subitem1 Num="1">
                        <Subitem1Title>イ</Subitem1Title>
                        <Subitem1Sentence>
                          <Sentence Num="1" WritingMode="vertical">第二号ロに規定する運送賃のうち、陸揚げの地及び時において現に存する債権の額</Sentence>
                        </Subitem1Sentence>
                      </Subitem1>
                      <Subitem1 Num="2">
                        <Subitem1Title>ロ</Subitem1Title>
                        <Subitem1Sentence>
                          <Sentence Num="1" WritingMode="vertical">船員の給料その他の航海に必要な費用（共同海損となる費用を除く。）のうち、共同危険回避処分の時に船舶及び第二号イに規定する積荷の全部が滅失したとした場合に運送人が支払うことを要しないこととなる額</Sentence>
                        </Subitem1Sentence>
                      </Subitem1>
                    </Item>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">共同危険回避処分の後、到達又は陸揚げ前に船舶又は積荷等について必要費又は有益費を支出したときは、当該船舶又は積荷等については、前項第一号から第三号までに定める額は、その費用（共同海損となる費用を除く。）の額を控除した額とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">第一項に規定する者が共同危険回避処分によりその財産につき損害を受けたときは、その者については、同項各号に定める額は、その損害の額（当該財産について前項に規定する必要費又は有益費を支出した場合にあっては、その費用（共同海損となる費用に限る。）の額を超える部分の額に限る。）を加算した額とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="4">
                    <ParagraphNum>４</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">価格評定書類に積荷の実価を超える価額を記載したときは、その積荷の利害関係人は、当該価格評定書類に記載された価額に応じて共同海損を分担する。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">積荷の価格に影響を及ぼす事項につき価格評定書類に虚偽の記載をした場合において、当該記載によることとすれば積荷の実価を超える価格が評定されることとなるときも、同様とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="811">
                  <ArticleCaption>（共同海損を分担すべき者の責任）</ArticleCaption>
                  <ArticleTitle>第八百十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">前条の規定により共同海損を分担すべき者は、船舶の到達（同条第一項第二号又は第四号に掲げる者にあっては、積荷の陸揚げ）の時に現存する価額の限度においてのみ、その責任を負う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="812">
                  <ArticleCaption>（共同海損の分担に基づく債権の消滅時効）</ArticleCaption>
                  <ArticleTitle>第八百十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">共同海損の分担に基づく債権は、その計算が終了した時から一年間行使しないときは、時効によって消滅する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="813:814">
                  <ArticleTitle>第八百十三条及び第八百十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="7">
                <ChapterTitle>第七章　海上保険</ChapterTitle>
                <Article Num="815">
                  <ArticleCaption>（定義等）</ArticleCaption>
                  <ArticleTitle>第八百十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">この章において「海上保険契約」とは、損害保険契約のうち、保険者（営業として保険の引受けを行うものに限る。以下この章において同じ。）が航海に関する事故によって生ずることのある損害を塡補することを約するものをいう。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">海上保険契約については、この章に別段の定めがある場合を除き、保険法（平成二十年法律第五十六号）第二章第一節から第四節まで及び第六節並びに第五章の規定を適用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="816">
                  <ArticleCaption>（保険者の塡補責任）</ArticleCaption>
                  <ArticleTitle>第八百十六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">保険者は、この章又は海上保険契約に別段の定めがある場合を除き、保険の目的について、保険期間内に発生した航海に関する事故によって生じた一切の損害を塡補する責任を負う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="817">
                  <ArticleTitle>第八百十七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">保険者は、海難の救助又は共同海損の分担のため被保険者が支払うべき金額を塡補する責任を負う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">保険法第十九条の規定は、前項に規定する金額について準用する。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、同条中「てん補損害額」とあるのは、「商法（明治三十二年法律第四十八号）第八百十七条第一項に規定する金額」と読み替えるものとする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="818">
                  <ArticleCaption>（船舶保険の保険価額）</ArticleCaption>
                  <ArticleTitle>第八百十八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶を保険の目的物とする海上保険契約（以下この章において「船舶保険契約」という。）については、保険期間の始期における当該船舶の価額を保険価額とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="819">
                  <ArticleCaption>（貨物保険の保険価額）</ArticleCaption>
                  <ArticleTitle>第八百十九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">貨物を保険の目的物とする海上保険契約（以下この章において「貨物保険契約」という。）については、その船積みがされた地及び時における当該貨物の価額、運送賃並びに保険に関する費用の合計額を保険価額とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="820">
                  <ArticleCaption>（告知義務）</ArticleCaption>
                  <ArticleTitle>第八百二十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">保険契約者又は被保険者になる者は、海上保険契約の締結に際し、海上保険契約により塡補することとされる損害の発生の可能性（以下この章において「危険」という。）に関する重要な事項について、事実の告知をしなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="821">
                  <ArticleCaption>（契約締結時に交付すべき書面の記載事項）</ArticleCaption>
                  <ArticleTitle>第八百二十一条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">保険者が海上保険契約を締結した場合においては、保険法第六条第一項に規定する書面には、同項各号に掲げる事項のほか、次の各号に掲げる場合の区分に応じ、当該各号に定める事項を記載しなければならない。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Column Num="1">
                          <Sentence Num="1" WritingMode="vertical">船舶保険契約を締結した場合</Sentence>
                        </Column>
                        <Column Num="2">
                          <Sentence Num="1" WritingMode="vertical">船舶の名称、国籍、種類、船質、総トン数、建造の年及び航行区域（一の航海について船舶保険契約を締結した場合にあっては、発航港及び到達港（寄航港の定めがあるときは、その港を含む。））並びに船舶所有者の氏名又は名称</Sentence>
                        </Column>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Column Num="1">
                          <Sentence Num="1" WritingMode="vertical">貨物保険契約を締結した場合</Sentence>
                        </Column>
                        <Column Num="2">
                          <Sentence Num="1" WritingMode="vertical">船舶の名称並びに貨物の発送地、船積港、陸揚港及び到達地</Sentence>
                        </Column>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                </Article>
                <Article Num="822">
                  <ArticleCaption>（航海の変更）</ArticleCaption>
                  <ArticleTitle>第八百二十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">保険期間の始期の到来前に航海の変更をしたときは、海上保険契約は、その効力を失う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">保険期間内に航海の変更をしたときは、保険者は、その変更以後に発生した事故によって生じた損害を塡補する責任を負わない。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その変更が保険契約者又は被保険者の責めに帰することができない事由によるものであるときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">到達港を変更し、その実行に着手した場合においては、海上保険契約で定める航路を離れないときであっても、航海の変更をしたものとみなす。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="823">
                  <ArticleCaption>（著しい危険の増加）</ArticleCaption>
                  <ArticleTitle>第八百二十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">次に掲げる場合には、保険者は、その事実が生じた時以後に発生した事故によって生じた損害を塡補する責任を負わない。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、当該事実が当該事故の発生に影響を及ぼさなかったとき、又は保険契約者若しくは被保険者の責めに帰することができない事由によるものであるときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">被保険者が発航又は航海の継続を怠ったとき。</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">被保険者が航路を変更したとき。</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="3">
                      <ItemTitle>三</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">前二号に掲げるもののほか、保険契約者又は被保険者が危険を著しく増加させたとき。</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                </Article>
                <Article Num="824">
                  <ArticleCaption>（船舶の変更）</ArticleCaption>
                  <ArticleTitle>第八百二十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">貨物保険契約で定める船舶を変更したときは、保険者は、その変更以後に発生した事故によって生じた損害を塡補する責任を負わない。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その変更が保険契約者又は被保険者の責めに帰することができない事由によるものであるときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="825">
                  <ArticleCaption>（予定保険）</ArticleCaption>
                  <ArticleTitle>第八百二十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">貨物保険契約において、保険期間、保険金額、保険の目的物、約定保険価額、保険料若しくはその支払の方法、船舶の名称又は貨物の発送地、船積港、陸揚港若しくは到達地（以下この条において「保険期間等」という。）につきその決定の方法を定めたときは、保険法第六条第一項に規定する書面には、保険期間等を記載することを要しない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">保険契約者又は被保険者は、前項に規定する場合において、保険期間等が確定したことを知ったときは、遅滞なく、保険者に対し、その旨の通知を発しなければならない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">保険契約者又は被保険者が故意又は重大な過失により遅滞なく前項の通知をしなかったときは、貨物保険契約は、その効力を失う。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="826">
                  <ArticleCaption>（保険者の免責）</ArticleCaption>
                  <ArticleTitle>第八百二十六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">保険者は、次に掲げる損害を塡補する責任を負わない。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、第四号に掲げる損害にあっては、保険契約者又は被保険者が発航の当時同号に規定する事項について注意を怠らなかったことを証明したときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">保険の目的物の性質若しくは瑕疵又はその通常の損耗によって生じた損害</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">保険契約者又は被保険者の故意又は重大な過失（責任保険契約にあっては、故意）によって生じた損害</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="3">
                      <ItemTitle>三</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">戦争その他の変乱によって生じた損害</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="4">
                      <ItemTitle>四</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">船舶保険契約にあっては、発航の当時第七百三十九条第一項各号（第七百七条及び第七百五十六条第一項において準用する場合を含む。）に掲げる事項を欠いたことにより生じた損害</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="5">
                      <ItemTitle>五</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">貨物保険契約にあっては、貨物の荷造りの不完全によって生じた損害</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                </Article>
                <Article Num="827">
                  <ArticleCaption>（貨物の損傷等の場合の塡補責任）</ArticleCaption>
                  <ArticleTitle>第八百二十七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">保険の目的物である貨物が損傷し、又はその一部が滅失して到達地に到着したときは、保険者は、第一号に掲げる額の第二号に掲げる額に対する割合を保険価額（約定保険価額があるときは、当該約定保険価額）に乗じて得た額を塡補する責任を負う。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">当該貨物に損傷又は一部滅失がなかったとした場合の当該貨物の価額から損傷又は一部滅失後の当該貨物の価額を控除した額</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">当該貨物に損傷又は一部滅失がなかったとした場合の当該貨物の価額</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                </Article>
                <Article Num="828">
                  <ArticleCaption>（不可抗力による貨物の売却の場合の塡補責任）</ArticleCaption>
                  <ArticleTitle>第八百二十八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">航海の途中において不可抗力により保険の目的物である貨物が売却されたときは、保険者は、第一号に掲げる額から第二号に掲げる額を控除した額を塡補する責任を負う。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">保険価額（約定保険価額があるときは、当該約定保険価額）</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">当該貨物の売却によって得た代価から運送賃その他の費用を控除した額</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                </Article>
                <Article Num="829">
                  <ArticleCaption>（告知義務違反による解除）</ArticleCaption>
                  <ArticleTitle>第八百二十九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">保険者は、保険契約者又は被保険者が、危険に関する重要な事項について、故意又は重大な過失により事実の告知をせず、又は不実の告知をしたときは、海上保険契約を解除することができる。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合においては、保険法第二十八条第二項（第一号に係る部分に限る。）及び第四項並びに第三十一条第二項（第一号に係る部分に限る。）の規定を準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="830">
                  <ArticleCaption>（相互保険への準用）</ArticleCaption>
                  <ArticleTitle>第八百三十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">この章の規定は、相互保険について準用する。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その性質がこれを許さないときは、この限りでない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="831:841">
                  <ArticleTitle>第八百三十一条から第八百四十一条まで</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
              <Chapter Num="8">
                <ChapterTitle>第八章　船舶先取特権及び船舶抵当権</ChapterTitle>
                <Article Num="842">
                  <ArticleCaption>（船舶先取特権）</ArticleCaption>
                  <ArticleTitle>第八百四十二条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">次に掲げる債権を有する者は、船舶及びその属具について先取特権を有する。</Sentence>
                    </ParagraphSentence>
                    <Item Num="1">
                      <ItemTitle>一</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">船舶の運航に直接関連して生じた人の生命又は身体の侵害による損害賠償請求権</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="2">
                      <ItemTitle>二</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">救助料に係る債権又は船舶の負担に属する共同海損の分担に基づく債権</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="3">
                      <ItemTitle>三</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">国税徴収法（昭和三十四年法律第百四十七号）若しくは国税徴収の例によって徴収することのできる請求権であって船舶の入港、港湾の利用その他船舶の航海に関して生じたもの又は水先料若しくは引き船料に係る債権</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="4">
                      <ItemTitle>四</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">航海を継続するために必要な費用に係る債権</Sentence>
                      </ItemSentence>
                    </Item>
                    <Item Num="5">
                      <ItemTitle>五</ItemTitle>
                      <ItemSentence>
                        <Sentence Num="1" WritingMode="vertical">雇用契約によって生じた船長その他の船員の債権</Sentence>
                      </ItemSentence>
                    </Item>
                  </Paragraph>
                </Article>
                <Article Num="843">
                  <ArticleCaption>（船舶先取特権の順位）</ArticleCaption>
                  <ArticleTitle>第八百四十三条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">前条各号に掲げる債権に係る先取特権（以下この章において「船舶先取特権」という。）が互いに競合する場合には、その優先権の順位は、同条各号に掲げる順序に従う。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、同条第二号に掲げる債権（救助料に係るものに限る。）に係る船舶先取特権は、その発生の時において既に生じている他の船舶先取特権に優先する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Function="main" Num="1" WritingMode="vertical">同一順位の船舶先取特権を有する者が数人あるときは、これらの者は、その債権額の割合に応じて弁済を受ける。</Sentence>
                      <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、前条第二号から第四号までに掲げる債権にあっては、同一順位の船舶先取特権が同時に生じたものでないときは、後に生じた船舶先取特権が前に生じた船舶先取特権に優先する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="844">
                  <ArticleCaption>（船舶先取特権と他の先取特権との競合）</ArticleCaption>
                  <ArticleTitle>第八百四十四条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶先取特権と他の先取特権とが競合する場合には、船舶先取特権は、他の先取特権に優先する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="845">
                  <ArticleCaption>（船舶先取特権と船舶の譲受人）</ArticleCaption>
                  <ArticleTitle>第八百四十五条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶所有者がその船舶を譲渡したときは、譲受人は、その登記をした後、船舶先取特権を有する者に対し、一定の期間内にその債権の申出をすべき旨を公告しなければならない。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、その期間は、一箇月を下ることができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶先取特権を有する者が前項の期間内に同項の申出をしなかったときは、その船舶先取特権は、消滅する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="846">
                  <ArticleCaption>（船舶先取特権の消滅）</ArticleCaption>
                  <ArticleTitle>第八百四十六条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶先取特権は、その発生後一年を経過したときは、消滅する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="847">
                  <ArticleCaption>（船舶抵当権）</ArticleCaption>
                  <ArticleTitle>第八百四十七条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">登記した船舶は、抵当権の目的とすることができる。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶の抵当権は、その属具に及ぶ。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="3">
                    <ParagraphNum>３</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶の抵当権には、不動産の抵当権に関する規定を準用する。</Sentence>
                      <Sentence Num="2" WritingMode="vertical">この場合において、民法第三百八十四条第一号中「抵当権を実行して競売の申立てをしないとき」とあるのは、「抵当権の実行としての競売の申立て若しくはその提供を承諾しない旨の第三取得者に対する通知をせず、又はその通知をした債権者が抵当権の実行としての競売の申立てをすることができるに至った後一週間以内にこれをしないとき」と読み替えるものとする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="848">
                  <ArticleCaption>（船舶抵当権と船舶先取特権等との競合）</ArticleCaption>
                  <ArticleTitle>第八百四十八条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶の抵当権と船舶先取特権とが競合する場合には、船舶先取特権は、船舶の抵当権に優先する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                  <Paragraph Num="2">
                    <ParagraphNum>２</ParagraphNum>
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">船舶の抵当権と先取特権（船舶先取特権を除く。）とが競合する場合には、船舶の抵当権は、民法第三百三十条第一項に規定する第一順位の先取特権と同順位とする。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="849">
                  <ArticleCaption>（質権設定の禁止）</ArticleCaption>
                  <ArticleTitle>第八百四十九条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">登記した船舶は、質権の目的とすることができない。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
                <Article Num="850">
                  <ArticleCaption>（製造中の船舶への準用）</ArticleCaption>
                  <ArticleTitle>第八百五十条</ArticleTitle>
                  <Paragraph Num="1">
                    <ParagraphNum />
                    <ParagraphSentence>
                      <Sentence Num="1" WritingMode="vertical">この章の規定は、製造中の船舶について準用する。</Sentence>
                    </ParagraphSentence>
                  </Paragraph>
                </Article>
              </Chapter>
            </Part>
          </MainProvision>
          <SupplProvision AmendLawNum="明治四四年五月三日法律第七三号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">本法施行ノ期日ハ勅令ヲ以テ之ヲ定ム</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">本法ノ規定ハ本法施行ノ日ヨリ其施行前ニ生シタル事項ニモ亦之ヲ適用ス</Sentence>
                  <Sentence Num="2" WritingMode="vertical">但従前ノ規定ニ依リテ生シタル効力ヲ妨ケス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和一二年八月一四日法律第七九号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="67">
              <ArticleTitle>第六十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">本法施行ノ期日ハ勅令ヲ以テ之ヲ定ム</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="68">
              <ArticleTitle>第六十八条</ArticleTitle>
              <Paragraph Num="3" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第五百七十五条及第五編第二章第二節ハ之ヲ削除ス</Sentence>
                  <Sentence Num="2" WritingMode="vertical">但シ商法其ノ他ノ法令ノ規定ノ適用上之ニ依ルベキ場合ニ於テハ仍其ノ効力ヲ有ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和一三年四月五日法律第七二号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">本法施行ノ期日ハ勅令ヲ以テ之ヲ定ム</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二二年四月一六日法律第六一号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、日本国憲法施行の日から、これを施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二二年九月一日法律第一〇〇号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、第十章の規定を除いて、公布の日からこれを施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二二年一二月二二日法律第二二三号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="29">
              <ArticleTitle>第二十九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、昭和二十三年一月一日から、これを施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二三年七月一二日法律第一四八号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から、これを施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この附則で、新法とは、この法律による改正後の規定をいい、旧法とは、従前の規定をいう。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">新法施行の際、株金全額の払込の完了していない株式に関しては、新法施行後もなお旧法を適用する。</Sentence>
                  <Sentence Num="2" WritingMode="vertical">新法施行前に行われた設立又は資本増加の際引受のあつた株式で、一時に全額を払込ませないものに関しても、また同様である。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項に定めるものの外、新法施行前に生じた事項については、旧法を適用する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前条第一項に規定する株式については、会社は新法施行の日から二年内に株金全額払込済のものとするため、株金の払込をなさしめ、又は資本を減少する等必要な措置を講じなければならない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項に規定する期間内に、同項に定める措置を講じなかつた場合における措置に関しては、別に法律を以てこれを定める。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">旧法第二百九十七条第一項第二項及び第三百一条第一項第十号の規定は、株金全額の払込の完了していない株式のある会社の社債の発行に関しては、新法施行後も、なおその効力を有する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">新法施行の際、他の法令中に商法の規定を準用する旨定めた規定がある場合においては、その規定は、既に引受のあつた株式又は出資についてのみ新法施行後もなお旧法を準用するものとし、その限りにおいて旧法はなおその効力を有する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二四年五月三一日法律第一三七号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、昭和二十四年六月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="9">
              <ParagraphNum>９</ParagraphNum>
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">登記所がすべき公告は、当分の間官報でするものとする。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">但し、登記事項の公告は、当分の間しない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="10">
              <ParagraphNum>１０</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">商法第十二条の規定の適用については、登記の時に登記及び公告があつたものとみなす。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二五年五月一〇日法律第一六七号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、昭和二十六年七月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="4">
              <ParagraphNum>４</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律施行前に成立した株式会社が既に発行した株式及びこの法律施行後発行する額面株式については、第二百二条第二項の改正規定にかかわらず、改正前の同条同項の規定を適用する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二五年一二月二〇日法律第二九〇号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、新法の施行の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二六年六月八日法律第二〇九号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、昭和二十六年七月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二六年六月八日法律第二一三号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、昭和二十六年七月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二七年七月三一日法律第二六八号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、昭和二十七年八月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和三〇年六月三〇日法律第二八号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、昭和三十年七月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="2">
              <ParagraphNum>２</ParagraphNum>
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">この法律による改正後の商法は、特別の定がある場合を除いては、この法律の施行前に生じた事項にも適用する。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、従前の商法によつて生じた効力を妨げない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="3">
              <ParagraphNum>３</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律の施行前に定めた新株の引受権に関する定款の規定の不備は、会社の設立、新株の発行、合併、組織変更又は定款の他の規定の効力を妨げない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="4">
              <ParagraphNum>４</ParagraphNum>
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">この法律の施行前に定めた株主の新株の引受権に関する定款の規定は、この法律の施行の際における会社が発行する株式の総数のうち未発行の部分について、その効力を有する。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その定款の規定を廃止し、又は変更することを妨げない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="5">
              <ParagraphNum>５</ParagraphNum>
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">この法律の施行前に定めた株主以外の者の新株の引受権に関する定款の規定は、この法律の施行後はその効力を有しない。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、この法律の施行前に申込があつた新株の引受権については、従前の例による。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和三三年四月一五日法律第六二号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、昭和三十四年一月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和三三年四月三〇日法律第一〇六号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、昭和三十三年七月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和三七年四月二〇日法律第八二号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、昭和三十八年四月一日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleCaption>（定義）</ArticleCaption>
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この附則で、「新法」とは、この法律による改正後の商法をいい、「旧法」とは、従前の商法をいう。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleCaption>（原則）</ArticleCaption>
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">新法は、特別の定めがある場合を除いては、この法律の施行前に生じた事項にも適用する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、旧法によつて生じた効力を妨げない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleCaption>（清算結了の登記）</ArticleCaption>
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">新法第百十九条ノ二（新法第百四十七条で準用する場合を含む。）の規定は、この法律の施行前に財産の処分を完了した場合には適用しない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleCaption>（帳簿等の保存）</ArticleCaption>
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に解散の登記をした合名会社又は合資会社については、この法律の施行後も、なお旧法第百四十三条（旧法第百四十七条で準用する場合を含む。）の規定を適用する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleCaption>（所在不明株主等）</ArticleCaption>
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行の際、株主名簿に記載した株主若しくは質権者の住所又は株主若しくは質権者が会社に通知した住所にあてて発した通知及び催告が継続して三年をこえる期間到達していないときは、その期間のうち三年をこえる部分は、新法第二百二十四条ノ二第一項（同条第三項で準用する場合を含む。）の期間に算入しない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="7">
              <ArticleCaption>（新株の効力発生日）</ArticleCaption>
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に新株の発行の決議があつたときは、この法律の施行後も、なお旧法第二百八十条ノ九の規定を適用する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="8">
              <ArticleCaption>（株式会社の計算）</ArticleCaption>
              <ArticleTitle>第八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律の施行の際現に存する株式会社のこの法律の施行後最初に到来する決算期以前の決算期に関する計算については、この法律の施行後も、なお従前の例による。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、新法第二百八十八条ノ二第二項の規定の適用を妨げない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="9">
              <ArticleTitle>第九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">新法第二百八十五条ノ二、第二百八十五条ノ三及び第二百八十五条ノ五から第二百八十五条ノ七までの規定の適用については、この法律の施行の際現に存する株式会社がこの法律の施行後最初に到来する決算期以前に取得し、又は製作した資産は、その決算期において附することができる最高額（その額の範囲内で別に附した価額があるときは、その価額）をもつて、その決算期の翌日に取得し、又は製作したものとみなす。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="10">
              <ArticleTitle>第十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">新法第二百八十六条ノ二、第二百八十六条ノ三又は第二百八十六条ノ五に規定する貸借対照表の資産の部に計上することができる金額で、この法律の施行の際現に存する株式会社がこの法律の施行後最初に到来する決算期以前に支出したものについては、その金額からその決算期以前にこれらの規定が適用されたならば償却すべきであつた額の最少額を控除した金額を、その決算期の次の決算期において、貸借対照表の資産の部に計上することができる。</Sentence>
                  <Sentence Num="2" WritingMode="vertical">この場合においては、これらの規定による償却期間からすでに経過した期間を控除した期間内に、毎決算期に均等額以上の償却をしなければならない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項の場合においては、同項の規定により貸借対照表の資産の部に計上した金額（社債発行のために必要な費用の額を除く。）は、新法第二百九十条第一項の規定の適用については、新法第二百八十六条ノ二又は第二百八十六条ノ三の規定により貸借対照表の資産の部に計上した金額とみなす。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="11">
              <ArticleCaption>（合併の場合の貸借対照表の備置き）</ArticleCaption>
              <ArticleTitle>第十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">新法第四百八条ノ二の規定は、同条第一項に規定する株主総会の会日がこの法律の施行後二週間以内である場合には、適用しない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="12">
              <ArticleCaption>（罰則）</ArticleCaption>
              <ArticleTitle>第十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和三八年七月九日法律第一二六号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、商業登記法の施行の日（昭和三十九年四月一日）から施行する。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、第七条中商法第二百十条第四号、第二百八十条ノ四第二項及び第四百九十八条第一項第九号の改正規定は、公布の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和四一年六月一四日法律第八三号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphCaption>（施行期日）</ParagraphCaption>
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、昭和四十一年七月一日から施行する。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、商法第百八十八条第二項第五号、第二百五条、第二百十三条から第二百二十一条まで、第二百二十三条第一項、第二百二十九条、第二百八十四条ノ二及び第四百九十八条第一項第十六号の改正規定、同法第二百二十六条の次に一条を加える改正規定並びに附則第三項及び第四項の規定は、昭和四十二年四月一日から、同法第三百四十一条ノ六の改正規定、同条を同法第三百四十一条ノ七とし、同法第三百四十一条ノ五の次に一条を加える改正規定並びに次項及び附則第七項の規定は、公布の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="2">
              <ParagraphCaption>（経過措置）</ParagraphCaption>
              <ParagraphNum>２</ParagraphNum>
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">この法律による改正後の商法（以下「新法」という。）の規定は、特別の定めがある場合を除いては、当該改正規定の施行前に生じた事項にも適用する。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、従前の商法（以下「旧法」という。）の規定によつて生じた効力を妨げない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="3">
              <ParagraphNum>３</ParagraphNum>
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">昭和四十二年四月一日前における株式の移転又は株券の取得については、同日以後も、なお旧法第二百五条及び第二百二十九条の規定を適用する。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、同日以後の株券の占有につき新法第二百五条第二項の規定を適用することを妨げない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="4">
              <ParagraphNum>４</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">昭和四十二年四月一日前に発行された株券を同日以後に取得した者が、裏書の連続又は株式の譲渡を証する書面の整否につき調査をしなかつた場合においても、新法第二百二十九条の規定の適用については、その調査をしなかつたことをもつて、悪意又は重大な過失があつたものとすることはできない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="5">
              <ParagraphNum>５</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">新法第二百三十九条第六項及び第二百三十九条ノ二の規定（新法第百八十条第三項及び第四百十三条第三項において準用する場合を含む。）は、この法律の施行の日から起算して二週間内の日を会日とする株主総会又は創立総会における議決権の行使については、適用しない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="6">
              <ParagraphNum>６</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律の施行前に新株の発行の決議があつたときは、その新株の発行に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                <Sentence Num="2" WritingMode="vertical">この法律の施行前にされた旧法第二百八十条ノ二第二項の決議において定めた株式の発行に関しても、同様とする。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="7">
              <ParagraphNum>７</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">新法第三百四十一条ノ六第二項の規定は、同項の一定の日がこの法律の公布の日前であるときは、適用しない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和四一年七月一日法律第一一一号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から起算して六月をこえない範囲内において政令で定める日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和四九年四月二日法律第二一号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、公布の日から起算して六月をこえない範囲内において政令で定める日から施行する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、商法第二百九条第一項、第二百四十条第二項、第二百五十六条ノ三、第二百八十条ノ二第一項、第二百八十条ノ六第三号、第二百八十条ノ七、第二百八十八条ノ二、第二百九十三条ノ二、第二百九十三条ノ三第三項、第二百九十三条ノ四第二項、第三百四十一条ノ二、第三百四十一条ノ七、第三百七十九条第一項及び第四百九十八条ノ二の各改正規定、同法第二百五十六条ノ四を削る改正規定、同法第二百八十条ノ九の次に一条を加える改正規定、同法第三百四十一条ノ二の次に四条を加える改正規定、同法第四百六条ノ二の次に一条を加える改正規定並びに次条、附則第五条及び第十条から第十三条までの規定は、公布の日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleCaption>（経過措置の原則）</ArticleCaption>
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律による改正後の商法の規定は、特別の定めがある場合を除いては、当該改正規定の施行前に生じた事項にも適用する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、改正前の商法の規定によつて生じた効力を妨げない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleCaption>（商業帳簿等に関する経過措置）</ArticleCaption>
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行の際現に商人である者がこの法律の施行後最初に到来する改正後の商法第三十三条の一定の時期（会社にあつては、決算期をいう。以下この条及び次条において同じ。）以前において作成すべき商業帳簿及びその附属明細書並びに当該一定の時期以前においてする計算及び当該一定の時期に関する計算に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleCaption>（流動資産及び固定資産の評価に関する経過措置）</ArticleCaption>
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">改正後の商法第三十四条第一号及び第二号の規定の適用については、この法律の施行の際現に株式会社以外の商人である者がこの法律の施行後最初に到来する改正後の商法第三十三条の一定の時期以前に取得し、又は製作した資産は、当該一定の時期において附することができる最高価額（その額の範囲内で別に附した価額があるときは、その価額）をもつて、当該一定の時期の翌日に取得し、又は製作したものとみなす。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleCaption>（累積投票に関する経過措置）</ArticleCaption>
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">商法第二百五十六条ノ三の改正規定及び同法第二百五十六条ノ四を削る改正規定の施行の際現に取締役の選任について累積投票によらないことを定めた定款には、発行済株式の総数の四分の一以上に当たる株式を有する株主が累積投票によるべきことを求めることができる旨の定めがあるものとみなす。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、発行済株式の総数の四分の一以下の割合以上に当たる株式を有する株主がその請求をすることができる旨の定めがある場合は、この限りでない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleCaption>（会社と取締役又は清算人との間の訴えについての会社代表に関する経過措置）</ArticleCaption>
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行の際現に存する株式会社が取締役若しくは清算人に対し、又は取締役若しくは清算人がその会社に対して提起する訴えについて会社を代表すべき者に関しては、この法律の施行後最初に到来する決算期に関する定時総会の終結前は、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="7">
              <ArticleCaption>（監査役に関する経過措置）</ArticleCaption>
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行の際現に存する株式会社の監査役で、この法律の施行後最初に到来する決算期に関する定時総会の終結前に在任するものに関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項の定時総会の終結の際現に在任する監査役は、同項の定時総会の終結と同時に退任する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="8">
              <ArticleCaption>（定時総会の招集の通知に添附すべき書類に関する経過措置）</ArticleCaption>
              <ArticleTitle>第八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">改正後の商法第二百八十三条第二項の規定は、この法律の施行後最初に到来する決算期以前の決算期に関する定時総会については、適用しない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="9">
              <ArticleCaption>（子会社の株式の評価に関する経過措置）</ArticleCaption>
              <ArticleTitle>第九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行の際現に存する株式会社がこの法律の施行後最初に到来する決算期において附則第三条の規定によりなおその例によるものとされる改正前の商法第二百八十五条ノ六第二項において準用する同法第二百八十五条ノ二第二項の規定により子会社の株式に時価を附した場合においては、改正後の商法第二百八十五条ノ六第一項及び同条第二項において準用する同法第二百八十五条ノ二第一項ただし書の規定の適用については、その附した時価を取得価額とみなす。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="10">
              <ArticleCaption>（株式による配当に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第二百九十三条ノ二の改正規定の施行前に株主総会の招集に関する取締役会の決議があつた場合において、その株主総会の決議をもつて利益の配当の全部又は一部を新たに発行する株式をもつてするときは、その改正規定の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="11">
              <ArticleCaption>（転換社債の発行に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">転換社債に関する改正規定の施行前に転換社債の発行の決議があつたときは、その転換社債の発行に関しては、その改正規定の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="12">
              <ArticleCaption>（資本の減少に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第三百七十九条第一項の改正規定の施行前に資本の減少の決議があつたときは、その資本の減少に関しては、その改正規定の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="13">
              <ArticleCaption>（休眠会社に関する特例）</ArticleCaption>
              <ArticleTitle>第十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">昭和四十九年十月一日において、最後の登記をした後十年を経過している株式会社は、その日に解散したものとみなす。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">改正後の商法第四百六条ノ三第三項の規定は、前項の場合について準用する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3">
                <ParagraphNum>３</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商業登記法（昭和三十八年法律第百二十五号）第九十一条の二の規定は、第一項の規定による解散の登記について準用する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="14">
              <ArticleCaption>（罰則の適用に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前にした行為及びこの法律附則の規定により従前の例によることとされる事項に係るこの法律の施行後にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和五〇年一二月二七日法律第九四号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphCaption>（施行期日等）</ParagraphCaption>
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、海上航行船舶の所有者の責任の制限に関する国際条約が日本国について効力を生ずる日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="2">
              <ParagraphNum>２</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、この法律の施行前に発生した事故により生じた損害に基づく債権については適用せず、この法律の施行前に生じた債権及びこの法律の施行前に発生した事故によりこの法律の施行後に生じた損害に基づく債権については、なお従前の例による。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和五四年三月三〇日法律第五号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphCaption>（施行期日）</ParagraphCaption>
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、民事執行法（昭和五十四年法律第四号）の施行の日（昭和五十五年十月一日）から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="2">
              <ParagraphCaption>（経過措置）</ParagraphCaption>
              <ParagraphNum>２</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律の施行前に申し立てられた民事執行、企業担保権の実行及び破産の事件については、なお従前の例による。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="3">
              <ParagraphNum>３</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">前項の事件に関し執行官が受ける手数料及び支払又は償還を受ける費用の額については、同項の規定にかかわらず、最高裁判所規則の定めるところによる。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和五六年六月九日法律第七四号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、昭和五十七年十月一日から施行する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、第一条中商法目次の改正規定及び同法第二編第四章第五節に一款を加える改正規定は、公布の日から起算して一年を超えない範囲内において政令で定める日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleCaption>（経過措置の原則）</ArticleCaption>
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律による改正後の商法、株式会社の監査等に関する商法の特例に関する法律（以下「商法特例法」という。）及び有限会社法の規定（罰則を除く。）は、特別の定めがある場合を除いては、この法律の施行前に生じた事項にも適用する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、改正前のこれらの法律によつて生じた効力を妨げない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleCaption>（子会社が有する親会社の株式又は持分に関する経過措置）</ArticleCaption>
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行の際改正後の商法第二百十一条ノ二（改正後の有限会社法第二十四条第一項において準用する場合を含む。以下この項において同じ。）に規定する子会社が改正後の商法第二百十一条ノ二に規定する親会社の株式又は持分を有しているときは、その子会社は、相当の時期に、その株式又は持分の処分をしなければならない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">改正後の商法第四百九十八条第一項第十二号及び第二項並びに改正後の有限会社法第八十五条第一項第七号及び第二項の規定は、前項の規定に違反して株式又は持分の処分をしなかつた場合について準用する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleCaption>（株券の記載事項に関する経過措置）</ArticleCaption>
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に発行された株券の記載事項に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="7">
              <ArticleCaption>（株主総会の決議の取消しの訴え等に関する経過措置）</ArticleCaption>
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に株主総会若しくは創立総会又は社員総会の決議があつた場合においては、その決議の取消し、変更又は不存在若しくは無効の確認を請求する訴えに関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="8">
              <ArticleCaption>（取締役等の資格に関する経過措置）</ArticleCaption>
              <ArticleTitle>第八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律の施行の際現に在任する取締役、監査役及び清算人については、改正後の商法第二百五十四条ノ二第一号及び第二号（同法第二百八十条第一項及び第四百三十条第二項並びに有限会社法第三十二条、第三十四条及び第七十五条第二項において準用する場合を含む。以下この項において同じ。）の規定は、この法律の施行後最初に招集される株主総会の終結の時までは、適用しない。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、この法律の施行後に改正後の商法第二百五十四条ノ二第一号又は第二号に該当することとなつたものについては、この限りでない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前にした行為について刑に処せられた者に係る取締役、監査役及び清算人の資格に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="9">
              <ArticleCaption>（取締役がする会社の営業の部類に属する取引に関する経過措置）</ArticleCaption>
              <ArticleTitle>第九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に改正前の商法第二百六十四条第一項の規定による株主総会の認許があつた場合においては、その認許に係る取引に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="10">
              <ArticleCaption>（取締役会社間の取引に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">改正後の商法第二百六十五条第三項の規定は、この法律の施行前にした同条第一項の取引については、適用しない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="11">
              <ArticleCaption>（新株の発行等に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に新株の発行の決議があつた場合においては、その新株の発行に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                  <Sentence Num="2" WritingMode="vertical">この法律の施行前に株式の分割の決議があつた場合のその株式の分割に関しても、同様とする。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="12">
              <ArticleCaption>（決算期に取締役が作成すべき書類等に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に到来した最終の決算期以前の決算期に取締役が作成すべき書類及びその決算期に係る計算に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="13">
              <ArticleCaption>（株主権の行使に関する利益の供与の禁止に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">改正後の商法第二百九十四条ノ二の規定は、この法律の施行前にした行為については、適用しない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="14">
              <ArticleCaption>（転換社債の転換の場合の資本に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に転換社債の発行の決議があつた場合においては、その転換社債の転換により増加すべき資本に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="27">
              <ArticleCaption>（罰則の適用に関する経過措置）</ArticleCaption>
              <ArticleTitle>第二十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前にした行為及びこの法律附則の規定により従前の例によることとされる事項に係るこの法律の施行後にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成元年一二月二二日法律第九一号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から起算して二年を超えない範囲内において政令で定める日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成二年六月二九日法律第六四号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から起算して一年を超えない範囲内において政令で定める日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleCaption>（経過措置の原則）</ArticleCaption>
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律による改正後の商法及び有限会社法の規定（罰則を除く。）は、特別の定めがある場合を除いては、この法律の施行前に生じた事項にも適用する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、改正前のこれらの法律によって生じた効力を妨げない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleCaption>（業務執行停止等の仮処分に関する経過措置）</ArticleCaption>
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に社員の業務若しくは取締役、監査役若しくは清算人の職務の執行を停止し、又は社員の業務代行者若しくは取締役、監査役若しくは清算人の職務代行者を選任する仮処分の申請があった場合においては、その仮処分の事件及び仮処分に関する登記並びにその業務代行者又は職務代行者の権限に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleCaption>（設立に関する経過措置）</ArticleCaption>
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に定款の認証を受けた場合においては、その定款に係る株式会社又は有限会社の設立に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleCaption>（株式会社の資本の額の制限に関する経過措置）</ArticleCaption>
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行の際現に存する株式会社又はこの法律の施行前に定款の認証を受け、この法律の施行後に成立する株式会社で、その資本の額が千万円に満たないものについては、改正後の商法第百六十八条ノ四の規定は、この法律の施行後五年間は、適用しない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項に規定する株式会社は、同項の期間内に限り、株主総会の決議によりその組織を変更して合名会社又は合資会社とすることができる。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3">
                <ParagraphNum>３</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">法務大臣は、第一項の期間が満了したときは、登記された資本の額が千万円に満たない株式会社は次条第一項に規定する登記の申請をしないときは同項の規定により解散したものとみなされることとなる旨を官報で公告しなければならない。</Sentence>
                  <Sentence Num="2" WritingMode="vertical">この場合において、登記所は、その株式会社に対し、その公告があったことの通知を発しなければならない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="4">
                <ParagraphNum>４</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第百条、有限会社法第六十一条第一項及び第六十六条並びに改正後の有限会社法第六十四条第一項ただし書、第二項、第三項及び第五項、第六十四条ノ二並びに第六十四条ノ三の規定は、第二項の規定による組織変更について準用する。</Sentence>
                  <Sentence Num="2" WritingMode="vertical">この場合において、有限会社法第六十六条中「有限会社ニ付テハ第十三条第二項ニ定ムル登記」とあるのは、「合名会社ニ付テハ商法第六十四条第一項ニ定ムル登記、合資会社ニ付テハ同法第百四十九条第一項ニ定ムル登記」と読み替えるものとする。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="5">
                <ParagraphNum>５</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">改正後の商法第二百十条第四号及び商法第二百十一条の規定は、前項において準用する改正後の有限会社法第六十四条ノ二の規定による株式の買取りについて準用する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleCaption>（株式会社が最低資本金に達しない場合の措置）</ArticleCaption>
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前条第三項に規定する株式会社が同項の公告の日から起算して二月を経過する日までに資本の額を千万円以上とする変更の登記又は有限会社、合名会社若しくは合資会社に組織を変更した場合にすべき登記の申請をしないときは、その株式会社は、その日に解散したものとみなす。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項の規定により解散したものとみなされた会社は、そのみなされた日から起算して三年内に限り、商法第三百四十三条に定める決議により会社を継続することができる。</Sentence>
                  <Sentence Num="2" WritingMode="vertical">この場合において、その会社は、資本の額を千万円以上とし、又は組織を変更して有限会社、合名会社若しくは合資会社とするまでの間は、当該資本の額又は組織の変更の目的の範囲内において、権利を有し、義務を負う。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3">
                <ParagraphNum>３</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項の規定による会社の継続は、同項の期間内に、その資本の額を千万円以上とせず、かつ、その組織を変更して有限会社、合名会社又は合資会社としなかったときは、その効力を失う。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="4">
                <ParagraphNum>４</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前条第二項、第四項及び第五項の規定は、第二項の規定により継続した会社が同項の期間内にその組織を変更して合名会社又は合資会社とする場合について準用する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="5">
                <ParagraphNum>５</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第二項の規定による継続の登記の申請と資本の額の変更の登記又は組織を変更した場合にすべき登記の申請とは、同時にしなければならない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="6">
                <ParagraphNum>６</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商業登記法（昭和三十八年法律第百二十五号）第九十一条の二の規定は、第一項の規定による解散の登記について準用する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="7">
              <ArticleCaption>（組織変更の登記の申請書の添付書類等）</ArticleCaption>
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">附則第五条第二項（前条第四項において準用する場合を含む。以下この条において同じ。）の規定により合名会社に組織を変更した場合の合名会社についてする登記の申請書には、次の書類を添付しなければならない。</Sentence>
                </ParagraphSentence>
                <Item Num="1">
                  <ItemTitle>一</ItemTitle>
                  <ItemSentence>
                    <Sentence Num="1" WritingMode="vertical">定款</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="2">
                  <ItemTitle>二</ItemTitle>
                  <ItemSentence>
                    <Sentence Num="1" WritingMode="vertical">商業登記法第六十七条第二号及び第九十三条第一項第五号に掲げる書面</Sentence>
                  </ItemSentence>
                </Item>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">附則第五条第二項の規定により合資会社に組織を変更した場合の合資会社についてする登記の申請書には、前項各号に掲げる書類のほか、商業登記法第七十四条の書面を添付しなければならない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3">
                <ParagraphNum>３</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商業登記法第七十一条及び第七十三条の規定は、前二項に規定する場合について準用する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="8">
              <ArticleCaption>（組織変更に係る罰則）</ArticleCaption>
              <ArticleTitle>第八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">会社の業務を執行する社員若しくはその業務代行者又は株式会社の取締役若しくは商法第二百五十八条第二項、改正前の商法第二百七十条第一項若しくは改正後の商法第百八十八条第三項において準用する商法第六十七条ノ二の取締役の職務代行者が次の各号の一に該当するときは、百万円以下の過料に処する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、その行為について刑を科すべきときは、この限りでない。</Sentence>
                </ParagraphSentence>
                <Item Num="1">
                  <ItemTitle>一</ItemTitle>
                  <ItemSentence>
                    <Sentence Num="1" WritingMode="vertical">附則第五条第四項（附則第六条第四項において準用する場合を含む。以下この条において同じ。）において準用する有限会社法第六十六条の規定に違反して登記をすることを怠ったとき。</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="2">
                  <ItemTitle>二</ItemTitle>
                  <ItemSentence>
                    <Sentence Num="1" WritingMode="vertical">附則第五条第四項において準用する改正後の有限会社法第六十四条第二項又は第六十四条ノ三の規定に違反して公告若しくは通知をすることを怠り、又は不正の公告若しくは通知をしたとき。</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="3">
                  <ItemTitle>三</ItemTitle>
                  <ItemSentence>
                    <Sentence Num="1" WritingMode="vertical">附則第五条第四項において準用する商法第百条の規定に違反して組織変更をしたとき。</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="4">
                  <ItemTitle>四</ItemTitle>
                  <ItemSentence>
                    <Sentence Num="1" WritingMode="vertical">附則第五条第五項（附則第六条第四項において準用する場合を含む。）において準用する商法第二百十一条の規定に違反して株式の処分をすることを怠ったとき。</Sentence>
                  </ItemSentence>
                </Item>
              </Paragraph>
            </Article>
            <Article Num="9">
              <ArticleCaption>（株式等の譲渡承認請求等に関する経過措置）</ArticleCaption>
              <ArticleTitle>第九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前にその譲渡につき取締役会の承認を要する株式又は有限会社の持分の譲渡の承認又は取得に係る買受人指定の請求があった場合においては、その請求に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="10">
              <ArticleCaption>（質権に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に到来した最終の決算期以前の決算期に関する定時総会において改正前の商法第二百九十三条ノ二第一項の規定による株式をもってする配当の決議があった場合又はこの法律の施行前に同法第二百九十三条ノ三第二項若しくは第二百九十三条ノ三ノ二第一項の規定による株式の発行の決議があった場合においては、その決議の前に株式について設定された質権に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="11">
              <ArticleCaption>（株式分割等に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に決議があった株式の分割又は準備金の全部若しくは一部を資本に組み入れた場合若しくは額面株式の発行価額中券面額を超えて資本に組み入れた部分がある場合の株式の発行に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="12">
              <ArticleCaption>（無記名式の株券に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に発行されている無記名式の株券に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="13">
              <ArticleCaption>（議決権のない株式に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">定款をもって議決権がないものとされる株式については、この法律の施行前に到来した最終の決算期以前の決算期に関する定時総会に係る議決権に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="14">
              <ArticleCaption>（株主の新株引受権等に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に株式の譲渡につき取締役会の承認を要する会社において新株、転換社債又は新株引受権付社債の発行の決議があった場合においては、その会社の株主に係る引受権に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="15">
              <ArticleCaption>（新株発行の場合の現物出資に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に新株の発行の決議があった場合においては、その新株に係る現物出資に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="16">
              <ArticleCaption>（利益準備金の積立てに関する経過措置）</ArticleCaption>
              <ArticleTitle>第十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に到来した最終の決算期以前の決算期に株式会社又は有限会社が利益準備金として積み立てるべき金額に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="17">
              <ArticleCaption>（利益の処分に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に到来した最終の決算期以前の決算期に係る株式会社の利益の処分に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="23">
              <ArticleCaption>（組織変更に関する経過措置）</ArticleCaption>
              <ArticleTitle>第二十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に決議があった株式会社又は有限会社の組織変更に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="25">
              <ArticleCaption>（罰則の適用に関する経過措置）</ArticleCaption>
              <ArticleTitle>第二十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前にした行為及びこの法律附則の規定により従前の例によることとされる場合におけるこの法律の施行後にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成五年六月一四日法律第六二号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から起算して六月を超えない範囲内において政令で定める日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleCaption>（経過措置の原則）</ArticleCaption>
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">改正後の商法、株式会社の監査等に関する商法の特例に関する法律及び担保附社債信託法の規定（罰則を除く。）は、特別の定めがある場合を除いては、この法律の施行前に生じた事項にも適用する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、改正前のこれらの法律によって生じた効力を妨げない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleCaption>（代表訴訟に関する経過措置）</ArticleCaption>
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に商法第二百六十七条第二項又は第三項（これらの規定を同法又は他の法律において準用する場合を含む。）の訴えが提起された場合においては、その訴訟の目的の価額の算定に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleCaption>（監査役の任期に関する経過措置）</ArticleCaption>
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行の際現に存する株式会社の監査役でこの法律の施行後最初に到来する決算期に関する定時総会の終結前に在任するものの任期に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleCaption>（旧社債に関する経過措置）</ArticleCaption>
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前に社債（担保付社債を除く。以下この条、次条及び附則第十四条において同じ。）の募集の決議があった場合においては、その社債に関しては、この法律の施行後も、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleCaption>（旧社債の社債権者集会に関する経過措置）</ArticleCaption>
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前条に規定する場合においても、この法律の施行後に招集手続が開始される社債の社債権者集会に関しては、同条の規定にかかわらず、改正後の商法第三百二十一条ノ二、第三百二十四条、第三百二十九条及び第三百三十九条の規定を適用する。</Sentence>
                  <Sentence Num="2" WritingMode="vertical">この場合において、同条第二項及び第四項中「社債管理会社」とあるのは、「社債募集ノ委託ヲ受ケタル会社」とする。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="12">
              <ArticleCaption>（罰則の適用に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前にした行為及びこの法律附則の規定により従前の例によることとされる場合におけるこの法律の施行後にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成六年六月二九日法律第六六号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphCaption>（施行期日）</ParagraphCaption>
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から起算して六月を超えない範囲内において政令で定める日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="2">
              <ParagraphCaption>（経過措置）</ParagraphCaption>
              <ParagraphNum>２</ParagraphNum>
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">改正後の商法及び有限会社法の規定（罰則を除く。）は、次項に定めるものを除き、この法律の施行前に生じた事項にも適用する。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、改正前のこれらの法律によって生じた効力を妨げない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="3">
              <ParagraphNum>３</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">改正後の商法第二百十条第五号、第二百十条ノ三第一項及び第二項並びに第二百十二条ノ二第一項及び第三項（これらの規定を改正後の有限会社法第二十四条第一項において準用する場合を含む。）並びに改正後の商法第二百十条ノ二第一項の規定は、この法律の施行前に株主総会又は社員総会の招集の手続が開始された場合における自己の株式又は持分の取得については、適用しない。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="4">
              <ParagraphCaption>（罰則の適用に関する経過措置）</ParagraphCaption>
              <ParagraphNum>４</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律の施行前にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成九年五月二一日法律第五六号" Extract="true">
