          <SupplProvision AmendLawNum="平成二〇年六月六日法律第五三号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から起算して三月を超えない範囲内において政令で定める日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成二〇年六月六日法律第五七号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、保険法の施行の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成二三年五月二五日法律第五三号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、新非訟事件手続法の施行の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成二六年五月三〇日法律第四二号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から起算して二年を超えない範囲内において政令で定める日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成二六年六月二七日法律第九一号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、会社法の一部を改正する法律の施行の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成二九年六月二日法律第四五号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、民法改正法の施行の日から施行する。</Sentence>
                <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、第百三条の二、第百三条の三、第二百六十七条の二、第二百六十七条の三及び第三百六十二条の規定は、公布の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成三〇年五月二五日法律第二九号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、公布の日から起算して一年を超えない範囲内において政令で定める日から施行する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、附則第五十条及び第五十二条の規定は、公布の日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleCaption>（商法の一部改正に伴う経過措置の原則）</ArticleCaption>
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">第一条の規定による改正後の商法（以下「新商法」という。）の規定は、この附則に特別の定めがある場合を除き、この法律の施行の日（以下「施行日」という。）前に生じた事項にも適用する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、同条の規定による改正前の商法（以下「旧商法」という。）の規定によって生じた効力を妨げない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleCaption>（運送取扱営業に関する経過措置）</ArticleCaption>
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">施行日前に締結された運送取扱契約（以下「旧運送取扱契約」という。）並びに旧運送取扱契約に係る運送品に関する運送取扱人及びその被用者の不法行為による損害賠償の責任については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleCaption>（物品運送に関する経過措置）</ArticleCaption>
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">施行日前に締結された物品運送契約（以下「旧物品運送契約」という。）並びに旧物品運送契約に係る運送品に関する運送人及びその被用者の不法行為による損害賠償の責任については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleCaption>（旅客運送に関する経過措置）</ArticleCaption>
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">施行日前に締結された旅客運送契約（以下この条において「旧旅客運送契約」という。）並びに旧旅客運送契約に係る手荷物（旅客から引渡しを受けていないものにあっては、身の回り品を含む。）に関する運送人及びその被用者の不法行為による損害賠償の責任については、なお従前の例による。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、施行日以後に旧旅客運送契約に基づいて発生した旅客の生命又は身体の侵害に係る運送人の損害賠償の責任については、この限りでない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleCaption>（寄託に関する経過措置）</ArticleCaption>
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">施行日前に締結された寄託契約（以下「旧寄託契約」という。）については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="7">
              <ArticleCaption>（船舶に対する差押え等に関する経過措置）</ArticleCaption>
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">施行日前に申し立てられた船舶の差押え又は仮差押えの執行の申立てに係る事件については、新商法第六百八十九条の規定にかかわらず、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="8">
              <ArticleCaption>（共有に係る船舶についての損益の分配等に関する経過措置）</ArticleCaption>
              <ArticleTitle>第八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">共有に係る船舶であって施行日前に発航をしたものについての旧商法第六百九十七条に規定する損益の分配については、その航海に限り、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項に規定する船舶の利用に関する計算については、新商法第六百九十九条第二項の規定にかかわらず、その航海に限り、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="9">
              <ArticleCaption>（船舶賃貸借に関する経過措置）</ArticleCaption>
              <ArticleTitle>第九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">新商法第七百二条の規定は、施行日前に締結された船舶の賃貸借契約については、適用しない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="10">
              <ArticleCaption>（定期傭船に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">新商法第七百四条から第七百七条までの規定は、施行日前に締結された定期傭船契約については、適用しない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="11">
              <ArticleCaption>（船長に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">船長の施行日前の行為に基づく旧商法第七百五条に規定する損害賠償の責任については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">施行日前に発航をした船舶（以下「既発航船舶」という。）に係る船長による代理については、その航海に限り、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3">
                <ParagraphNum>３</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">既発航船舶に係る旧商法第七百二十条第二項に規定する航海に関する計算については、その航海に限り、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="12">
              <ArticleCaption>（船舶の衝突に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">施行日前に生じた船舶と他の船舶との衝突に係る事故については、新商法第七百八十八条及び第七百八十九条の規定にかかわらず、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">新商法第七百九十条及び第七百九十一条の規定は、施行日前に生じた事故については、適用しない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="13">
              <ArticleCaption>（海難救助に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">既発航船舶又は既発航船舶内にある積荷その他の物が海難に遭遇した場合におけるその救助については、その航海に限り、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">新商法第八百七条の規定は、施行日前に発航をした非航海船については、その航行を終了するまでの間は、適用しない。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="14">
              <ArticleCaption>（共同海損に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">既発航船舶に係る共同海損については、その航海に限り、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">既発航船舶に係る旧商法第七百九十九条に規定する費用については、その航海に限り、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="15">
              <ArticleCaption>（海上保険に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">施行日前に締結された海上保険契約については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="16">
              <ArticleCaption>（船舶先取特権に関する経過措置）</ArticleCaption>
              <ArticleTitle>第十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">施行日前に船舶（製造中の船舶を含む。）、その属具及び受領していない運送賃に関し国税徴収法（昭和三十四年法律第百四十七号）第二条第十二号に規定する強制換価手続、再生手続、更生手続又は特別清算手続が開始された場合における旧商法第八百四十二条の先取特権又は第二条の規定による改正前の国際海上物品運送法第十九条第一項の先取特権の効力及び順位については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="51">
              <ArticleCaption>（罰則に関する経過措置）</ArticleCaption>
              <ArticleTitle>第五十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">施行日前にした行為及びこの附則の規定によりなお従前の例によることとされる場合における施行日以後にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="52">
              <ArticleCaption>（政令への委任）</ArticleCaption>
              <ArticleTitle>第五十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この附則に規定するもののほか、この法律の施行に関し必要な経過措置は、政令で定める。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="令和三年六月一一日法律第六一号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、令和五年四月一日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('132AC0000000049','明治三十二年法律第四十九号','商法施行法','1899-03-09',NULL,'2026-02-25 02:15:15.350693','132AC0000000049_20190401_430AC0000000029','<LawFullText>
      <Law Lang="ja" Era="Meiji" Year="32" Num="049" PromulgateMonth="03" PromulgateDay="09" LawType="Act">
        <LawNum>明治三十二年法律第四十九号</LawNum>
        <LawBody>
          <LawTitle Kana="しょうほうしこうほう" Abbrev="" AbbrevKana="">商法施行法</LawTitle>
          <MainProvision>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ生シタル事項ニ付テハ本法ニ別段ノ定アル場合ヲ除ク外旧法ノ規定ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商事ニ関スル特別ノ法令ハ商法施行ノ後ト雖モ仍ホ其効力ヲ存ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">特別ノ法令中旧商法ノ規定ニ依ルヘキモノト定メタル場合ニ付テハ旧商法ハ商法施行ノ後ト雖モ仍ホ其効力ヲ存ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ヨリ商業ヲ営ム未成年者、妻及ヒ後見人ハ商法ノ規定ニ従ヒテ登記ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ会社ノ無限責任社員ト為ルコトヲ許サレタル未成年者又ハ妻ハ商法施行ノ日ヨリ其会社ノ業務ニ関シ之ヲ能力者ト看做ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第七条第二項ノ規定ハ商法施行ノ日ヨリ其施行前ニ定メタル制限ニモ亦之ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="7">
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="8">
              <ArticleTitle>第八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ旧法ノ規定ニ依リテ為シタル登記ハ商法ノ規定ニ従ヒテ為シタルモノト同一ノ効力ヲ有ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="9">
              <ArticleTitle>第九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ登記シタル事項ニ変更ヲ生シ又ハ其事項カ消滅シタル場合ニ於テ商法施行前ニ登記ヲ為ササリシトキハ当事者ハ其施行ノ後遅滞ナク登記ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="10">
              <ArticleTitle>第十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ設立ノ登記ヲ為シタル会社ノ社名ハ商法ノ規定ニ従ヒテ登記シタル商号ト同一ノ効力ヲ有ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="11">
              <ArticleTitle>第十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ設立シタル合名会社ニシテ其社名中ニ合名会社ナル文字ヲ用ヰサルモノハ其施行ノ日ヨリ三个月内ニ商法第十七条ノ規定ニ従ヒテ其社名ヲ改メ且其登記ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">会社ノ業務ヲ執行スル社員カ前項ノ規定ニ違反シタルトキハ五円以上五十円以下ノ過料ニ処セラル</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="12">
              <ArticleTitle>第十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第十八条ノ規定ハ商法施行前ヨリ使用スル商号ニハ之ヲ適用セス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="13">
              <ArticleTitle>第十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第十九条ノ規定ハ旧商法施行前ヨリ使用スル商号ニハ之ヲ適用セス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行後ニ商号ノ登記ヲ為シタル者ト雖モ旧商法施行前ヨリ同一又ハ類似ノ商号ヲ使用スル者ニ対シテハ商法第二十条ニ定メタル権利ヲ行フコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="14">
              <ArticleTitle>第十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="15">
              <ArticleTitle>第十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ東京市又ハ大阪市ニ於テ商号ノ登記ヲ為シタル者ハ商法施行ノ日ヨリ六个月内ニ其市ニ存スル他ノ登記所ニ於テ其登記ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項ニ定メタル登記ヲ為ササリシ者ハ其登記ヲ為ササリシ登記所ノ管轄区域内ニ於テハ商法第二十条ニ定メタル権利ヲ行フコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="16">
              <ArticleTitle>第十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="17">
              <ArticleTitle>第十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第二十八条ノ規定ハ商法施行前ニ作リタル商業帳簿ニモ亦之ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="18">
              <ArticleTitle>第十八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">代務人ニハ商法施行ノ日ヨリ支配人ニ関スル規定ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="19">
              <ArticleTitle>第十九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ヨリ支配人又ハ支配役ト称スル者カ商法第三十条ニ定メタル権限ヲ有セサルトキハ主人ハ商法施行ノ日ヨリ三个月内ニ其名称ヲ改ムルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">主人カ前項ノ期間内ニ支配人又ハ支配役ノ名称ヲ改メサリシトキハ其者ハ商法第三十条ニ定メタル権限ヲ有スルモノト看做ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="20">
              <ArticleTitle>第二十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第三十二条第三項ノ規定ハ旧商法第五十条ノ規定ニ反シテ為シタル行為ニ之ヲ準用ス</Sentence>
                  <Sentence Num="2" WritingMode="vertical">但一年ノ期間ハ商法施行ノ日ヨリ之ヲ起算ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">主人カ商法施行前ニ前項ノ行為ヲ知リタルトキハ二週間ノ期間モ亦其施行ノ日ヨリ之ヲ起算ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="21">
              <ArticleTitle>第二十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法中代理商ニ関スル規定ハ商法施行ノ日ヨリ其施行前ニ定メタル代理商ニモ亦之ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="22">
              <ArticleTitle>第二十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法中会社ニ関スル規定ハ本法ニ別段ノ定アル場合ヲ除ク外商法施行ノ日ヨリ其施行前ニ設立シタル会社ニモ亦之ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="23">
              <ArticleTitle>第二十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第四十七条ニ定メタル期間ハ商法施行前ニ本店ノ所在地ニ於テ設立ノ登記ヲ為シタル会社ニ付テハ其施行ノ日ヨリ之ヲ起算ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="24">
              <ArticleTitle>第二十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ設立シタル合名会社ニシテ未タ設立ノ登記ヲ為ササルモノハ商法施行ノ日ヨリ一个月内ニ商法ノ規定ニ従ヒテ定款ヲ作リ且商法第五十一条第一項ニ定メタル登記ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="25">
              <ArticleTitle>第二十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ本店ノ所在地ニ於テ設立ノ登記ヲ為シタル合名会社ハ商法施行ノ日ヨリ一个月内ニ本店ノ所在地ニ於テハ支店、支店ノ所在地ニ於テハ本店並ニ他ノ支店及ヒ社員ノ出資ノ種類並ニ財産ヲ目的トスル出資ノ価格ヲ登記スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="26">
              <ArticleTitle>第二十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第五十一条第二項、第三項及ヒ第五十二条ノ規定ハ合名会社カ設立ノ登記ヲ為シタル後商法施行前ニ支店ヲ設ケ又ハ其本店若クハ支店ヲ移転シタル場合ニ之ヲ準用ス</Sentence>
                  <Sentence Num="2" WritingMode="vertical">但登記期間ハ商法施行ノ日ヨリ之ヲ起算ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="27">
              <ArticleTitle>第二十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">会社ノ業務ヲ執行スル社員カ前二条ノ規定ニ依リ為スヘキ登記ヲ怠リタルトキハ五円以上五十円以下ノ過料ニ処セラル</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="28">
              <ArticleTitle>第二十八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第六十条第二項及ヒ第三項ノ規定ハ旧商法第百四条ノ規定ニ反シテ為シタル行為ニ之ヲ準用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第二十条ノ規定ハ前項ノ場合ニ之ヲ準用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="29">
              <ArticleTitle>第二十九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第七十一条ノ規定ハ商法施行前ニ設立シタル合名会社ニハ之ヲ適用セス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="30">
              <ArticleTitle>第三十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">合名会社ノ目的タル事業ノ成功カ商法施行前ニ不能ト為リタルトキハ裁判所カ解散ヲ命シタル場合ヲ除ク外其会社ハ商法ノ施行ト同時ニ解散シタルモノト看做ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="31">
              <ArticleTitle>第三十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">合名会社カ商法施行前ニ解散シタル場合ニ於テ未タ清算人ヲ選任セサルトキハ其施行ノ日ヨリ二週間内ニ商法第七十六条ノ規定ニ従ヒテ登記ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="32">
              <ArticleTitle>第三十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">合名会社カ商法施行前ニ解散シタル場合ニ於テ既ニ清算人ヲ選任シタルトキハ其施行ノ日ヨリ二週間内ニ商法第七十六条及ヒ第九十条ノ規定ニ従ヒテ登記ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="33">
              <ArticleTitle>第三十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="34">
              <ArticleTitle>第三十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">合名会社カ商法施行前ニ解散シタル場合ニ於テ未タ清算人ヲ選任セサルトキハ総社員ノ同意ヲ以テ会社財産ノ処分方法ヲ定ムルコトヲ得此場合ニ於テハ商法施行ノ日ヨリ二週間内ニ財産目録及ヒ貸借対照表ヲ作ルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第七十八条第二項、第七十九条及ヒ第八十条ノ規定ハ前項ノ場合ニ之ヲ準用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="35">
              <ArticleTitle>第三十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">合名会社カ商法施行前ニ解散ノ登記ヲ為シタル場合ニ於テハ清算ハ旧商法ノ規定ニ依リテ之ヲ為ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="36">
              <ArticleTitle>第三十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">合名会社ニ於テ商法施行前ニ清算人ノ解任又ハ変更アリタルトキハ其施行ノ日ヨリ二週間内ニ商法第九十七条ノ規定ニ従ヒテ登記ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="37">
              <ArticleTitle>第三十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第百三条ノ規定ハ商法施行前ニ解散シタル合名会社ニモ亦之ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="38">
              <ArticleTitle>第三十八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ設立シタル合資会社ニハ旧商法ノ規定ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
