            <Article Num="78">
              <ArticleTitle>第七十八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第二百四条第一項ノ規定ハ株式会社カ商法施行前ニ債券発行ノ認許ヲ得タル場合ニハ之ヲ適用セス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="79">
              <ArticleTitle>第七十九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">株式会社カ商法施行前ニ債券発行ノ認許ヲ得タル場合ニ於テ一時ニ全額ノ払込ヲ為サシメサルトキハ第一回ノ払込アリタル後二週間内ニ本店及ヒ支店ノ所在地ニ於テ払込ミタル金額及ヒ商法第百七十三条第三号乃至第六号ニ掲ケタル事項ヲ登記スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="80">
              <ArticleTitle>第八十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ社債ノ全額又ハ一部ノ払込アリタルトキハ其施行ノ日ヨリ二週間内ニ本店及ヒ支店ノ所在地ニ於テ払込ミタル金額及ヒ商法第百七十三条第三号乃至第六号ニ掲ケタル事項ヲ登記スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="81">
              <ArticleTitle>第八十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ発行シタル債券ハ商法第二百五条ノ規定ニ違フモ之ヲ改ムルコトヲ要セス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">第五十七条但書ノ規定ハ債券ニ之ヲ準用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="82">
              <ArticleTitle>第八十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第二百九条第二項ノ規定ハ商法施行前ニ仮決議ヲ為シテ未タ其通知ヲ発セサル場合ニモ亦之ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="83">
              <ArticleTitle>第八十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第二百九条第四項ノ規定ハ株式会社カ商法施行前ニ定款変更ノ決議又ハ仮決議ヲ為シタル場合ニハ之ヲ適用セス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="84">
              <ArticleTitle>第八十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">株式会社カ商法施行前ニ資本ノ増加若クハ減少ノ決議又ハ仮決議ヲ為シタル場合ニ於テハ旧商法ノ規定ニ依リテ其増加又ハ減少ヲ為スコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法第百二十八条乃至第百三十条ノ規定ハ前項ノ場合ニ之ヲ準用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="85">
              <ArticleTitle>第八十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ為シタル決議又ハ仮決議ニ依リテ資本ヲ増加シタル場合ニ於テ商法施行前ニ新株ニ付キ払込ミタル株金額ノ登記ヲ為ササリシトキハ其施行ノ日ヨリ商法施行後ニ払込アリタルトキハ其日ヨリ二週間内ニ本店及ヒ支店ノ所在地ニ於テ其登記ヲ為スコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="86">
              <ArticleTitle>第八十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">株式会社カ商法施行前ニ解散シタル場合ニ於テ未タ解散ノ決議ヲ為ササルトキハ取締役ハ商法施行ノ後遅滞ナク株主ニ対シテ解散ノ通知ヲ発スルコトヲ要ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
