              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ旧法中会社ニ関スル罰則ヲ適用スヘキ行為アリタルトキハ商法施行ノ後ト雖モ其罰則ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
