              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">私設鉄道株式会社ニハ明治二十年勅令第十二号私設鉄道条例ノ改正ニ至ルマテ旧商法及ヒ其附属法令中株式会社ニ関スル規定ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
