            </Article>
            <Article Num="118">
              <ArticleTitle>第百十八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ設定シタル質権ノ実行ニ付テハ別段ノ意思表示アリタル場合ヲ除ク外民事執行法（昭和五十四年法律第四号）ノ規定ヲ適用ス</Sentence>
                  <Sentence Num="2" WritingMode="vertical">但取引所ノ相場アル有価証券其他ノ商品ニ在リテハ執行官ハ取引所ニ於テ之ヲ売却スルコトヲ得</Sentence>
