                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">商法施行前ニ進行ヲ始メタル時効ノ残期カ商法施行ノ日ヨリ起算シテ六个月ヨリ短キトキハ時効ハ其残期ヲ経過スルニ因リテ完成ス</Sentence>
