  ');
INSERT INTO laws VALUES('132AC0000000093','明治三十二年法律第九十三号','行旅病人及行旅死亡人取扱法','1899-03-28',NULL,'2026-02-25 02:15:19.640493','132AC0000000093_20240401_505AC0000000063','<LawFullText>
      <Law Era="Meiji" Lang="ja" LawType="Act" Num="093" Year="32" PromulgateMonth="03" PromulgateDay="28">
        <LawNum>明治三十二年法律第九十三号</LawNum>
        <LawBody>
          <LawTitle Kana="こうりょびょうにんおよびこうりょしぼうにんとりあつかいほう" Abbrev="行旅法" AbbrevKana="こ">行旅病人及行旅死亡人取扱法</LawTitle>
          <MainProvision>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">此ノ法律ニ於テ行旅病人ト称スルハ歩行ニ堪ヘサル行旅中ノ病人ニシテ療養ノ途ヲ有セス且救護者ナキ者ヲ謂ヒ行旅死亡人ト称スルハ行旅中死亡シ引取者ナキ者ヲ謂フ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">住所、居所若ハ氏名知レス且引取者ナキ死亡人ハ行旅死亡人ト看做ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前二項ノ外行旅病人及行旅死亡人ニ準スヘキ者ハ政令ヲ以テ之ヲ定ム</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行旅病人ハ其ノ所在地市町村之ヲ救護スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">必要ノ場合ニ於テハ市町村ハ行旅病人ノ同伴者ニ対シテ亦相当ノ救護ヲ為スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行旅病人又ハ其ノ同伴者ヲ救護シタルトキハ市町村ハ速ニ扶養義務者又ハ第五条ニ掲ケタル公共団体ニ通知シ之ヲ引取ラシムルノ手続ヲ為スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">救護ニ要シタル費用ハ被救護者ノ負担トシ被救護者ヨリ弁償ヲ得サルトキハ其ノ扶養義務者ノ負担トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行旅病人若ハ其ノ同伴者ノ引取ヲ為ス者ナキトキ又ハ救護費用ノ弁償ヲ得サル場合ニ於テ其ノ引取並費用ノ弁償ヲ為スヘキ公共団体ニ関シテハ勅令ノ定ムル所ニ依ル</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">扶養義務者ニ対スル被救護者引取ノ請求及救護費用弁償ノ請求ハ扶養義務者中ノ何人ニ対シテモ之ヲ請求スルコトヲ得</Sentence>
                  <Sentence Num="2" WritingMode="vertical">但シ費用ノ弁償ヲ為シタル者ハ民法第八百七十八条ニ依リ扶養ノ義務ヲ履行スヘキ者ニ対シ求償ヲ為スヲ妨ケス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="7">
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行旅死亡人アルトキハ其ノ所在地市町村ハ其ノ状況相貌遺留物件其ノ他本人ノ認識ニ必要ナル事項ヲ記録シタル後其ノ死体ノ埋葬又ハ火葬ヲ為スベシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">墓地若ハ火葬場ノ管理者ハ本条ノ埋葬又ハ火葬ヲ拒ムコトヲ得ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="8">
              <ArticleTitle>第八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">必要ノ場合ニ於テハ市町村ハ行旅死亡人ノ同伴者ニ対シテ亦相当ノ救護ヲ為スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行旅病人ニ関スル規定ハ前項ノ場合ニ準用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="9">
              <ArticleTitle>第九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行旅死亡人ノ住所、居所又ハ氏名知レザルトキハ市町村ハ其ノ状況相貌遺留物件其ノ他本人ノ認識ニ必要ナル事項ニ付テ公署ノ掲示場ニ告示シ官報ニ公告シ及厚生労働省令ノ定ムル所ニ依リ電気通信回線ニ接続シテ行フ自動公衆送信（公衆ニ依リ直接受信セラルルコトヲ目的トシ公衆ノ請求ニ依リ自動的ニ送信ヲ行フコトヲ謂ヒ放送又ハ有線放送ニ該当スルモノヲ除ク）ニ依リ公衆ノ閲覧ニ供スベシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="10">
              <ArticleTitle>第十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行旅死亡人ノ住所若ハ居所及氏名知レタルトキハ市町村ハ速ニ相続人ニ通知シ相続人分明ナラサルトキハ扶養義務者若ハ同居ノ親族ニ通知シ又ハ第十三条ニ掲ケタル公共団体ニ通知スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="11">
              <ArticleTitle>第十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行旅死亡人取扱ノ費用ハ先ツ其ノ遺留ノ金銭若ハ有価証券ヲ以テ之ニ充テ仍足ラサルトキハ相続人ノ負担トシ相続人ヨリ弁償ヲ得サルトキハ死亡人ノ扶養義務者ノ負担トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="12">
              <ArticleTitle>第十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行旅死亡人ノ遺留物件ハ市町村之ヲ保管スヘシ</Sentence>
                  <Sentence Num="2" WritingMode="vertical">但シ其ノ保管ノ物件滅失若ハ毀損ノ虞アルトキ又ハ其ノ保管ニ不相当ノ費用若ハ手数ヲ要スルトキハ之ヲ売却シ又ハ棄却スルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="13">
              <ArticleTitle>第十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">市町村ハ第九条ノ公告後六十日ヲ経過スルモ仍行旅死亡人取扱費用ノ弁償ヲ得サルトキハ行旅死亡人ノ遺留物品ヲ売却シテ其ノ費用ニ充ツルコトヲ得其ノ仍足ラサル場合ニ於テ費用ノ弁償ヲ為スヘキ公共団体ニ関シテハ勅令ノ定ムル所ニ依ル</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">市町村ハ行旅死亡人取扱費用ニ付遺留物件ノ上ニ他ノ債権者ノ先取特権ニ対シ優先権ヲ有ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="14">
              <ArticleTitle>第十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">市町村ハ行旅死亡人取扱費用ノ弁償ヲ得タルトキハ相続人ニ其ノ保管スル遺留物件ヲ引渡スヘシ相続人ナキトキハ正当ナル請求者ト認ムル者ニ之ヲ引渡スコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="15">
              <ArticleTitle>第十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">行旅病人行旅死亡人及其ノ同伴者ノ救護若ハ取扱ニ関スル費用ハ所在地市町村費ヲ以テ一時之ヲ繰替フヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項費用ノ弁償金徴収ニ付テハ市町村税滞納処分ノ例ニ依ル</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3" OldNum="true" OldStyle="false">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項ノ徴収金ノ先取特権ハ国税及地方税ニ次グモノトス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="16">
              <ArticleTitle>第十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="17">
              <ArticleTitle>第十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">外国人タル行旅病人行旅死亡人及其ノ同伴者並其ノ所持物件若ハ遺留物件ノ取扱ニ関シ別段ノ規定ヲ要スルモノハ政令ヲ以テ之ヲ定ム</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="18">
              <ArticleTitle>第十八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">船車内ニ於ケル行旅病人行旅死亡人及其ノ同伴者並其ノ所持物件若ハ遺留物件ノ取扱ニ関シ別段ノ規定ヲ要スルモノハ政令ヲ以テ之ヲ定ム</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="19:20">
              <ArticleTitle>第十九条及第二十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">削除</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="21">
              <ArticleTitle>第二十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">此ノ法律ハ明治三十二年七月一日ヨリ施行ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="22">
              <ArticleTitle>第二十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">明治十五年第四十九号布告行旅死亡人取扱規則ハ此ノ法律施行ノ日ヨリ廃止ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </MainProvision>
          <SupplProvision AmendLawNum="昭和二二年一二月二二日法律第二二三号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="29">
              <ArticleTitle>第二十九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、昭和二十三年一月一日から、これを施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二八年八月一五日法律第二一三号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、昭和二十八年九月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="2">
              <ParagraphNum>２</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律施行前従前の法令の規定によりなされた許可、認可その他の処分又は申請、届出その他の手続は、それぞれ改正後の相当規定に基いてなされた処分又は手続とみなす。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和三四年四月二〇日法律第一四八号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphCaption>（施行期日）</ParagraphCaption>
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、国税徴収法（昭和三十四年法律第百四十七号）の施行の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="7">
              <ParagraphCaption>（公課の先取特権の順位の改正に関する経過措置）</ParagraphCaption>
              <ParagraphNum>７</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">第二章の規定による改正後の各法令（徴収金の先取特権の順位に係る部分に限る。）の規定は、この法律の施行後に国税徴収法第二条第十二号に規定する強制換価手続による配当手続が開始される場合について適用し、この法律の施行前に当該配当手続が開始されている場合における当該法令の規定に規定する徴収金の先取特権の順位については、なお従前の例による。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和四二年八月一日法律第一二〇号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphCaption>（施行期日）</ParagraphCaption>
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和六一年一二月二六日法律第一〇九号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、公布の日から施行する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、次の各号に掲げる規定は、それぞれ当該各号に定める日から施行する。</Sentence>
                </ParagraphSentence>
                <Item Num="1:4">
                  <ItemTitle>一から四まで</ItemTitle>
                  <ItemSentence>
                    <Sentence Num="1" WritingMode="vertical">略</Sentence>
                  </ItemSentence>
                </Item>
                <Item Num="5">
                  <ItemTitle>五</ItemTitle>
                  <ItemSentence>
                    <Column Num="1">
                      <Sentence Num="1" WritingMode="vertical">第十四条の規定、第十五条の規定（身体障害者福祉法第十九条第四項及び第十九条の二の改正規定を除く。附則第七条第二項において同じ。）、第十六条の規定、第十七条の規定（児童福祉法第二十条第四項の改正規定を除く。附則第七条第二項において同じ。）、第十八条、第十九条、第二十六条及び第三十九条の規定並びに附則第七条第二項及び第十一条から第十三条までの規定</Sentence>
                    </Column>
                    <Column Num="2">
                      <Sentence Num="1" WritingMode="vertical">公布の日から起算して六月を超えない範囲内において政令で定める日</Sentence>
                    </Column>
                  </ItemSentence>
                </Item>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleCaption>（その他の処分、申請等に係る経過措置）</ArticleCaption>
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律（附則第一条各号に掲げる規定については、当該各規定。以下この条及び附則第八条において同じ。）の施行前に改正前のそれぞれの法律の規定によりされた許可等の処分その他の行為（以下この条において「処分等の行為」という。）又はこの法律の施行の際現に改正前のそれぞれの法律の規定によりされている許可等の申請その他の行為（以下この条において「申請等の行為」という。）でこの法律の施行の日においてこれらの行為に係る行政事務を行うべき者が異なることとなるものは、附則第二条から前条までの規定又は改正後のそれぞれの法律（これに基づく命令を含む。）の経過措置に関する規定に定めるものを除き、この法律の施行の日以後における改正後のそれぞれの法律の適用については、改正後のそれぞれの法律の相当規定によりされた処分等の行為又は申請等の行為とみなす。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="令和五年六月一六日法律第六三号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、公布の日から起算して一年を超えない範囲内において政令で定める日から施行する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、次の各号に掲げる規定は、当該各号に定める日から施行する。</Sentence>
                </ParagraphSentence>
                <Item Num="1">
                  <ItemTitle>一</ItemTitle>
                  <ItemSentence>
                    <Column Num="1">
                      <Sentence Num="1" WritingMode="vertical">第一条及び第二条の規定並びに附則第七条、第十九条及び第二十条の規定</Sentence>
                    </Column>
                    <Column Num="2">
                      <Sentence Num="1" WritingMode="vertical">公布の日</Sentence>
                    </Column>
                  </ItemSentence>
                </Item>
              </Paragraph>
            </Article>
            <Article Num="7">
              <ArticleCaption>（政令への委任）</ArticleCaption>
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この附則に定めるもののほか、この法律の施行に関し必要な経過措置（罰則に関する経過措置を含む。）は、政令で定める。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('132AC0000000095','明治三十二年法律第九十五号','水難救護法','1899-03-29',NULL,'2026-02-25 02:15:22.340445','132AC0000000095_20250601_504AC0000000068','<LawFullText>
      <Law Era="Meiji" Lang="ja" LawType="Act" Num="095" Year="32" PromulgateMonth="03" PromulgateDay="29">
        <LawNum>明治三十二年法律第九十五号</LawNum>
        <LawBody>
          <LawTitle Kana="すいなんきゅうごほう" Abbrev="" AbbrevKana="">水難救護法</LawTitle>
          <MainProvision>
            <Chapter Num="1">
              <ChapterTitle>第一章　遭難船舶</ChapterTitle>
              <Article Num="1">
                <ArticleTitle>第一条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">遭難船舶救護ノ事務ハ最初ニ事件ヲ認知シタル市町村長之ヲ行フ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="2">
                <ArticleTitle>第二条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">遭難船舶アルコトヲ発見シタル者ハ遅滞ナク最近地ノ市町村長又ハ警察官吏ニ報告スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">警察官吏ニ於テ報告ニ接シタルトキハ市町村長ニ通知スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="3">
                <ArticleTitle>第三条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">遭難船舶アルコトヲ認知シタルトキハ市町村長ハ直ニ現場ニ臨ミ救護ニ必要ナル処分ヲ為スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="4">
                <ArticleTitle>第四条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">警察官吏ハ救護ノ事務ニ関シ市町村長ヲ助ケ市町村長現場ニ在ラサルトキハ之ニ代リ其ノ職務ヲ執行スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="5">
                <ArticleTitle>第五条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">救護ハ船長ノ意ニ反シテ之ヲ為スコトヲ得ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ規定ハ市町村長ニ於テ船長ノ人命ヲ保護スル手段ヲ不充分ナリト認メ又ハ船長ニ悪意アリト認メタル場合ニハ之ヲ適用セス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="6">
                <ArticleTitle>第六条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ救護ノ為人ヲ招集シ船舶車馬其ノ他ノ物件ヲ徴用シ又ハ他人ノ所有地ヲ使用スルコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ規定ニ依リ招集セラレタル者ハ市町村長ノ指揮ニ従ヒ救護ニ従事スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="7">
                <ArticleTitle>第七条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ救護ニ際シ必要ナラスト認ムル者、妨害ヲ為シタル者又ハ不正ノ行為ヲ為シタル者ヲ退去セシムルコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ救護ニ際シ暴行ヲ為シタル者ノ身体ヲ拘束スルコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="3" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長前項ノ処分ヲ為スニ当リ助力ヲ命セラレタル者ハ之ヲ拒ムコトヲ得ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="8">
                <ArticleTitle>第八条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ救護ニ際シ遭難物件ヲ隠匿シタル者アリト認ムルトキハ其ノ物件ヲ捜索シ又ハ之ヲ差押フルコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="9">
                <ArticleTitle>第九条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ遭難船舶其ノ他救上ケタル物件及前条ノ規定ニ依リ差押ヘタル物件ヲ保管スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ物件中ニ郵便物又ハ民間事業者による信書の送達に関する法律（平成十四年法律第九十九号）第二条第三項ニ規定スル信書便物アルトキハ市町村長ハ遅滞ナク最寄ノ日本郵便株式会社ノ事業所（郵便ノ業務ヲ行フモノニ限ル）又ハ同条第六項ニ規定スル一般信書便事業者若ハ同条第九項ニ規定スル特定信書便事業者ノ事業所ニ引渡スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="10">
                <ArticleTitle>第十条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">船長ハ遭難後遅滞ナク船難報告書ヲ作リ市町村長ニ差出スヘシ</Sentence>
                    <Sentence Num="2" WritingMode="vertical">但シ船舶国籍証書ノ交付ヲ申請スルコトヲ要セサル船舶又ハ湖川港湾ノミヲ限リ航行スル船舶ノ遭難ニ付テハ此ノ限ニアラス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ報告書ノ事実ヲ審査シ相当ト認ムルトキハ船長ノ請求ニ依リ認証ヲ与フヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="3" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ報告書ノ事実ヲ審査スル為船内書類ノ提出ヲ命シ又ハ船員、旅客其ノ他船中ニ在リタル者ヲ呼出シ訊問ヲ為スコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="11">
                <ArticleTitle>第十一条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ救上ケタル物件左ニ掲クル事項ノ一ニ該当スト認メタルトキハ之ヲ公売シ其ノ代金ヲ保管スヘシ</Sentence>
                  </ParagraphSentence>
                  <Item Num="1">
                    <ItemTitle>一</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">物件久ニ耐ヘ難キコト又ハ著シク其ノ価格ヲ減スル虞アルコト</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="2">
                    <ItemTitle>二</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">爆発物、容易ニ燃焼スヘキ物又ハ其ノ他ノ物件ニシテ保管上危険ノ虞アルコト</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="3">
                    <ItemTitle>三</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">保管ノ費用其ノ物件ノ価格ニ超過シ又ハ其ノ価格ニ比シ不相当ナルコト</Sentence>
                    </ItemSentence>
                  </Item>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ規定ニ依リ公売ヲ為サントスル場合ニ於テ船長其ノ地ニ在ルトキハ市町村長ハ期間ヲ定メ其ノ期間内ニ市町村長ノ相当ト認ムル担保ヲ供シテ物件ノ引渡ヲ請求セサルトキハ公売ニ付スヘキ旨ヲ船長ニ告知スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="3" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">遭難船舶ノ所在地船籍港ナルトキハ前項ノ告知ハ船舶所有者ニ之ヲ為スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="4" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">船長又ハ船舶所有者ニ於テ第二項ノ規定ニ依リ物件ノ引渡ヲ請求シタルトキハ公売ヲ為スコトヲ得ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="12">
                <ArticleTitle>第十二条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">救護ニ関係シタル者ハ市町村長ヨリ救護費用ノ支給ヲ受クルコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ規定ハ左ニ掲クル者ニハ之ヲ適用セス</Sentence>
                  </ParagraphSentence>
                  <Item Num="1">
                    <ItemTitle>一</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">救護セラレタル船舶ノ所有者又ハ其ノ船舶ノ船員</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="2">
                    <ItemTitle>二</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">故意、懈怠又ハ過失ニ因リ遭難ヲ惹起シタル者</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="3">
                    <ItemTitle>三</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">第五条ノ規定ニ違反シテ救護シタル者</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="4">
                    <ItemTitle>四</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">救護ニ際シ妨害ヲ為シ又ハ不正ノ行為ヲ為シタル者</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="5">
                    <ItemTitle>五</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">遭難物件ヲ持去リ又ハ其ノ引渡ヲ拒ミタル者</Sentence>
                    </ItemSentence>
                  </Item>
                </Paragraph>
              </Article>
              <Article Num="13">
                <ArticleTitle>第十三条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">左ニ掲クルモノヲ以テ救護費用トス</Sentence>
                  </ParagraphSentence>
                  <Item Num="1">
                    <ItemTitle>一</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">救護ニ関係シタル者ノ労務ノ報酬</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="2">
                    <ItemTitle>二</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">第六条ノ規定ニ依ル土地ノ使用又ハ物件ノ徴用ニ対スル補償</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="3">
                    <ItemTitle>三</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">救上ケタル物件ノ運搬、保管又ハ公売ニ要シタル費用</Sentence>
                    </ItemSentence>
                  </Item>
                </Paragraph>
              </Article>
              <Article Num="14">
                <ArticleTitle>第十四条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">救護費用ノ支給ヲ受ケントスル者ハ市町村長ノ指定スル期間内ニ其ノ金額ヲ申立ツヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ手続ヲ為ササル者ハ救護費用ノ支給ヲ受クルコトヲ得ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="15">
                <ArticleTitle>第十五条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">救護費用ノ金額ハ命令ノ規定ニ依リ市町村長之ヲ定ム</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ救護費用ノ金額ヲ船長ニ告知シ期間ヲ定メテ之ヲ納付セシムヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="3" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">遭難船舶ノ所在地船籍港ナルトキ又ハ船長在ラサルトキハ前項ノ告知ハ船舶所有者ニ之ヲ為スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="16">
                <ArticleTitle>第十六条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">船長又ハ船舶所有者ハ救護費用ヲ納付シテ市町村長ノ保管ニ係ル金銭其ノ他ノ物件ノ引渡ヲ受クヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">船長又ハ船舶所有者ニ於テ市町村長ノ相当ト認ムル担保ヲ供スルトキハ前項ノ金銭其ノ他ノ物件ノ全部若ハ一部ノ引渡ヲ受クルコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="3" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">左ニ掲クル物件ハ前二項ノ規定ニ拘ラス其ノ引渡ヲ受クルコトヲ得</Sentence>
                  </ParagraphSentence>
                  <Item Num="1">
                    <ItemTitle>一</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">船員ノ所持品</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="2">
                    <ItemTitle>二</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">船員及旅客ノ食料</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="3">
                    <ItemTitle>三</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">運送賃ヲ支払フコトナクシテ船中ニ携帯スル旅客ノ手荷物</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="4">
                    <ItemTitle>四</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">第十七条第二項ニ掲クル物件</Sentence>
                    </ItemSentence>
                  </Item>
                </Paragraph>
                <Paragraph Num="4" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ノ保管スル船舶又ハ積荷ヲ売却シ抵当ト為シ又ハ質入セントスルトキハ市町村長ノ認可ヲ受クヘシ此ノ場合ニ於テ市町村長必要アリト認ムルトキハ之ニ立会フヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="5" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ処分ニ因リ取得シタル金銭其ノ他ノ物件ハ市町村長之ヲ保管スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="6" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ニ於テ第十一条又ハ前項ノ規定ニ依リ金銭ヲ保管スル場合ニ其ノ金銭救護費用ノ金額ニ達シタルトキハ直ニ其ノ金銭ヲ以テ救護費用ヲ支弁シ其ノ残額ハ保管ニ係ル他ノ物件ト共ニ船長又ハ船舶所有者ニ引渡スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="17">
                <ArticleTitle>第十七条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">船長又ハ船舶所有者ニ於テ市町村長ノ定メタル期間内ニ救護費用ヲ納付セサルトキハ市町村長ハ保管ノ物件又ハ担保トシテ差出シタル物件ヲ公売シ其ノ代金ヲ保管スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ規定ハ市町村長ニ於テ公売ヲ為スモ其ノ代金ヲ以テ公売ノ費用ヲ償フニ足ラスト認メタル物件ニハ之ヲ適用セス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="18">
                <ArticleTitle>第十八条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ納付ヲ受ケタル金額又ハ其ノ保管ニ係ル金銭ヲ以テ救護費用ヲ支弁スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="19">
                <ArticleTitle>第十九条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">船長又ハ船舶所有者救護費用ヲ納付セサル場合ニ於テ第十七条ニ定ムル手続ヲ為シタル後市町村長ノ保管ニ係ル金額ヲ以テ救護費用ヲ支弁スルニ残余アルトキハ船長又ハ船舶所有者ニ之ヲ還付ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="20">
                <ArticleTitle>第二十条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">本章ノ規定ハ市町村長ノ招集ヲ待タスシテ救護ニ従事シタル者ニ亦之ヲ適用ス</Sentence>
                    <Sentence Num="2" WritingMode="vertical">但シ市町村長ニ於テ救護ニ干与セサルトキハ此ノ限ニアラス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="21">
                <ArticleTitle>第二十一条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">本章中船長ニ関スル規定ハ船長ニ代リテ其ノ職務ヲ行フ者ニ亦之ヲ適用ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="22">
                <ArticleTitle>第二十二条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">第一条乃至第四条、第五条第一項、第六条乃至第九条、第十二条乃至第十四条、第十五条第一項第二項、第十八条、第二十条及第二十一条ノ規定ハ海軍艦船其ノ他官庁ノ所有スル船舶ニ亦之ヲ準用ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="23">
                <ArticleTitle>第二十三条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">本章ノ規定ハ条約ニ別段ノ定アル場合ニハ之ヲ適用セス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
            </Chapter>
            <Chapter Num="2">
              <ChapterTitle>第二章　漂流物及沈没品</ChapterTitle>
              <Article Num="24">
                <ArticleTitle>第二十四条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">漂流物又ハ沈没品ヲ拾得シタル者ハ遅滞ナク之ヲ市町村長ニ引渡スヘシ</Sentence>
                    <Sentence Num="2" WritingMode="vertical">但シ其ノ物件ノ所有者分明ナル場合ニ於テハ拾得ノ日ヨリ七日以内ニ限リ直ニ其ノ所有者ニ引渡スコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項但書ノ場合ニ於テハ拾得者ハ所有者ヨリ河川ニ漂流スル材木ニ在リテハ其ノ価格ノ十五分ノ一、其ノ他ノ漂流物ニ在リテハ其ノ物件ノ価格ノ十分ノ一、沈没品ニ在リテハ其ノ物件ノ価格ノ三分ノ一ニ相当スル金額以内ノ報酬ヲ受クルコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="25">
                <ArticleTitle>第二十五条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ引渡ヲ受ケタル物件ヲ保管スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ハ前項ノ物件ヲ所有者ニ引渡スヘキコトヲ公告スヘシ</Sentence>
                    <Sentence Num="2" WritingMode="vertical">但シ其ノ所有者知レタルトキハ公告スヘキ事項ヲ直ニ其ノ所有者ニ告知スヘシ此ノ場合ニ於テハ公告ヲ須ヰサルコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="26">
                <ArticleTitle>第二十六条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">第十一条第一項ノ規定ハ漂流物及沈没品ニ之ヲ準用ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="27">
                <ArticleTitle>第二十七条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">市町村長ニ於テ第二十五条ノ公告又ハ告知ヲ為シタル日ヨリ六箇月（沈没品中政令ヲ以テ定ムルモノニ在リテハ一箇年）以内ニ限リ所有者ハ河川ニ漂流スル材木ニ在リテハ其ノ価格ノ十五分ノ一、其ノ他ノ漂流物ニ在リテハ其ノ物件ノ価格ノ十分ノ一、沈没品ニ在リテハ其ノ物件ノ価格ノ三分ノ一ニ相当スル金額並公告、保管、公売又ハ評価ニ要シタル費用ヲ市町村長ニ納付シテ物件ノ引渡ヲ受クルコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ場合ニ於テハ市町村長ハ拾得者ニ河川ニ漂流スル材木ニ在リテハ其ノ価格ノ十五分ノ一、其ノ他ノ漂流物ニ在リテハ其ノ物件ノ価格ノ十分ノ一、沈没品ニ在リテハ其ノ物件ノ価格ノ三分ノ一ニ相当スル金額ヲ支給ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="3" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">物件ノ価格ハ市町村長之ヲ定ム</Sentence>
                    <Sentence Num="2" WritingMode="vertical">但シ鑑定人ヲシテ之ヲ評価セシムルコトヲ得</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="28">
                <ArticleTitle>第二十八条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前条ノ期間内ニ所有者物件ノ引渡ヲ請求セサルトキ又ハ物件ノ引渡ヲ請求セサル意思ヲ表示シタルトキハ市町村長ハ期間ヲ定メ其ノ期間内ニ物件ノ引渡ヲ受クヘキコトヲ拾得者ニ告知スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">拾得者ハ前項ノ期間内ニ公告、保管、公売又ハ評価ニ要シタル費用ヲ市町村長ニ納付シ物件ノ引渡ヲ受クルニ因リテ其ノ所有権ヲ取得ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="3" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">拾得者ニ於テ前項ノ期間内ニ物件ノ引渡ヲ受ケサルトキハ市町村長ハ其ノ物件ヲ公売シ其ノ代金ヨリ前項ノ費用ヲ控除スヘシ此ノ場合ニ於テ残余アルトキハ市町村ノ取得トス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="29">
                <ArticleTitle>第二十九条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">警察官吏ニ於テ航路、錨地又ハ建造物ニ障害ヲ為スト認メタル漂流物又ハ沈没品ヲ取除キタル場合ニ於テハ警察官吏ハ其ノ物件ヲ市町村長ニ引渡スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ニ依リ市町村長ニ於テ引渡ヲ受ケタル物件ニ付テハ第十一条第一項及第二十五条第二項ノ規定ヲ適用ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="30">
                <ArticleTitle>第三十条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前条ニ依リ公告若ハ告知ヲ為シタル日ヨリ六箇月以内ニ所有者物件ノ引渡ヲ請求シタルトキハ市町村長ハ所有者ヲシテ取除、保管及公告ニ要シタル費用ヲ納付セシメ之ニ其ノ物件ヲ引渡スヘシ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
                <Paragraph Num="2" OldNum="true" OldStyle="false">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">前項ノ期間内ニ物件ノ引渡ヲ請求スル者ナキトキハ市町村長ハ其ノ物件ヲ公売シ其ノ代金ヲ以テ取除、保管、公告及公売ニ要シタル費用ヲ支弁スヘシ此ノ場合ニ於テ残余アルトキハ市町村ノ取得トス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
            </Chapter>
            <Chapter Num="3">
              <ChapterTitle>第三章　雑則</ChapterTitle>
              <Article Num="30_2">
                <ArticleTitle>第三十条ノ二</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">行政手続法（平成五年法律第八十八号）第三章ノ規定ハ第六条又ハ第七条第三項ノ処分ニハ之ヲ適用セズ</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="30_3">
                <ArticleTitle>第三十条ノ三</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">本法ニ定ムルモノノ外本法施行ニ関シ必要ナル事項ハ政令ヲ以テ之ヲ定ム</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
            </Chapter>
            <Chapter Num="4">
              <ChapterTitle>第四章　罰則</ChapterTitle>
              <Article Num="31">
                <ArticleTitle>第三十一条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">遭難船舶救護ノ場合ニ於テ左ノ各号ニ該当スル者ハ二万円以下ノ罰金ニ処ス</Sentence>
                  </ParagraphSentence>
                  <Item Num="1">
                    <ItemTitle>一</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">正当ノ理由ナクシテ市町村長ノ招集ニ応セス又ハ物件ノ徴用若ハ土地ノ使用ヲ拒ミタル者</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="2">
                    <ItemTitle>二</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">第六条第二項ノ規定ニ違反シタル者</Sentence>
                    </ItemSentence>
                  </Item>
                  <Item Num="3">
                    <ItemTitle>三</ItemTitle>
                    <ItemSentence>
                      <Sentence Num="1" WritingMode="vertical">第七条第三項ノ規定ニ違反シタル者</Sentence>
                    </ItemSentence>
                  </Item>
                </Paragraph>
              </Article>
              <Article Num="32">
                <ArticleTitle>第三十二条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">遭難船舶救護ノ場合ニ於テ妨害ヲ為シタル者ハ六月以下ノ拘禁刑ニ処ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="33">
                <ArticleTitle>第三十三条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">第十条第一項ノ手続ヲ為スコトヲ怠リタル者ハ二万円以下ノ罰金ニ処ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="34">
                <ArticleTitle>第三十四条</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">詐偽ノ所為ヲ以テ船難報告書ニ認証ヲ受ケタル者ハ十一日以上六月以下ノ拘禁刑ニ処シ又ハ二万円以下ノ罰金ニ処ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="35_1">
                <ArticleTitle>第三十五条ノ一</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">刑法第三百八十五条及第三百八十七条ノ規定ハ沈没品ニ亦之ヲ適用ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
              <Article Num="35_2">
                <ArticleTitle>第三十五条ノ二</ArticleTitle>
                <Paragraph Num="1">
                  <ParagraphNum />
                  <ParagraphSentence>
                    <Sentence Num="1" WritingMode="vertical">漂流ノ物件ニ対シ現存スル記号ヲ塗抹毀損シ若ハ新ニ付記押捺シタル者ハ二万円以下ノ罰金ニ処ス</Sentence>
                  </ParagraphSentence>
                </Paragraph>
              </Article>
            </Chapter>
          </MainProvision>
          <SupplProvision Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="36">
              <ArticleTitle>第三十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">此ノ法律施行ノ期日ハ勅令ヲ以テ之ヲ定ム</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="37">
              <ArticleTitle>第三十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">明治三年二月二十九日／不開港場規則／難船救助／心得方条目、明治四年四月二十二日外国船漂著ノ節取扱方、明治八年第六十六号布告及明治十年第五十五号布告ハ此ノ法律施行ノ日ヨリ廃止ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="39">
              <ArticleTitle>第三十九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">此ノ法律ニ於ケル市町村長ノ事務ハ東京市、京都市及大阪市ニ於テハ区長之ヲ行ヒ市制町村制ヲ施行セサル地ニ於テハ戸長又ハ之ニ準スヘキ者之ヲ行フ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二八年八月一五日法律第二一三号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、昭和二十八年九月一日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和三三年三月一〇日法律第五号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphCaption>（施行期日）</ParagraphCaption>
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律は、公布の日から起算して六月をこえない範囲内において政令で定める日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="2">
              <ParagraphCaption>（経過規定）</ParagraphCaption>
              <ParagraphNum>２</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">この法律による改正後の遺失物法、水難救護法及び民法の規定は、この法律の施行の日前において拾得された遺失物及び漂流物又は沈没品でそれぞれまだ警察署長に差し出されておらず、又は市町村長に引き渡されていないものについて適用し、この法律の施行の際現に警察署長に差し出されている遺失物及び市町村長に引き渡されている漂流物又は沈没品については、なお従前の例による。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="4">
              <ParagraphNum>４</ParagraphNum>
              <ParagraphSentence>
                <Sentence Num="1" WritingMode="vertical">前二項の規定は、遺失物法の規定が準用される物件の経過措置について準用する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成五年一一月一二日法律第八九号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、行政手続法（平成五年法律第八十八号）の施行の日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="15">
              <ArticleCaption>（政令への委任）</ArticleCaption>
              <ArticleTitle>第十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">附則第二条から前条までに定めるもののほか、この法律の施行に関して必要な経過措置は、政令で定める。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成一一年七月一六日法律第八七号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、平成十二年四月一日から施行する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、次の各号に掲げる規定は、当該各号に定める日から施行する。</Sentence>
                </ParagraphSentence>
                <Item Num="1">
                  <ItemTitle>一</ItemTitle>
                  <ItemSentence>
                    <Column Num="1">
                      <Sentence Num="1" WritingMode="vertical">第一条中地方自治法第二百五十条の次に五条、節名並びに二款及び款名を加える改正規定（同法第二百五十条の九第一項に係る部分（両議院の同意を得ることに係る部分に限る。）に限る。）、第四十条中自然公園法附則第九項及び第十項の改正規定（同法附則第十項に係る部分に限る。）、第二百四十四条の規定（農業改良助長法第十四条の三の改正規定に係る部分を除く。）並びに第四百七十二条の規定（市町村の合併の特例に関する法律第六条、第八条及び第十七条の改正規定に係る部分を除く。）並びに附則第七条、第十条、第十二条、第五十九条ただし書、第六十条第四項及び第五項、第七十三条、第七十七条、第百五十七条第四項から第六項まで、第百六十条、第百六十三条、第百六十四条並びに第二百二条の規定</Sentence>
                    </Column>
                    <Column Num="2">
                      <Sentence Num="1" WritingMode="vertical">公布の日</Sentence>
                    </Column>
                  </ItemSentence>
                </Item>
              </Paragraph>
            </Article>
            <Article Num="159">
              <ArticleCaption>（国等の事務）</ArticleCaption>
              <ArticleTitle>第百五十九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律による改正前のそれぞれの法律に規定するもののほか、この法律の施行前において、地方公共団体の機関が法律又はこれに基づく政令により管理し又は執行する国、他の地方公共団体その他公共団体の事務（附則第百六十一条において「国等の事務」という。）は、この法律の施行後は、地方公共団体が法律又はこれに基づく政令により当該地方公共団体の事務として処理するものとする。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="161">
              <ArticleCaption>（不服申立てに関する経過措置）</ArticleCaption>
              <ArticleTitle>第百六十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">施行日前にされた国等の事務に係る処分であって、当該処分をした行政庁（以下この条において「処分庁」という。）に施行日前に行政不服審査法に規定する上級行政庁（以下この条において「上級行政庁」という。）があったものについての同法による不服申立てについては、施行日以後においても、当該処分庁に引き続き上級行政庁があるものとみなして、行政不服審査法の規定を適用する。</Sentence>
                  <Sentence Num="2" WritingMode="vertical">この場合において、当該処分庁の上級行政庁とみなされる行政庁は、施行日前に当該処分庁の上級行政庁であった行政庁とする。</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum>２</ParagraphNum>
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前項の場合において、上級行政庁とみなされる行政庁が地方公共団体の機関であるときは、当該機関が行政不服審査法の規定により処理することとされる事務は、新地方自治法第二条第九項第一号に規定する第一号法定受託事務とする。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="163">
              <ArticleCaption>（罰則に関する経過措置）</ArticleCaption>
              <ArticleTitle>第百六十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="164">
              <ArticleCaption>（その他の経過措置の政令への委任）</ArticleCaption>
              <ArticleTitle>第百六十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この附則に規定するもののほか、この法律の施行に伴い必要な経過措置（罰則に関する経過措置を含む。）は、政令で定める。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="250">
              <ArticleCaption>（検討）</ArticleCaption>
              <ArticleTitle>第二百五十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">新地方自治法第二条第九項第一号に規定する第一号法定受託事務については、できる限り新たに設けることのないようにするとともに、新地方自治法別表第一に掲げるもの及び新地方自治法に基づく政令に示すものについては、地方分権を推進する観点から検討を加え、適宜、適切な見直しを行うものとする。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="251">
              <ArticleTitle>第二百五十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">政府は、地方公共団体が事務及び事業を自主的かつ自立的に執行できるよう、国と地方公共団体との役割分担に応じた地方税財源の充実確保の方途について、経済情勢の推移等を勘案しつつ検討し、その結果に基づいて必要な措置を講ずるものとする。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成一四年七月三一日法律第一〇〇号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、民間事業者による信書の送達に関する法律（平成十四年法律第九十九号）の施行の日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleCaption>（罰則に関する経過措置）</ArticleCaption>
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleCaption>（その他の経過措置の政令への委任）</ArticleCaption>
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">前条に定めるもののほか、この法律の施行に関し必要な経過措置は、政令で定める。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成一七年一〇月二一日法律第一〇二号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律は、郵政民営化法の施行の日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="117">
              <ArticleCaption>（罰則に関する経過措置）</ArticleCaption>
              <ArticleTitle>第百十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律の施行前にした行為、この附則の規定によりなお従前の例によることとされる場合におけるこの法律の施行後にした行為、この法律の施行後附則第九条第一項の規定によりなおその効力を有するものとされる旧郵便為替法第三十八条の八（第二号及び第三号に係る部分に限る。）の規定の失効前にした行為、この法律の施行後附則第十三条第一項の規定によりなおその効力を有するものとされる旧郵便振替法第七十条（第二号及び第三号に係る部分に限る。）の規定の失効前にした行為、この法律の施行後附則第二十七条第一項の規定によりなおその効力を有するものとされる旧郵便振替預り金寄附委託法第八条（第二号に係る部分に限る。）の規定の失効前にした行為、この法律の施行後附則第三十九条第二項の規定によりなおその効力を有するものとされる旧公社法第七十条（第二号に係る部分に限る。）の規定の失効前にした行為、この法律の施行後附則第四十二条第一項の規定によりなおその効力を有するものとされる旧公社法第七十一条及び第七十二条（第十五号に係る部分に限る。）の規定の失効前にした行為並びに附則第二条第二項の規定の適用がある場合における郵政民営化法第百四条に規定する郵便貯金銀行に係る特定日前にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成二四年五月八日法律第三〇号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="1">
              <ArticleCaption>（施行期日）</ArticleCaption>
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Function="main" Num="1" WritingMode="vertical">この法律は、公布の日から起算して一年を超えない範囲内において政令で定める日から施行する。</Sentence>
                  <Sentence Function="proviso" Num="2" WritingMode="vertical">ただし、第一条の規定（郵政民営化法目次中「／第六章　郵便事業株式会社／　第一節　設立等（第七十条―第七十二条）／　第二節　設立に関する郵便事業株式会社法等の特例（第七十三条・第七十四条）／　第三節　移行期間中の業務に関する特例等（第七十五条―第七十八条）／第七章　郵便局株式会社／」を「／第六章　削除／第七章　日本郵便株式会社／」に改める改正規定、同法第十九条第一項第一号及び第二号、第二十六条、第六十一条第一号並びに第六章の改正規定、同法中「第七章　郵便局株式会社」を「第七章　日本郵便株式会社」に改める改正規定、同法第七十九条第三項第二号及び第八十三条第一項の改正規定、同法第九十条から第九十三条までの改正規定、同法第百五条第一項、同項第二号及び第百十条第一項第二号ホの改正規定、同法第百十条の次に一条を加える改正規定、同法第百三十五条第一項、同項第二号及び第百三十八条第二項第四号の改正規定、同法第百三十八条の次に一条を加える改正規定、同法第十一章に一節を加える改正規定（第百七十六条の五に係る部分に限る。）、同法第百八十条第一項第一号及び第二号並びに第百九十六条の改正規定（第十二号を削る部分を除く。）並びに同法附則第二条第二号の改正規定を除く。）、第二条のうち日本郵政株式会社法附則第二条及び第三条の改正規定、第五条（第二号に係る部分に限る。）の規定、次条の規定、附則第四条、第六条、第十条、第十四条及び第十八条の規定、附則第三十八条の規定（郵政民営化法等の施行に伴う関係法律の整備等に関する法律（平成十七年法律第百二号）附則第二条第一項、第四十九条、第五十五条及び第七十九条第二項の改正規定、附則第九十条の前の見出しを削り、同条に見出しを付する改正規定並びに附則第九十一条及び第九十五条の改正規定を除く。）、附則第四十条から第四十四条までの規定、附則第四十五条中総務省設置法（平成十一年法律第九十一号）第三条及び第四条第七十九号の改正規定並びに附則第四十六条及び第四十七条の規定は、公布の日から施行する。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="46">
              <ArticleCaption>（罰則に関する経過措置）</ArticleCaption>
              <ArticleTitle>第四十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence Num="1" WritingMode="vertical">この法律（附則第一条ただし書に規定する規定にあっては、当該規定）の施行前にした行為及びこの附則の規定によりなお従前の例によることとされる場合におけるこの法律の施行後にした行為に対する罰則の適用については、なお従前の例による。</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="47">
              <ArticleCaption>（その他の経過措置の政令への委任）</ArticleCaption>
