    </LawFullText>
  ');
INSERT INTO laws VALUES('132AC0000000101','明治三十二年法律第百一号','明治三十二年法律第百一号（国債ヲ外国ニ於テ募集スル場合ニ関スル法律）','1899-04-20',NULL,'2026-02-25 02:15:25.133645','132AC0000000101_19010404_134AC0000000018','<LawFullText>
      <Law Era="Meiji" Lang="ja" LawType="Act" Num="101" Year="32" PromulgateMonth="04" PromulgateDay="20">
        <LawNum>明治三十二年法律第百一号</LawNum>
        <LawBody>
          <LawTitle Kana="こくさいをがいこくにおいてぼしゅうするばあいにかんするほうりつ" Abbrev="" AbbrevKana="">明治三十二年法律第百一号（国債ヲ外国ニ於テ募集スル場合ニ関スル法律）</LawTitle>
          <MainProvision>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>明治二十五年法律第四号鉄道敷設法明治二十九年法律第五十九号事業公債条例明治二十九年法律第九十三号北海道鉄道敷設法及明治三十二年法律第七十五号台湾事業公債法ニ拠ル公債ヲ外国ニ於テ募集スル場合ニハ外国貨幣ヲ以テ証書ノ金額ヲ記載シ其ノ証書ノ種類、元金ノ据置年限、募集、償還、利子ノ計算及仕払ニ関スル方法其ノ他必要ナル手続ハ命令ヲ以テ之ヲ定ムルコトヲ得但シ償還期限ハ公債募集ノ年ヨリ起算シ五十五年ヲ超ユルコトヲ得ス</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </MainProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('132AC1000000040','明治三十二年法律第四十号','明治三十二年法律第四十号（失火ノ責任ニ関スル法律）','1899-03-08',NULL,'2026-02-25 02:15:27.187620','132AC1000000040_18990308_000000000000000','<LawFullText>
      <Law Era="Meiji" Lang="ja" LawType="Act" Num="040" Year="32" PromulgateMonth="03" PromulgateDay="08">
        <LawNum>明治三十二年法律第四十号</LawNum>
        <LawBody>
          <LawTitle Kana="しっかのせきにんにかんするほうりつ" Abbrev="失火責任法,失火法" AbbrevKana="し,し">明治三十二年法律第四十号（失火ノ責任ニ関スル法律）</LawTitle>
          <MainProvision>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>民法第七百九条ノ規定ハ失火ノ場合ニハ之ヲ適用セス但シ失火者ニ重大ナル過失アリタルトキハ此ノ限ニ在ラス</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </MainProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('132IO0000000001','明治三十二年勅令','日本国及希臘国間修好通商航海条約','1899-10-12',NULL,'2026-02-25 02:15:30.815574','132IO0000000001_18991012_000000000000000','<LawFullText>
      <Law Era="Meiji" Year="32" Num="000" LawType="ImperialOrder" Lang="ja" PromulgateMonth="10" PromulgateDay="12">
        <LawNum>明治三十二年勅令</LawNum>
        <LawBody>
          <LawTitle Kana="にほんこくおよびぎりしゃこくかんしゅうこうつうしょうこうかいじょうやく" Abbrev="" AbbrevKana="">日本国及希臘国間修好通商航海条約</LawTitle>
          <Preamble>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>日本国皇帝陛下及希臘国皇帝陛下ハ両国間並ニ其ノ臣民間ノ友好通商ノ関係ヲ永久堅固ノ基礎ニ置クコトヲ欲シ修好通商航海条約ヲ締結スルコトニ決シ之カ為ニ日本国皇帝陛下ハ特命全権公使従四位勲三等牧野伸顕ヲ希臘国皇帝陛下ハ外務大臣セイウヨール勲章ノ「ナイト」アトス、ローマノスヲ其ノ全権委員ニ任命セリ因テ各全権委員ハ互ニ其ノ委任状ヲ示シ其ノ良好妥当ナルヲ認メ以テ左ノ諸条ヲ協議決定セリ</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </Preamble>
          <MainProvision>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>日本帝国ト希臘王国トノ間並ニ両国臣民ノ間ニ永久堅固ノ和親アルヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>日本国皇帝陛下ハ適宜ニ其ノ外交官ヲ希臘国ニ駐留セシムルコトヲ得希臘国皇帝陛下モ亦適宜ニ其ノ外交官ヲ日本国ニ駐留セシムルコトヲ得ヘシ又両締盟国ノ一方ハ他ノ一方ノ領土及所属地ニ於テ最恵国領事官ノ駐在ヲ許シタル各港、各地ニ総領事、領事、副領事若ハ代弁領事ヲ駐在セシムルノ権利ヲ有スヘシ但シ総領事、領事、副領事若ハ代弁領事ハ其ノ職務ヲ執行スルニ先チ常式ニ従ヒ其ノ任国政府ノ認可ヲ経ヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>両締盟国ノ一方ノ外交官及領事官ハ本条約ノ規定ニ従ヒ他ノ一方ノ領土及所属地ニ於テ最恵国ノ同格ノ外交官及領事官ニ現ニ許与シ或ハ許与セラルヘキ一切ノ権利、特典、特権及免除ヲ享有スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>両締盟国ノ領土及所属地ノ間ニハ相互ニ通商及航海ノ自由アルヘシ両締盟国ノ一方ノ臣民ハ他ノ一方ノ領土及所属地内ノ各地、諸港及諸河ニシテ最恵国臣民或ハ人民ノ到来ヲ許ス場所ヘハ其ノ船舶及貨物ヲ以テ自由ニ且安全ニ到来スルノ権利ヲ有スヘシ又該臣民ハ最恵国臣民或ハ人民ノ在留、居住ヲ許ス各地、諸港ニ在留、居住シ且其ノ地ニ於テ家屋、倉庫ヲ借受ケ、使用シ、総テ正業ニ属スル各種ノ生産物、製造品及商品ノ卸売若ハ小売営業ニ従事スルコトヲ得ヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>諸種ノ財産ヲ得有、使用及譲与スルコトニ関シ両締盟国ノ一方ノ臣民ハ他ノ一方ノ領土及所属地ニ於テ最恵国臣民或ハ人民ト同一ノ取扱ヲ享クヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>両締盟国ハ其ノ一方ノ通商及航海ヲ他ノ一方ニ於テ総テ最恵国ノ基礎ニ置クノ主意ヲ有スルニ因リ旅行、居住、通商及航海ニ関スル一切ノ事項ニ関シ其ノ一方ヨリ別国ノ政府、船舶、臣民或ハ人民ニ現ニ許与シ或ハ将来許与スヘキ一切ノ特典、殊遇若ハ免除ハ他ノ一方ノ政府、船舶、臣民或ハ人民ニモ即時ニ且条件ヲ附セスシテ之ヲ許与スヘキコトヲ両締盟国ニ於テ約定ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>希臘国ノ生産或ハ製造ニ係ル物品ヲ日本国ニ輸入シ又日本国ノ生産或ハ製造ニ係ル物品ヲ希臘国ニ輸入スルニモ総テ別国ノ生産或ハ製造ニ係ル同種ノ物品ニシテ同様ノ目的ヲ以テ輸入スルモノニ対シ課スル処ノ税ニ異ナルカ或ハ之ヨリ多額ノ税ヲ課セラルルコトナカルヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>両締盟国ノ一方ノ領土若ハ所属地ヨリ他ノ一方ノ領土若ハ所属地ヘ輸出スル一切ノ物品ヘハ別国ヘ輸出スル同種物品ニ対シ賦課シ若ハ賦課スヘキ所ニ異ナルカ域ハ之ヨリ多額ノ税金又ハ雑費ヲ賦課スルコトナカルヘシ又両締盟国ノ一方ノ領土若ハ所属地ヘ別国ノ生産或ハ製造ニ係ル同種ノ物品ノ輸入ヲ禁止スルニ非サレハ他ノ一方ノ領土若ハ所属地ノ生産若ハ製造ニ係ル物品ヲ輸入スルコトヲ禁止スルコトナカルヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>又両締盟国ノ一方ノ領土若ハ所属地ニ於テ総テ別国ニ向ヒ同種ノ物品ノ輸出ヲ禁止スルニ非サレハ他ノ一方ノ領土若ハ所属地ヘ物品ヲ輸出スルコトヲモ禁止セサルヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>内地通過、倉入、奨励金、便益及税金払戻ニ関スル一切ノ事項ニ就テハ両締盟国ノ一方ノ臣民ハ他ノ一方ノ領土及所属地ニ在リテ総テ最恵国ノ取扱ヲ享クヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="7">
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>政府、官吏、公吏、一私人、会社若ハ何等施設ノ名義ヲ以テスルカ又ハ其ノ利益ノ為ニ課セラルル所ノ噸税、灯台税、港税、水先案内料、検疫費、難船救助料其ノ他之ト同種ノ税金及雑費ハ其ノ性質又ハ名義ノ如何ニ拘ハラス希臘国ノ船舶ハ日本国諸港ニ於テ又日本国ノ船舶ハ希臘国諸港ニ於テ同様ノ場合ニ同一ノ港ニ於テ最恵国船舶ニ賦課シ若ハ将来賦課スヘキモノニ異ナルカ或ハ之ヨリ多額ノモノヲ課セラルルコトナカルヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="8">
              <ArticleTitle>第八条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>両締盟国ノ沿海貿易ハ本条約ニ於テ規定スルノ限ニ在ラス各其ノ法律、勅令及規則ヲ以テ之ヲ規定スヘキモノトス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="9">
              <ArticleTitle>第九条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>本条約ニ於テハ日本国ノ国法ニ従ヒ日本国船舶ト看做サル可キ一切ノ船舶ハ之ヲ日本国船舶ト見認メ又希臘国ノ国法ニ従ヒ希臘国船舶ト看做サルヘキ一切ノ船舶ハ之ヲ希臘国船舶ト見認ムヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="10">
              <ArticleTitle>第十条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>両締盟国ノ一方ノ軍艦或ハ商船ニシテ暴風又ハ其ノ他ノ危難ニ遭遇シ避難ノ為メ已ムヲ得ス他ノ一方ノ海港ニ進入スルモノハ内国船舶ノ払フヘキ税金ノ外何等ノ税金ヲ払フコトナク其ノ港ニ於テ更ニ艤装ヲ為シ一切ノ需要品ヲ求メ再ヒ航行スルヲ得ヘシ但シ商船ノ船長ニシテ其ノ費用ヲ支弁スル為メ其ノ積荷ノ一部ヲ売却スルヲ要スル場合ニハ該船長ハ其ノ寄港地ノ規則及税目ヲ遵守スヘキモノトス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>両締盟国ノ一方ノ軍艦或ハ商船ニシテ他ノ一方ノ沿岸ニ於テ浅瀬ニ乗上ケ或ハ難破シタルトキハ右難破若ハ乗上ケタル船舶並ニ其ノ器具及其ノ他一切ノ附属品及該船舶ヨリ救上ケタル貨物並ニ商品及右等ノ諸物件ニシテ海中ニ投棄セラレタルモノ又ハ之ヲ売却シタルトキハ其ノ収得金並ニ該遭難船内ニ発見セラレタル一切ノ書類ハ右船舶ノ持主或ハ其ノ代理人ヨリ要求スルトキハ之ニ引渡スヘシ右持主或ハ代理人ノ現場ニ在ラサルトキハ内国法律ニ定メタル期限内ニ当該総領事、領事、副領事或ハ代弁領事ヨリ請求アレハ之ヲ引渡スヘシ而シテ右領事官、持主或ハ代理人ハ内国船舶難破ノ場合ニ於テ払フヘキ所ノ物品保存費並ニ難破救助費及其ノ他ノ費用ノミヲ払フヘキモノトス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>難破船ヨリ救上ケタル貨物及商品ハ消費ノ為ニ通関手続ヲ為スモノニ非サレハ一切ノ関税ヲ免除スヘシ但シ消費ノ為ニ之ヲ売捌ク場合ニハ普通ノ関税ヲ納ムヘキモノトス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="4">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>両締盟国ノ一方ノ臣民ニ属スル船舶ニシテ他ノ一方ノ版図内ニ於テ浅瀬ニ乗上ケ或ハ難破シタルトキ其ノ持主、船長若ハ持主代理人不在ノ場合ニハ当該総領事、領事、副領事若ハ代弁領事ハ其ノ自国臣民ニ必要ノ輔助ヲ与フル為メ職権上ノ助力ヲ為スヲ許サルヘキモノトス此ノ規定ハ持主、船長若ハ他ノ代理人現ニ其ノ場ニ在ルトキト雖モ右様ノ輔助ヲ与フルヲ請求スル場合ニハ亦適用スヘキモノトス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="11">
              <ArticleTitle>第十一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>日本国若ハ其ノ領海ニ到来スル希臘国臣民及船舶ハ其ノ日本国若ハ其ノ領海ニ在ル間ハ日本国法律及日本国ノ裁判管轄権ニ服従スヘシ又之ト均シク希臘国若ハ其ノ領海ニ到来スル日本国臣民及船舶ハ希臘国法律及其ノ裁判管轄権ニ服従スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="12">
              <ArticleTitle>第十二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>両締盟国ノ一方ノ臣民ハ相互ニ他ノ一方ノ領土及所属地ニ於テ其ノ身体及財産ニ対シ完全ナル保護ヲ享受シ、其ノ権利ヲ執行シ及防護セムカ為メ自由ニ裁判所ニ訴出ルコトヲ得ヘク又該裁判所ニ於テ内国臣民ト同様ニ弁護人及代理人ヲ使用スルノ自由ヲ有スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>該臣民ハ良心ニ関シ完全ナル自由及現行法律、勅令及規則ニ従テ公私ノ礼拝ヲ行フノ権利並ニ其ノ宗教上ノ慣習ニ従ヒ埋葬ノ為メ設置保存セラルル所ノ適当便宜ノ地ニ自国人ヲ埋葬スルノ権利ヲ享有スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="13">
              <ArticleTitle>第十三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>兵員宿泊ノ義務、陸海軍ノ強迫兵役、軍事上ノ賦歛若ハ強募公債ニ関シテハ両締盟国ノ一方ノ臣民ハ他ノ一方ノ領土及所属地ニ於テ最恵国ノ臣民或ハ人民ト同様ノ特典、免除及特権ヲ享有スヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="14">
              <ArticleTitle>第十四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>両締盟国ノ一方ノ臣民カ他ノ一方ノ領土及所属地ニ於テ住居若ハ商業ノ為ニ供スル家宅、倉庫、店舗及之ニ属スル総テノ附属構造物ハ侵スヘカラス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>右家宅等ヘハ内国臣民ニ対シ法律、勅令及規則ヲ以テ規定セル条件及方式ニ拠ルノ外一切之ニ侵入捜索シ又ハ帳簿、書類或ハ簿記帳ヲ検査点閲スルコトナカルヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="15">
              <ArticleTitle>第十五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>本条約ハ批准交換後直チニ実施セラルヘシ而シテ其ノ実施ノ日ヨリ十二箇年間効力ヲ有スルモノトス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>両締盟国ノ一方ハ本条約実施ノ日ヨリ十一箇年ヲ経過シタル後ハ何時タリトモ本条約ヲ終了セムト欲スル旨ヲ他ノ一方ヘ通知スルノ権利ヲ有スヘシ而シテ此ノ通知ヲ為シタル後十二箇月ヲ経過シタルトキハ本条約ハ全ク消滅ニ帰スヘキモノトス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="16">
              <ArticleTitle>第十六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>本条約ハ日本文、希臘文及英吉利文各二通ニ調印スヘシ而シテ若シ日本文ト希臘文ト齟齬スル所アリタル場合ニハ英吉利文ニ依テ之ヲ決シ両国政府ニ於テ之ニ遵依スヘキモノトス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="17">
              <ArticleTitle>第十七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>本条約ハ両締盟国ニ於テ之ヲ批准シ其ノ批准ハ可成速ニ羅馬ニ於テ交換スヘシ</Sentence>
                </ParagraphSentence>
                <List>
                  <ListSentence>
                    <Sentence>右証拠トシテ双方ノ全権委員ハ之ニ記名調印スルモノナリ</Sentence>
                  </ListSentence>
                </List>
                <List>
                  <ListSentence>
                    <Sentence>明治三十二年六月一日即千八百九十九年五月二十日雅典ニ於テ六通ヲ作ル</Sentence>
                  </ListSentence>
                </List>
                <List>
                  <ListSentence>
                    <Sentence>牧野伸顕印</Sentence>
                  </ListSentence>
                </List>
                <List>
                  <ListSentence>
                    <Sentence>ア、ローマノス印</Sentence>
                  </ListSentence>
                </List>
              </Paragraph>
            </Article>
          </MainProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('132IO0000000277','明治三十二年勅令第二百七十七号','明治三十二年勅令第二百七十七号（行旅病人死亡人等ノ引取及費用弁償ニ関スル件）','1899-06-17',NULL,'2026-02-25 02:15:33.082455','132IO0000000277_19950401_406CO0000000398','<LawFullText>
      <Law Era="Meiji" Lang="ja" LawType="ImperialOrder" Num="277" Year="32" PromulgateMonth="06" PromulgateDay="17">
        <LawNum>明治三十二年勅令第二百七十七号</LawNum>
        <LawBody>
          <LawTitle Kana="こうりょびょうにんしぼうにんとうのひきとりおよびひようべんしょうにかんするけん" Abbrev="行旅病人死亡人等の引取及費用弁償に関する件" AbbrevKana="こ">明治三十二年勅令第二百七十七号（行旅病人死亡人等ノ引取及費用弁償ニ関スル件）</LawTitle>
          <MainProvision>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>行旅病人及行旅死亡人取扱法第五条及第十三条ノ公共団体ハ行旅病人行旅死亡人若ハ其ノ同伴者ノ救護又ハ取扱ヲ為シタル地ノ道府県トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>前項ノ規定ニ拘ラズ行旅病人行旅死亡人若ハ其ノ同伴者ノ救護又ハ取扱ヲ為シタル地方自治法（昭和二十二年法律第六十七号）第二百五十二条の十九第一項ノ指定都市ハ地方自治法施行令（昭和二十二年政令第十六号）第百七十四条の三十ノ定ムル所ニ依リ行旅病人及行旅死亡人取扱法第五条及第十三条ノ公共団体トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="3" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>第一項ノ規定ニ拘ラズ行旅病人行旅死亡人若ハ其ノ同伴者ノ救護又ハ取扱ヲ為シタル地方自治法第二百五十二条の二十二第一項ノ中核市ハ地方自治法施行令第百七十四条の四十九の六ノ定ムル所ニ依リ行旅病人及行旅死亡人取扱法第五条及第十三条ノ公共団体トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </MainProvision>
          <SupplProvision Extract="false" Type="New">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>削除</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>本令ハ明治三十二年七月一日ヨリ施行ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </SupplProvision>
          <SupplProvision AmendLawNum="明治四〇年一〇月一日勅令第三一九号" Extract="false" Type="Amend">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>本令ハ公布ノ日ヨリ之ヲ施行ス</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二二年五月一日勅令第一八七号" Extract="false" Type="Amend">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>この勅令は、日本国憲法施行の日から、これを施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和三一年八月二一日政令第二六五号" Extract="false" Type="Amend">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum>１</ParagraphNum>
              <ParagraphSentence>
                <Sentence>この政令は、地方自治法の一部を改正する法律（昭和三十一年法律第百四十七号）及び地方自治法の一部を改正する法律の施行に伴う関係法律の整理に関する法律（昭和三十一年法律第百四十八号）の施行の日（昭和三十一年九月一日）から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
            <Paragraph Num="2">
              <ParagraphNum>２</ParagraphNum>
              <ParagraphSentence>
                <Sentence>この政令による改正後のそれぞれの政令及び勅令の規定による都道府県又は都道府県知事その他の都道府県の機関が処理し、又は管理し、及び執行している事務の地方自治法第二百五十二条の十九第一項の指定都市（以下「指定都市」という。）又は指定都市の市長その他の機関への引継に関し必要な経過措置は、それぞれ地方自治法施行令の一部を改正する政令（昭和三十一年政令第二百五十三号）附則第三項から第十項までに定めるところによる。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="平成六年一二月二一日政令第三九八号" Extract="false" Type="Amend">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>この政令は、地方自治法の一部を改正する法律中第二編第十二章の改正規定並びに地方自治法の一部を改正する法律の施行に伴う関係法律の整備に関する法律第一章の規定及び附則第二項の規定の施行の日（平成七年四月一日）から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('132M10000040022','明治三十二年大蔵省令第二十二号','明治三十二年大蔵省令第二十二号（英国倫敦ニ於テ募集スル公債ニ関スル手続方法）','1899-05-31',NULL,'2026-02-25 02:15:35.834051','132M10000040022_19521124_327M50000040135','<LawFullText>
      <Law Era="Meiji" Lang="ja" LawType="MinisterialOrdinance" Num="022" Year="32" PromulgateMonth="05" PromulgateDay="31">
        <LawNum>明治三十二年大蔵省令第二十二号</LawNum>
        <LawBody>
          <LawTitle Kana="えいこくろんどんにおいてぼしゅうするこうさいにかんするてつづきほうほう" Abbrev="" AbbrevKana="">明治三十二年大蔵省令第二十二号（英国倫敦ニ於テ募集スル公債ニ関スル手続方法）</LawTitle>
          <EnactStatement>英国倫敦ニ於テ募集スル公債ニ関シ手続方法等左ノ通相定メ明治三十二年五月三十一日ヨリ施行ス</EnactStatement>
          <MainProvision>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>帝国四分利付英貨公債壱千万磅ノ募集ハ横浜正金銀行、「パース」銀行、香港上海銀行及「チャータード」銀行ノ組織スル「シンヂケート」ヲシテ之ヲ引受ケシム</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>此ノ公債証券ハ無記名利札付トシ英貨ヲ以テ其ノ金額ヲ記載シ五拾磅壱百磅及五百磅ノ三種トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>此ノ公債ノ利率ハ一箇年百分ノ四トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="4">
              <ArticleTitle>第四条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>此ノ公債ノ元金ハ明治三十二年一月一日ヨリ起算シ十箇年間据置キタル後昭和三十八年十二月三十一日迄ニ抽籖ノ方法ニ依リ便宜之ヲ償還スベシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="5">
              <ArticleTitle>第五条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>此ノ公債ノ利子ハ毎年六月十二月ニ於テ仕払フヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="6">
              <ArticleTitle>第六条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>元金ノ払込ハ明治三十二年六月ヨリ十月マテ六回トシ本年分ノ利子ハ十二月ニ於テ半箇年分ヲ仕払フヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="7">
              <ArticleTitle>第七条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>本令ハ昭和二十七年九月二十六日北米合衆国紐育ニ於テ政府ト外貨債所持人団体理事会トノ間ニ締結セラレタル日本国ノ戦前外貨債ノ処理ニ関スル協定ニ基ク申出ニ対シ受諾アリタル本公債ニ付之ヲ適用ス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </MainProvision>
          <SupplProvision Type="New">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>本公債ノ昭和十七年六月迄ニ券面記載ノ仕払期日到来シ昭和二十七年十二月二十一日迄ニ仕払ハレザリシ利子ノ仕払期日ハ第五条ノ規定ニ拘ラズ同年十二月二十二日トシ本公債ノ昭和十七年十二月以後昭和二十七年六月迄ニ券面記載ノ仕払期日到来シ同年十二月二十一日迄ニ仕払ハレザリシ利子ノ仕払期日ハ第五条ノ規定ニ拘ラズ当該仕払期日ヲ十箇年繰延ベタル日トス</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二七年一一月二四日大蔵省令第一三五号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>この省令は、公布の日から施行する。</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
        </LawBody>
      </Law>
    </LawFullText>
  ');
INSERT INTO laws VALUES('132M10001000019','明治三十二年逓信省令第十九号','明治三十二年逓信省令第十九号（商法第七百九条ニ規定スル属具目録ノ書式ノ件）','1899-05-26',NULL,'2026-02-25 02:15:38.097327','132M10001000019_19480422_323M40000800010','<LawFullText>
      <Law Era="Meiji" Lang="ja" LawType="MinisterialOrdinance" Num="019" Year="32" PromulgateMonth="05" PromulgateDay="26">
        <LawNum>明治三十二年逓信省令第十九号</LawNum>
        <LawBody>
          <LawTitle Kana="しょうほうだいななひゃくきゅうじょうにきていするぞくぐもくろくのしょしきのけん" Abbrev="" AbbrevKana="">明治三十二年逓信省令第十九号（商法第七百九条ニ規定スル属具目録ノ書式ノ件）</LawTitle>
          <Preamble>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>商法第七百九条ニ規定スル属具目録ノ書式ノ件左ノ通定ム</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </Preamble>
          <MainProvision>
            <Article Num="1">
              <ArticleTitle>第一条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>属具目録ハ別表書式ニ依リ之ヲ調製スベシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>前項ノ書類ハ書式ニ示ス順序ニ依リ之ヲ編綴シ且各頁ニ頁数ヲ附スヘシ但其紙数ハ適宜トス</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="2">
              <ArticleTitle>第二条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>属具目録ニハ書式ニ定メサル事項ヲ記載スル為メ欄ヲ設クルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
              <Paragraph Num="2" OldNum="true">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>前項ノ場合ニ於テハ船籍港ヲ管轄スル海運局ノ認可ヲ受クヘシ</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
            <Article Num="3">
              <ArticleTitle>第三条</ArticleTitle>
              <Paragraph Num="1">
                <ParagraphNum />
                <ParagraphSentence>
                  <Sentence>属具目録ニハ各事項ニ付英訳ヲ附シ又ハ記載心得等ヲ掲クルコトヲ得</Sentence>
                </ParagraphSentence>
              </Paragraph>
            </Article>
          </MainProvision>
          <SupplProvision AmendLawNum="昭和一四年一〇月九日逓信省令第四四号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>本令ハ昭和十五年一月一日ヨリ之ヲ施行ス</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和一七年一月二〇日逓信省令第八号">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1">
              <ParagraphNum />
