                <Sentence>本令ハ公布ノ日ヨリ之ヲ施行ス</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和一八年一一月一日運輸通信省令第六号" Extract="true">
            <SupplProvisionLabel>附　則</SupplProvisionLabel>
            <Paragraph Num="1" OldNum="true">
              <ParagraphNum />
              <ParagraphSentence>
                <Sentence>本令ハ公布ノ日ヨリ之ヲ施行ス</Sentence>
              </ParagraphSentence>
            </Paragraph>
          </SupplProvision>
          <SupplProvision AmendLawNum="昭和二三年四月二二日運輸省令第一〇号">
